// AUTO-GENERATED — KHÔNG sửa tay. Regen: python tools/gen_minna_grammar_data.py
// Nguồn: 50 docx KOERU_Minna (jlpt-lesson-generator/output/docs/grammar)
window.MINNA_GRAMMAR = {"1":[{"title":"N は N です","formula":"N₁ は N₂ です\nThành phần | Câu hoàn chỉnh | Nghĩa\nわたし + は + がくせい + です | → わたしは がくせいです。 | Tôi là sinh viên/học sinh.\nやまださん + は + せんせい + です\nハンさんはかいしゃいんで\nTuansanは　トワ会社　のエンジニア　です | → やまださんは せんせいです。 | Anh Yamada là giáo viên.\nこれ + は + ほん + です | → これは ほんです。 | Cái này là sách.","explain":"Mẫu câu khẳng định cơ bản nhất trong tiếng Nhật: 'N₁ là N₂'.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.\nTiếng Nhật thường lược bỏ chủ ngữ nếu ngữ cảnh rõ ràng (khác tiếng Việt luôn cần chủ ngữ).","usage":"Dùng khi: Dùng khi giới thiệu bản thân, giới thiệu người khác, hoặc xác nhận danh tính/phân loại.\n❌ わたし が がくせいです → ✅ わたしは がくせいです","compare":"","examples":[{"jp":"わたし は ミラーです。アメリカじんです。","vn":"Tôi là Miller. Tôi là người Mỹ."},{"jp":"やまださんは かいしゃいんです。","vn":"Anh Yamada là nhân viên công ty."},{"jp":"→ わたしは がくせいです。","vn":"Tôi là sinh viên/học sinh."},{"jp":"→ やまださんは せんせいです。","vn":"Anh Yamada là giáo viên."},{"jp":"→ これは ほんです。","vn":"Cái này là sách."}]},{"title":"N は N じゃありません","formula":"N₁ は N₂ じゃありません\nKhẳng định | Phủ định | Ghi chú\nです | → じゃありません | phủ định nói\nです | → ではありません | phủ định viết / trang trọng","explain":"Phủ định lịch sự của です: 'N₁ không phải là N₂'.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"Dùng khi: Phủ nhận danh tính, nghề nghiệp, quốc tịch, hoặc phân loại sai.\n❌ わたしはじゃありません → ✅ わたしは [N₂] じゃありません — phải có danh từ trước じゃ.","compare":"じゃありません  vs  ではありません\nじゃありません | ではありません\nNgữ cảnh | Nói chuyện hàng ngày | Văn viết, thuyết trình\nMức lịch sự | Lịch sự bình thường | Lịch sự trang trọng\nTần suất | Rất phổ biến | Văn bản, email công việc\nVí dụ | がくせいじゃありません | がくせいではありません","examples":[{"jp":"わたしは いしゃじゃありません。エンジニアです。","vn":"Tôi không phải bác sĩ. Tôi là kỹ sư."},{"jp":"やまださんは がくせいじゃありません。せんせいです。","vn":"Anh Yamada không phải sinh viên. Anh ấy là giáo viên."},{"jp":"→ じゃありません","vn":"phủ định nói"},{"jp":"→ ではありません","vn":"phủ định viết / trang trọng"}]},{"title":"N₁ は N₂ ですか","formula":"N₁ は N₂ ですか ／ はい、～です ／ いいえ、～じゃありません","explain":"Câu hỏi Yes/No: chỉ cần thêm か vào cuối câu khẳng định.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.\nはい/いいえ trong tiếng Nhật xác nhận/phủ nhận NỘI DUNG, không phải câu hỏi. Ví dụ: 'Bạn không phải sinh viên à?' — はい、がくせいじゃありません (Vâng, đúng, tôi không phải).","usage":"Dùng khi: Xác nhận thông tin về ai đó / vật gì đó.\n❌ ですか あなたは がくせい？ → ✅ あなたは がくせいですか。 — không đảo ngữ.","compare":"","examples":[{"jp":"あなたは がくせいですか。　― はい、がくせいです。","vn":"Bạn là sinh viên à?"},{"jp":"わたし は ミラーです。アメリカじんです。","vn":"Tôi là Miller. Tôi là người Mỹ."},{"jp":"わたしは いしゃじゃありません。エンジニアです。","vn":"Tôi không phải bác sĩ. Tôi là kỹ sư."}]},{"title":"N の N","formula":"N₁ の N₂\nN₁ + の + N₂ | Kết quả | Quan hệ\nわたし + の + ほん | → わたしのほん | sách của tôi (sở hữu)\nにほんご + の + せんせい | → にほんごのせんせい | giáo viên tiếng Nhật (phân loại)\nIMC + の + やまださん | → IMCのやまださん | anh Yamada (bên) công ty IMC (thuộc về)","explain":"の nối 2 danh từ, N₁ bổ nghĩa cho N₂ (đọc từ phải sang trái).\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"Dùng khi: Nối bất kỳ 2 danh từ có quan hệ bổ nghĩa. Luôn đặt N bổ nghĩa trước の, N chính sau.\n❌ ほんのわたし → ✅ わたしのほん — N bổ nghĩa (sở hữu) đứng TRƯỚC の.","compare":"N₁ の N₂ (sở hữu)  vs  N₁ の N₂ (phân loại)\nN₁ の N₂ (sở hữu) | N₁ の N₂ (phân loại)\nÝ nghĩa | N₂ thuộc về N₁ | N₂ thuộc loại N₁\nVí dụ | わたしのほん (sách của tôi) | にほんごのほん (sách tiếng Nhật)\nKiểm tra | Ai sở hữu? → của ai | Loại gì? → phân loại","examples":[{"jp":"これは わたしの じしょです。","vn":"Đây là từ điển của tôi."},{"jp":"にほんごの ほんを ください。","vn":"Cho tôi cuốn sách tiếng Nhật."},{"jp":"あなたは がくせいですか。　― はい、がくせいです。","vn":"Bạn là sinh viên à?"}]},{"title":"N₁ も N₂ です","formula":"N₁ も N₂ です ／ N₁ も N₂ じゃありません\nCâu gốc (は) | Câu thêm (も) | Nghĩa\nCâu 1 (は) | Câu 2 (も) | Nghĩa\nわたしは がくせいです。 | マイさんも がくせいです。 | Tôi là SV. Mai cũng là SV.\nやまださんは にほんじんです。 | たなかさんも にほんじんです。 | Yamada là người Nhật. Tanaka cũng vậy.\nこれは ほんじゃありません。 | それも ほんじゃありません。 | Cái này không phải sách. Cái đó cũng không.","explain":"も = 'cũng', thay thế は khi thêm thông tin tương tự cho chủ đề mới.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.\nも CHỈ dùng khi thông tin của câu 2 GIỐNG với câu 1. Nếu khác thì vẫn dùng は.","usage":"Dùng khi: Khi muốn nói 2 người/vật có cùng đặc điểm — 'A là X, B cũng là X'.\n❌ わたしはも がくせいです → ✅ わたしも がくせいです — も thay thế は, không đi cùng.","compare":"","examples":[{"jp":"ミラーさんは かいしゃいんです。サントスさんも かいしゃいんです。","vn":"Anh Miller là nhân viên công ty. Anh Santos cũng là nhân viên công ty."},{"jp":"やまださんは エンジニアです。たなかさんも エンジニアです。","vn":"Anh Yamada là kỹ sư. Anh Tanaka cũng là kỹ sư."},{"jp":"マイさんも がくせいです。","vn":"Tôi là SV. Mai cũng là SV."},{"jp":"たなかさんも にほんじんです。","vn":"Yamada là người Nhật. Tanaka cũng vậy."},{"jp":"それも ほんじゃありません。","vn":"Cái này không phải sách. Cái đó cũng không."}]}],"2":[{"title":"これ／それ／あれ は N です","formula":"これ／それ／あれ は N ですか ⇒ ～は N です\nĐại từ | Ví dụ | Nghĩa\nこれ (こ — gần tôi) | → これは ほんです。 | Cái này là sách.\nそれ (そ — gần bạn) | → それは なんですか。 | Cái đó là cái gì?\nあれ (あ — xa cả hai) | → あれは がっこうです。 | Cái kia là trường học.\nどれ (ど — hỏi) | → どれが いいですか。 | Cái nào tốt?","explain":"これ/それ/あれ là đại từ chỉ thị — đứng một mình thay cho danh từ (không cần N phía sau).\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.\nKhi người A hỏi それ, người B sẽ trả lời bằng これ (vì đồ vật giờ gần B). Và ngược lại.","usage":"Dùng khi: Chỉ vào đồ vật cụ thể trong tầm nhìn và hỏi/nói về nó.\n❌ これほんです → ✅ これは ほんです — cần trợ từ は sau これ.","compare":"","examples":[{"jp":"これは ほんです。にほんごの ほんです。","vn":"Cái này là sách. Là sách tiếng Nhật."},{"jp":"それは なんですか。　― これは じしょです。","vn":"Cái đó là gì?"},{"jp":"→ これは ほんです。","vn":"Cái này là sách."},{"jp":"→ それは なんですか。","vn":"Cái đó là cái gì?"},{"jp":"→ あれは がっこうです。","vn":"Cái kia là trường học."}]},{"title":"この／その／あの N","formula":"この／その／あの + N は ～ です","explain":"この/その/あの là LIÊN THỂ TỪ (連体詞) — luôn phải đứng trước danh từ, KHÔNG đứng một mình.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"Dùng khi: Khi muốn chỉ cụ thể một vật mà cần nêu tên danh từ: 'cuốn sách này', 'cái túi đó'.\n❌ あれかたは → ✅ あのかたは — trước danh từ phải dùng あの.","compare":"これ/それ/あれ  vs  この/その/あの + N\nこれ/それ/あれ | この/その/あの + N\nLoại từ | Đại từ (đứng một mình) | Liên thể từ (+ danh từ)\nVí dụ | これは いいです。 | このほんは いいです。\nNghĩa | Cái này tốt. | Cuốn sách này tốt.\nHỏi | どれ が いいですか | どの ほん が いいですか","examples":[{"jp":"このかばんは わたしのです。","vn":"Cái túi này là của tôi."},{"jp":"そのでんわは あたらしいですか。","vn":"Cái điện thoại đó có mới không?"},{"jp":"「このかさは だれのですか。」「わたしのです。」","vn":"'Cái ô này là của ai?' 'Là của tôi.'"}]},{"title":"N₁ の N₂（所属・所有・説明）","formula":"N₁ の N₂ = 'N₂ của/thuộc N₁'\nLoại N₁ | Ví dụ | Nghĩa\n[người] の N | やまださんの かさ | ô của anh Yamada (sở hữu)\n[công ty/tổ chức] の N | ABCの しゃいん | nhân viên của ABC (sở thuộc)\n[quốc gia] の N | にほんの くるま | xe Nhật (xuất xứ)\n[ngôn ngữ] の N | にほんごの ほん | sách tiếng Nhật (phân loại)","explain":"の nối 2 danh từ: N₁ は N₂ の ra N₁ = 'N₂ của N₁'. Quan hệ: sở hữu, sở thuộc, mô tả.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ にほんくるま → ✅ にほんのくるま — 2 danh từ kết nối BẮT BUỘC có の ở giữa.","compare":"","examples":[{"jp":"これは やまださんの かさです。","vn":"Cái này là ô của anh Yamada."},{"jp":"ミラーさんは IMC の しゃいんです。","vn":"Anh Miller là nhân viên của IMC."},{"jp":"これは ほんです。にほんごの ほんです。","vn":"Cái này là sách. Là sách tiếng Nhật."}]},{"title":"の（代名詞的用法）— の thay thế danh từ","formula":"N は [người] のです ⇒ 'N là của [người]'","explain":"の ở cuối câu thay thế danh từ đã được nhắc đến, tránh lặp.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ このほんはわたしです → ✅ このほんはわたしのです — thiếu の chỉ sở hữu.","compare":"","examples":[{"jp":"「このかさは だれのですか。」「わたしのです。」","vn":"'Cái ô này là của ai?' 'Là của tôi.'"},{"jp":"「そのほんは ミラーさんのですか。」「いいえ、やまださんのです。」","vn":"'Cuốn sách đó là của anh Miller à?' 'Không, là của anh Yamada.'"},{"jp":"このかばんは わたしのです。","vn":"Cái túi này là của tôi."}]},{"title":"そうです ／ ちがいます","formula":"はい、そうです。／いいえ、ちがいます。","explain":"そうです = 'Đúng vậy' — xác nhận thông tin vừa được hỏi.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.\nそうです chỉ dùng khi xác nhận thông tin người khác đưa ra, KHÔNG dùng làm câu khẳng định độc lập.","usage":"❌ 「これは ほんですか。」「はい、ほんです。」→ ✅ 「はい、そうです。」 — Khi xác nhận, そうです tự nhiên hơn là lặp lại danh từ.","compare":"","examples":[{"jp":"「これは じしょですか。」「はい、そうです。」","vn":"'Cái này là từ điển à?' 'Vâng, đúng vậy.'"},{"jp":"「やまださんは がくせいですか。」「いいえ、ちがいます。せんせいです。」","vn":"'Anh Yamada là sinh viên à?' 'Không phải. Anh ấy là giáo viên.'"},{"jp":"「わたしは インドじんです。」「あ、そうですか。」","vn":"'Tôi là người Ấn Độ.' 'À vậy à.'"}]},{"title":"N₁ ですか、N₂ ですか（選択疑問）","formula":"N₁ ですか、N₂ ですか ⇒ ～です\nCấu trúc | Ví dụ | Nghĩa\nN₁ ですか、N₂ ですか | じしょですか、ほんですか | Là từ điển hay sách?\nこれ/それ/どれ + ですか...ですか | それは えんぴつですか、ボールペンですか | Là bút chì hay bút bi?","explain":"Câu hỏi lựa chọn: 'Là N₁ hay N₂?' — đưa ra 2 phương án để người nghe chọn.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"Dùng khi: Dùng khi không chắc là cái gì/ai, muốn người nghe xác nhận một trong hai.\n❌ やまださんはせんせいやがくせいですか → ✅ やまださんはせんせいですか、がくせいですか — tiếng Nhật không dùng 'hay' bằng một từ, dùng ですか...ですか.","compare":"","examples":[{"jp":"やまださんは せんせいですか、がくせいですか。　― せんせいです。","vn":"Anh Yamada là giáo viên hay sinh viên?"},{"jp":"これは えいごの ほんですか、にほんごの ほんですか。　― にほんごの ほんです。","vn":"Cái này là sách tiếng Anh hay sách tiếng Nhật?"},{"jp":"じしょですか、ほんですか","vn":"Là từ điển hay sách?"},{"jp":"それは えんぴつですか、ボールペンですか","vn":"Là bút chì hay bút bi?"},{"jp":"「このかさは だれのですか。」「わたしのです。」","vn":"'Cái ô này là của ai?' 'Là của tôi.'"}]},{"title":"お～（丁寧の接頭語）","formula":"お + [danh từ gốc Nhật] = dạng lịch sự / danh từ kính trọng\nTừ gốc | → お + từ | Ý nghĩa / Ngữ cảnh\nしごと (việc làm) | → おしごと | công việc (của người nghe/người khác)\nくに (quê hương) | → おくに | quê hương (của đối phương)\nなまえ (tên) | → おなまえ | tên (của đối phương)\nへや (phòng) | → おへや | phòng (của đối phương — khi hỏi)","explain":"Tiền tố お～ thêm vào trước danh từ để tăng mức độ lịch sự. Nguồn gốc Nhật (和語) dùng お, nguồn gốc Trung (漢語) thường dùng ご.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.\nお～ chỉ dùng cho từ Nhật (和語). Từ nước ngoài KHÔNG thêm お: ❌ おコーヒー, ❌ おスマホ.","usage":"Dùng khi: Dùng khi hỏi về thông tin của người nghe — thể hiện sự tôn trọng. KHÔNG dùng để nói về bản thân mình.\n❌ わたしのおしごとはかんごしです → ✅ わたしのしごとはかんごしです — お～ không dùng để nói về bản thân.","compare":"","examples":[{"jp":"おなまえは なんですか。","vn":"Tên bạn là gì ạ?"},{"jp":"おくには どちらですか。","vn":"Quê hương của bạn là đâu ạ?"},{"jp":"これは やまださんの かさです。","vn":"Cái này là ô của anh Yamada."}]},{"title":"そうですか（反応）","formula":"そうですか ／ ええ、そうです ／ あ、そうですか","explain":"そうですか = 'Vậy à / À ra vậy' — phản ứng khi nghe thông tin mới, bày tỏ đã tiếp nhận.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.\nそうですか KHÔNG giống そうです — そうです là xác nhận ('Vâng đúng'), そうですか là phản ứng ('Vậy à').","usage":"Dùng khi: Phản ứng tự nhiên sau khi nghe thông tin — thể hiện đang lắng nghe, đã hiểu.\n❌ 「わたしは がくせいです」「そうですか、わたしも そうですか」→ ✅「そうですか。わたしも がくせいです」 — そうですか không dùng cuối câu khẳng định.","compare":"","examples":[{"jp":"「わたしは インドじんです。」「あ、そうですか。」","vn":"'Tôi là người Ấn Độ.' 'À vậy à.'"},{"jp":"「やまださんは かいしゃいんじゃありません。」「そうですか。なんの おしごとですか。」","vn":"'Anh Yamada không phải nhân viên công ty.' 'Vậy à. Vậy anh ấy làm gì?'"},{"jp":"「これは じしょですか。」「はい、そうです。」","vn":"'Cái này là từ điển à?' 'Vâng, đúng vậy.'"}]}],"3":[{"title":"ここ／そこ／あそこ は N です","formula":"ここ／そこ／あそこ は [địa điểm/phân loại] です\nChỉ vật (Bài 2) | Chỉ nơi (Bài 3) | Dạng lịch sự\nこれ (vật) | → ここ (nơi) | → こちら (lịch sự)\nそれ (vật) | → そこ (nơi) | → そちら (lịch sự)\nあれ (vật) | → あそこ (nơi) | → あちら (lịch sự)\nどれ (vật) | → どこ (nơi) | → どちら (lịch sự)","explain":"Cùng hệ thống KO-SO-A-DO nhưng cho NƠI CHỐN: ここ(đây) → そこ(đó) → あそこ(kia) → どこ(đâu).\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ ここがきょうしつです (khi giới thiệu) → ✅ ここはきょうしつです — giới thiệu nơi chốn dùng は.","compare":"","examples":[{"jp":"ここは きょうしつです。","vn":"Đây là phòng học."},{"jp":"トイレは あそこです。","vn":"Nhà vệ sinh ở kia."},{"jp":"すみません、トイレは どこですか。　― あちらです。","vn":"Xin lỗi, nhà vệ sinh ở đâu?"},{"jp":"ミラーさんは かいしゃいんです。サントスさんも かいしゃいんです。","vn":"Anh Miller là nhân viên công ty. Anh Santos cũng là nhân viên công ty."},{"jp":"ほんは つくえの うえです。","vn":"Sách ở trên bàn."}]},{"title":"N は どこ ですか","formula":"N は どこ ですか ⇒ ～は [nơi] です","explain":"Hỏi vị trí: どこ = ở đâu. Đặt danh từ (thứ cần tìm) làm chủ đề bằng は.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.\nKhi hỏi đường với người lạ, luôn mở đầu bằng すみません.","usage":"❌ トイレはどこにいますか → ✅ トイレはどこですか — トイレ là đồ vật, dùng あります hoặc どこですか, không dùng います.","compare":"","examples":[{"jp":"すみません、トイレは どこですか。　― あちらです。","vn":"Xin lỗi, nhà vệ sinh ở đâu?"},{"jp":"やまださんの かいしゃは どこですか。　― おおさかです。","vn":"Công ty anh Yamada ở đâu?"},{"jp":"「お国はどちらですか。」「ベトナムから きました。ホーチミンです。」","vn":"'Bạn đến từ đâu?' 'Tôi đến từ Việt Nam. TP Hồ Chí Minh.'"}]},{"title":"N も (cũng)","formula":"N₁ は ～です。N₂ も ～です。\nCâu gốc (は) | Câu cũng (も) | Vị trí も\nわたしは がくせいです。 | → スミスさんも がくせいです。 | も thay は\nここにほんがあります。 | → そこにもほんがあります。 | にも (も + に)","explain":"も = 'cũng', thay thế は khi 2 chủ đề chia sẻ cùng thông tin.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ わたしはもがくせいです → ✅ わたしもがくせいです — も thay thế は, không đi kèm.","compare":"","examples":[{"jp":"ミラーさんは かいしゃいんです。サントスさんも かいしゃいんです。","vn":"Anh Miller là nhân viên công ty. Anh Santos cũng là nhân viên công ty."},{"jp":"ここは きょうしつです。そこも きょうしつです。","vn":"Đây là phòng học. Chỗ đó cũng là phòng học."},{"jp":"これは にほんの おみやげです。","vn":"Đây là quà lưu niệm Nhật Bản."}]},{"title":"N は N₁ の [位置語] です","formula":"[Vật] は [Mốc] の うえ/した/まえ/うしろ/なか/そと/となり/ちかく/あいだ です\nVị trí | Ví dụ | Nghĩa\nうえ (上) | つくえのうえ | trên bàn\nした (下) | いすのした | dưới ghế\nまえ (前) | えきのまえ | trước ga\nうしろ (後ろ) | ビルのうしろ | sau tòa nhà\nなか (中) | かばんのなか | trong túi\nとなり (隣) | ぎんこうのとなり | bên cạnh ngân hàng\nちかく (近く) | えきのちかく | gần ga\nあいだ (間) | AとBのあいだ | giữa A và B","explain":"Diễn tả vị trí tương đối: [Vật cần tìm] ở [vị trí] của [vật mốc].\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ つくえはほんのうえ → ✅ ほんはつくえのうえ — vật cần tìm là chủ đề, vật mốc đứng trước の.","compare":"となり (隣)  vs  ちかく (近く)\nとなり (隣) | ちかく (近く)\nNghĩa | Bên cạnh (sát nhau) | Gần (không sát)\nĐiều kiện | Cùng loại/cùng hàng | Khác loại / khoảng cách lớn hơn\nVí dụ | ぎんこうのとなりにポストがあります | えきのちかくにコンビニがあります\nHình dung | 🏦🏣 (sát nhau) | 🚉 ⋯ 🏪 (gần nhưng có khoảng cách)","examples":[{"jp":"ほんは つくえの うえです。","vn":"Sách ở trên bàn."},{"jp":"ねこは いすの したに います。","vn":"Con mèo ở dưới ghế."},{"jp":"かばんのなか","vn":"trong túi"},{"jp":"AとBのあいだ","vn":"giữa A và B"},{"jp":"ここは きょうしつです。","vn":"Đây là phòng học."}]},{"title":"N₁ の N₂（産地・出所・所属）","formula":"[Nơi xuất xứ/Thương hiệu] の [Sản phẩm/Người]\nN₁のN₂ | Nghĩa | Quan hệ\nフランスのワイン | Rượu (của/từ) Pháp | Xuất xứ\nにほんのくるま | Xe Nhật | Xuất xứ\nIMCのやまださん | Anh Yamada (công ty) IMC | Thuộc về\nベトナムのりょうり | Món ăn Việt Nam | Xuất xứ","explain":"の nối 2 danh từ khi N₁ là nơi sản xuất, thương hiệu, hoặc nơi xuất xứ của N₂.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.\nCùng cấu trúc NのN nhưng ngữ cảnh khác nhau: sở hữu (わたしのほん), phân loại (にほんごのほん), xuất xứ (にほんのビール).","usage":"Dùng khi: Nói về sản phẩm theo xuất xứ, thương hiệu: 'bia Đức', 'xe Nhật', 'đồng hồ Thụy Sĩ'.\n❌ にほんビール → ✅ にほんのビール — cần の khi nối 2 danh từ.","compare":"","examples":[{"jp":"これは にほんの おみやげです。","vn":"Đây là quà lưu niệm Nhật Bản."},{"jp":"あれは ドイツのビールですか。　― いいえ、にほんのビールです。","vn":"Cái kia là bia Đức à?"},{"jp":"ここは きょうしつです。","vn":"Đây là phòng học."}]},{"title":"お国はどちらですか（丁寧な質問）","formula":"お国はどちらですか ／ ご出身はどちらですか\nCâu hỏi | Trả lời | Ghi chú\nどこ (thường) | → どちら (lịch sự) | dùng theo ngữ cảnh\nお国はどちらですか | → ベトナムから きました。 | Tôi đến từ Việt Nam.\nご出身はどちらですか | → ベトナムです。 | Tôi là người Việt Nam.","explain":"Cách hỏi quê hương lịch sự. どちら = dạng lịch sự của どこ (ở đâu / nơi nào).\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.\nどちらですか = ở đâu (lịch sự) nhưng cũng có nghĩa là 'cái nào' khi hỏi lựa chọn.","usage":"Dùng khi: Dùng khi gặp người nước ngoài, trong hoàn cảnh lịch sự (không phải bạn bè thân).\n❌ あなたの国はどこですか → ✅ お国はどちらですか — với người lạ, lịch sự dùng どちら, tránh あなた.","compare":"","examples":[{"jp":"「お国はどちらですか。」「ベトナムから きました。ホーチミンです。」","vn":"'Bạn đến từ đâu?' 'Tôi đến từ Việt Nam. TP Hồ Chí Minh.'"},{"jp":"「ご出身はどちらですか。」「ハノイです。」","vn":"'Quê bạn ở đâu?' 'Hà Nội ạ.'"},{"jp":"→ ベトナムから きました。","vn":"Tôi đến từ Việt Nam."},{"jp":"→ ベトナムです。","vn":"Tôi là người Việt Nam."}]}],"4":[{"title":"今 なんじですか","formula":"いま なんじ ですか ⇒ ～じ ～ふん です\n1時 いちじ | 2時 にじ | 3時 さんじ\n4時 よじ ⚠️ | 5時 ごじ | 6時 ろくじ\n7時 しちじ ⚠️ | 8時 はちじ | 9時 くじ ⚠️\n10時 じゅうじ | 11時 じゅういちじ | 12時 じゅうにじ","explain":"Hỏi giờ hiện tại. なんじ = mấy giờ, なんぷん = mấy phút.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ よんじ → ✅ よじ (4時)  |  ❌ ななじ → ✅ しちじ (7時)  |  ❌ きゅうじ → ✅ くじ (9時)","compare":"","examples":[{"jp":"いま なんじですか。　― ごご ３じ１５ふんです。","vn":"Bây giờ mấy giờ?"},{"jp":"じゅぎょうは ９じから １１じはんまでです。","vn":"Giờ học từ 9 giờ đến 11 giờ rưỡi."},{"jp":"まいにち ９じから ５じまで はたらきます。","vn":"Mỗi ngày tôi làm việc từ 9 giờ đến 5 giờ."}]},{"title":"N から N まで","formula":"[Điểm bắt đầu] から [Điểm kết thúc] まで\nLoại | Ví dụ | Nghĩa\nThời gian | 9じから 5じまで はたらきます。 | Làm việc từ 9h đến 5h.\nKhông gian | とうきょうから おおさかまで | Từ Tokyo đến Osaka\nChỉ dùng から | 9じから べんきょうします。 | Học từ 9 giờ (không nói đến mấy giờ).\nChỉ dùng まで | 5じまで はたらきます。 | Làm đến 5 giờ.","explain":"から = 'từ' (điểm khởi đầu), まで = 'đến' (điểm kết thúc).\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ ９じまで５じから はたらきます → ✅ ９じから５じまで はたらきます — から luôn đứng trước まで.","compare":"から (từ/vì)  vs  まで (đến)\nから (từ/vì) | まで (đến)\nBài 4 | Điểm bắt đầu (thời gian/không gian) | Điểm kết thúc\nBài 14 | Nguyên nhân: ～ですから (vì…) | — (không liên quan)\nVí dụ B4 | 9じから はたらきます | 5じまで はたらきます\nVí dụ B14 | さむいですから、コートをきます | —","examples":[{"jp":"まいにち ９じから ５じまで はたらきます。","vn":"Mỗi ngày tôi làm việc từ 9 giờ đến 5 giờ."},{"jp":"げつようびから きんようびまで がっこうが あります。","vn":"Từ thứ Hai đến thứ Sáu có đi học."},{"jp":"じから 5じまで はたらきます。","vn":"Làm việc từ 9h đến 5h."},{"jp":"じから べんきょうします。","vn":"Học từ 9 giờ (không nói đến mấy giờ)."},{"jp":"じまで はたらきます。","vn":"Làm đến 5 giờ."}]},{"title":"どのくらい かかりますか","formula":"[A] から [B] まで どのくらい かかりますか ⇒ ～じかん／～ふん かかります","explain":"Hỏi khoảng thời gian cần để di chuyển / hoàn thành. かかります = mất (thời gian/tiền).\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ どのくらい かかりますよ → ✅ どのくらい かかりますか — hỏi dùng か, không phải よ.","compare":"","examples":[{"jp":"うちから えきまで どのくらいかかりますか。　― あるいて １５ふんぐらいです。","vn":"Từ nhà đến ga mất bao lâu?"},{"jp":"にほんまで ひこうきで どのくらいかかりますか。　― ６じかんぐらいです。","vn":"Đến Nhật bằng máy bay mất bao lâu?"},{"jp":"いま なんじですか。　― ごご ３じ１５ふんです。","vn":"Bây giờ mấy giờ?"}]},{"title":"V ます — 4 dạng cơ bản（導入）","formula":"Vます ／ Vません ／ Vました ／ Vませんでした\n+ | −\nHiện tại/Tương lai | Quá khứ\nKhẳng định (+) | おきます (thức dậy) | おきました (đã thức dậy)\nPhủ định (−) | おきません (không thức dậy) | おきませんでした (đã không thức dậy)","explain":"Đây là phần giới thiệu 4 dạng cơ bản của động từ thể ます — học chi tiết ở Bài 5.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"Dùng khi: Nói về thói quen hàng ngày, lịch trình, kế hoạch.\n❌ きのう おきます → ✅ きのう おきました — có きのう phải dùng quá khứ ました.","compare":"","examples":[{"jp":"まいにち ７じに おきます。","vn":"Mỗi ngày tôi thức dậy lúc 7 giờ."},{"jp":"きのうは ７じに おきませんでした。","vn":"Hôm qua tôi đã không thức dậy lúc 7 giờ."},{"jp":"おきます","vn":"thức dậy"},{"jp":"おきました","vn":"đã thức dậy"},{"jp":"おきません","vn":"không thức dậy"}]},{"title":"N と N（列挙）","formula":"N₁ と N₂（と N₃…）\nCấu trúc | Ví dụ | Nghĩa\nN₁ と N₂ | ほんとペン | sách và bút\nN₁ と N₂ と N₃ | にほんとベトナムとちゅうごく | Nhật, Việt Nam và Trung Quốc","explain":"と nối 2 danh từ có nghĩa 'và', liệt kê đầy đủ các thành phần.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.\nと dùng khi liệt kê HẾT (exhaustive). Ví dụ: 「A と B が あります」 = 'có A và B (chỉ có vậy thôi)'.","usage":"Dùng khi: Khi muốn liệt kê đầy đủ 2-3 vật/người.\n❌ にほんとベトナムやちゅうごく (muốn liệt kê đầy đủ) → ✅ にほんとベトナムとちゅうごく — liệt kê đầy đủ dùng と.","compare":"","examples":[{"jp":"かばんの なかに ほんと ペンと さいふが あります。","vn":"Trong túi có sách, bút và ví."},{"jp":"げつようびと すいようびと きんようびに じゅぎょうが あります。","vn":"Thứ Hai, thứ Tư và thứ Sáu có giờ học."},{"jp":"うちから えきまで どのくらいかかりますか。　― あるいて １５ふんぐらいです。","vn":"Từ nhà đến ga mất bao lâu?"}]},{"title":"～ね（確認・共感）","formula":"文 + ね","explain":"ね cuối câu dùng để tìm sự đồng thuận, xác nhận lại, hoặc bày tỏ cảm xúc chung.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"Dùng khi: Khi muốn chia sẻ cảm xúc, xác nhận điều vừa nghe, hoặc tìm sự đồng ý.\n❌ 「わたしは がくせいです、ね。」 (sai vị trí) → ✅ 「わたしは がくせいですね。」 — ね đặt cuối câu, không có dấu phẩy.","compare":"～ね（đồng thuận/xác nhận）  vs  ～よ（thông báo/nhấn mạnh）\n～ね（đồng thuận/xác nhận） | ～よ（thông báo/nhấn mạnh）\nMục đích | Tìm đồng thuận, chia sẻ | Thông báo điều mới, khẳng định\nVí dụ | たいへんですね。 | やすみですよ。\nNghĩa | Vất vả nhỉ (tôi thấy thế). | Ngày mai nghỉ đấy (bạn chưa biết).","examples":[{"jp":"はやいですね。","vn":"Sớm nhỉ."},{"jp":"たいへんですね。","vn":"Vất vả nhỉ."},{"jp":"わたしは がくせいです、ね。」","vn":"sai vị trí"}]},{"title":"曜日・日にち: Thứ, ngày, tháng","formula":"なんようび (thứ mấy) / なんにち (ngày mấy) / なんがつ (tháng mấy)","explain":"7 ngày trong tuần: にちようび (CN), げつようび (T2), かようび (T3), すいようび (T4), もくようび (T5), きんようび (T6), どようび (T7).\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.\n4 ngày dễ nhầm nhất: ついたち(1), ふつか(2), みっか(3), よっか(4) - đều đọc riêng, không theo quy tắc số đếm + にち.","usage":"Dùng khi: Dùng khi hỏi/nói lịch hẹn, ngày sinh, ngày nghỉ, deadline.\n❌ よんがつ → ✅ しがつ — Tháng 4 đọc đặc biệt là しがつ, không dùng よん","compare":"","examples":[{"jp":"きょうは なんようびですか。- もくようびです。","vn":"Hôm nay thứ mấy? - Thứ Năm."},{"jp":"わたしの たんじょうびは 8がつ ついたちです。","vn":"Sinh nhật tôi là ngày 1 tháng 8."},{"jp":"まいにち ７じに おきます。","vn":"Mỗi ngày tôi thức dậy lúc 7 giờ."}]}],"5":[{"title":"V ます — 4 dạng","formula":"V ます（khẳng định）／ V ません（phủ định）／ V ました（quá khứ）／ V ませんでした（quá khứ phủ định）\nThì | ＋ | −\nKhẳng định | Phủ định\nHiện tại / Tương lai | たべます (ăn / sẽ ăn) | たべません (không ăn)\nQuá khứ | たべました (đã ăn) | たべませんでした (đã không ăn)","explain":"Thể ます là dạng lịch sự của động từ. Có 4 biến thể tùy khẳng định/phủ định × hiện tại/quá khứ.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ きのうたべます → ✅ きのうたべました — có きのう (hôm qua) phải dùng quá khứ.","compare":"","examples":[{"jp":"まいにち にほんごを べんきょうします。","vn":"Mỗi ngày tôi học tiếng Nhật."},{"jp":"あした がっこうへ いきません。","vn":"Ngày mai tôi không đi học."},{"jp":"たべます","vn":"ăn / sẽ ăn"},{"jp":"たべません","vn":"không ăn"},{"jp":"たべました","vn":"đã ăn"}]},{"title":"N を V","formula":"N を [他動詞]","explain":"を (đọc 'o') là trợ từ tân ngữ trực tiếp — đánh dấu đối tượng bị tác động bởi hành động.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ コーヒーが のみます → ✅ コーヒーを のみます\n— tân ngữ trực tiếp dùng を, không phải が.","compare":"","examples":[{"jp":"コーヒーを のみます。","vn":"Tôi uống cà phê."},{"jp":"テレビを みます。にほんごの ばんぐみを みます。","vn":"Tôi xem TV. Tôi xem chương trình tiếng Nhật."},{"jp":"まいにち にほんごを べんきょうします。","vn":"Mỗi ngày tôi học tiếng Nhật."}]},{"title":"N で V (phương tiện ／ nơi hành động)","formula":"[Phương tiện/Nơi] で [動詞]","explain":"で có 2 nghĩa chính: (1) Phương tiện/công cụ: バスで いきます = đi bằng xe buýt. (2) Nơi hành động diễn ra: としょかんで べんきょうします = học ở thư viện.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ としょかんに べんきょうします → ✅ としょかんで べんきょうします — hành động xảy ra tại nơi dùng で, không phải に.","compare":"で (hành động)  vs  に (tồn tại / điểm đến)\nで (hành động) | に (tồn tại / điểm đến)\nÝ nghĩa | Nơi hành động diễn ra | Nơi tồn tại / Điểm đến\nVí dụ | としょかんで べんきょうします | としょかんに ほんが あります\nNghĩa | Học ở thư viện (hành động) | Trong thư viện có sách (tồn tại)\nĐộng từ | します、たべます、みます… | あります、います、いきます…","examples":[{"jp":"バスで がっこうへ いきます。","vn":"Tôi đi đến trường bằng xe buýt."},{"jp":"としょかんで にほんごを べんきょうします。","vn":"Tôi học tiếng Nhật ở thư viện."},{"jp":"コーヒーを のみます。","vn":"Tôi uống cà phê."}]},{"title":"N へ V (hướng di chuyển)","formula":"[Nơi đến] へ いきます／きます／かえります","explain":"へ (đọc 'e') chỉ hướng/đích đến. Dùng với động từ di chuyển: いく(đi), くる(đến), かえる(về).\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ がっこうへ べんきょうします → ✅ がっこうで べんきょうします — di chuyển đến dùng へ/に, hành động tại chỗ dùng で.","compare":"","examples":[{"jp":"にほんへ いきます。","vn":"Tôi đi đến Nhật Bản."},{"jp":"うちへ かえります。","vn":"Tôi về nhà."},{"jp":"バスで がっこうへ いきます。","vn":"Tôi đi đến trường bằng xe buýt."}]},{"title":"N と V (cùng với)","formula":"[Người] と [動詞]","explain":"と chỉ người đồng hành: 'cùng với, với'. Chỉ đi với người/sinh vật, KHÔNG dùng cho phương tiện.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ バスといきます → ✅ バスでいきます — phương tiện dùng で, không phải と.","compare":"","examples":[{"jp":"ともだちと えいがを みます。","vn":"Tôi xem phim cùng bạn bè."},{"jp":"かぞくと にほんへ いきます。","vn":"Tôi đi Nhật cùng gia đình."},{"jp":"にほんへ いきます。","vn":"Tôi đi đến Nhật Bản."}]},{"title":"どこへも V ません（全否定）","formula":"どこへも いきません ／ なにも しません\nCâu phủ định toàn bộ | Nghĩa\nどこへも いきません | Không đi đâu cả\nなにも たべません | Không ăn gì cả\nだれとも はなしません | Không nói chuyện với ai cả\nなにも しませんでした | Đã không làm gì cả (quá khứ)","explain":"どこへも + phủ định = 'không đi đâu cả'.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"Dùng khi: Khi muốn nhấn mạnh 'không làm gì / không đi đâu / không gặp ai'.\n❌ どこへいきません (thiếu も) → ✅ どこへもいきません — phủ định toàn bộ cần も.","compare":"","examples":[{"jp":"きのうは どこへも いきませんでした。うちに いました。","vn":"Hôm qua tôi không đi đâu cả. Tôi ở nhà."},{"jp":"やすみのひは なにも しません。ゆっくり やすみます。","vn":"Ngày nghỉ tôi không làm gì cả. Nghỉ ngơi thôi."},{"jp":"どこへも いきません","vn":"Không đi đâu cả"},{"jp":"なにも たべません","vn":"Không ăn gì cả"},{"jp":"だれとも はなしません","vn":"Không nói chuyện với ai cả"}]},{"title":"いつ（時の疑問詞）","formula":"いつ ～ますか ⇒ [時間] に ～ます","explain":"いつ = khi nào, bao giờ — hỏi về thời điểm.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"Dùng khi: Hỏi thời điểm diễn ra sự việc: kỳ nghỉ, sinh nhật, sự kiện.\n❌ いつに たんじょうびですか → ✅ たんじょうびは いつですか — いつ là đại từ hỏi, không đi kèm に.","compare":"","examples":[{"jp":"たんじょうびは いつですか。　― ６がつ ２０にちです。","vn":"Sinh nhật bạn là khi nào?"},{"jp":"にほんへ いつ いきますか。　― らいねん いきます。","vn":"Bạn đi Nhật khi nào?"},{"jp":"ともだちと えいがを みます。","vn":"Tôi xem phim cùng bạn bè."}]},{"title":"～よ（強調・情報提供）","formula":"文 + よ","explain":"よ cuối câu dùng để thông báo điều người nghe CHƯA BIẾT, hoặc nhấn mạnh điều mình nói.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"Dùng khi: Khi chia sẻ thông tin mới, đưa ra gợi ý, hoặc nhấn mạnh điều mình muốn nói.\n❌ よ dùng với người trên bậc (sếp, khách hàng) → ✅ với người cùng bậc hoặc dưới, thêm ます/です trước よ làm mềm giọng.","compare":"～ね（共感）  vs  ～よ（通知）\n～ね（共感） | ～よ（通知）\nMục đích | Chia sẻ cảm xúc chung | Thông báo điều người nghe chưa biết\nVí dụ | たいへんですね。 | たいへんですよ。\nNghĩa | Vất vả nhỉ (tôi đồng cảm). | Vất vả lắm đấy (bạn hãy biết vậy).","examples":[{"jp":"あの えいがは おもしろいですよ。","vn":"Bộ phim đó hay lắm đấy."},{"jp":"あした やすみですよ。","vn":"Ngày mai là ngày nghỉ đấy."},{"jp":"きのうは どこへも いきませんでした。うちに いました。","vn":"Hôm qua tôi không đi đâu cả. Tôi ở nhà."}]},{"title":"動詞の3グループ分類 - Phân loại 3 nhóm động từ","formula":"Nhóm 1 (u-verb) / Nhóm 2 (ru-verb) / Nhóm 3 (bất quy tắc: する, くる)","explain":"Trước khi chia thể (ない/た/て...) phải biết động từ thuộc nhóm nào - quy tắc chia mỗi nhóm khác nhau hoàn toàn.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.\nMột số động từ đuôi 'iru' nhưng vẫn là Nhóm 2: おきる (ngủ dậy), あびる (tắm).","usage":"Dùng khi: Luôn kiểm tra nhóm động từ TRƯỚC khi chia sang thể ない/ます/た/て.\n❌ かえります chia nhầm kiểu Nhóm 2: かえ+ます → ✅ かえります (đúng vì là Nhóm 1) — かえる là ngoại lệ Nhóm 1, KHÔNG bỏ る như Nhóm 2","compare":"","examples":[{"jp":"わたしは まいあさ みずを のみます。","vn":"Mỗi sáng tôi uống nước."},{"jp":"わたしは あさごはんを たべます。","vn":"Tôi ăn sáng."},{"jp":"たんじょうびは いつですか。　― ６がつ ２０にちです。","vn":"Sinh nhật bạn là khi nào?"}]}],"6":[{"title":"N を ください","formula":"N を [số lượng] ください","explain":"Mẫu câu xin/mua đồ: ください = 'xin cho tôi'. Số lượng đặt sau N, trước ください.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ りんごみっつをください → ✅ りんごをみっつください — を đi ngay sau N, số lượng đứng trước ください.","compare":"","examples":[{"jp":"みずを ください。","vn":"Cho tôi nước."},{"jp":"このほんを ２さつ ください。","vn":"Cho tôi 2 cuốn sách này."},{"jp":"たまごを ふたつ ください。","vn":"Cho tôi 2 quả trứng."},{"jp":"おちゃを ください。","vn":"Cho tôi trà."}]},{"title":"いくらですか","formula":"N は いくらですか ⇒ ～えんです\nSố | Đọc | Ngoại lệ\n100 | ひゃく | 300 さんびゃく ⚠️\n600 | ろっぴゃく ⚠️ | 800 はっぴゃく ⚠️\n1,000 | せん | 3,000 さんぜん ⚠️\n8,000 | はっせん ⚠️ | 10,000 いちまん","explain":"Hỏi giá. いくら = bao nhiêu (tiền). Trả lời: [số] えん です.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ このかばんはなんですか (muốn hỏi giá) → ✅ このかばんはいくらですか — なんですか hỏi 'là gì', いくらですか hỏi giá.","compare":"","examples":[{"jp":"このかばんは いくらですか。　― ３，０００えんです。","vn":"Cái túi này giá bao nhiêu?"},{"jp":"ぜんぶで いくらですか。　― ５，５００えんです。","vn":"Tổng cộng bao nhiêu?"},{"jp":"このかばんはなんですか","vn":"muốn hỏi giá"}]},{"title":"和語数詞 ひとつ～とお","formula":"ひとつ／ふたつ／みっつ／…／とお\n1 ひとつ | 2 ふたつ | 3 みっつ | 4 よっつ | 5 いつつ\n6 むっつ | 7 ななつ | 8 やっつ | 9 ここのつ | 10 とお","explain":"Đây là hệ đếm thuần Nhật (和語 — wago), dùng cho đồ vật KHÔNG có từ đếm chuyên biệt, đếm từ 1 đến 10.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ ほんをふたつ → ✅ ほんを２さつ — sách có từ đếm riêng ～さつ.","compare":"和語 ひとつ～ (thuần Nhật)  vs  漢語 ～こ (Hán-Nhật)\n和語 ひとつ～ (thuần Nhật) | 漢語 ～こ (Hán-Nhật)\nPhạm vi | 1-10 (chỉ đến とお) | Bất kỳ số nào\nDùng khi | Không có từ đếm riêng | Vật nhỏ, tròn\nVí dụ | りんごをみっつ | りんごを３こ (cũng đúng)","examples":[{"jp":"たまごを ふたつ ください。","vn":"Cho tôi 2 quả trứng."},{"jp":"いすが みっつ あります。","vn":"Có 3 cái ghế."},{"jp":"みずを ください。","vn":"Cho tôi nước."}]},{"title":"V ませんか ／ V ましょう（誘い・提案）","formula":"V ませんか（lời mời）／ V ましょう（đề nghị cùng）\nCấu trúc | Ví dụ | Nghĩa\nV ます → ませんか | いきませんか | Đi không?\nV ます → ましょう | いきましょう | Đi thôi!\nV ます → ましょうか | もちましょうか | Để tôi mang giúp nhé?","explain":"Vませんか = 'Bạn có muốn ～ không?' — mời ai làm gì, chờ đối phương đồng ý.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"Dùng khi: Vませんか: lời mời lịch sự. Vましょう: khi đã gần quyết định, rủ mạnh hơn.\n❌ いきませんかよ → ✅ いきませんか — ませんか đã đủ lịch sự, không thêm よ.","compare":"V ませんか（mời）  vs  V ましょう（rủ/đề nghị）\nV ませんか（mời） | V ましょう（rủ/đề nghị）\nSắc thái | Chờ đối phương đồng ý | Quyết định gần như xong\nTông | Lịch sự, mềm hơn | Tự tin, rủ mạnh hơn\nVí dụ | いっしょに いきませんか。 | いっしょに いきましょう。\nNghĩa | Cùng đi không? | Cùng đi thôi!","examples":[{"jp":"いっしょに ひるごはんを たべませんか。","vn":"Cùng ăn trưa không?"},{"jp":"つかれましたね。すこし やすみましょう。","vn":"Mệt nhỉ. Nghỉ một chút đi."},{"jp":"いきませんか","vn":"Đi không?"},{"jp":"いきましょう","vn":"Đi thôi!"},{"jp":"もちましょうか","vn":"Để tôi mang giúp nhé?"}]},{"title":"なん ／ なに（使い分け）","formula":"なん + [て/じ/ご/にん...] ／ なに + [を/が/か/も]","explain":"なに và なん đều là 何 — nhưng đọc khác nhau theo âm tiếp theo.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"Dùng khi: Nếu từ sau bắt đầu bằng d/t/n → なん. Trước trợ từ → なに.\n❌ いま なにじですか → ✅ いまなんじですか — trước 時(じ) dùng なん.","compare":"","examples":[{"jp":"これは なんですか。","vn":"Cái này là cái gì?"},{"jp":"なにを かいますか。","vn":"Bạn mua gì?"},{"jp":"このかばんは いくらですか。　― ３，０００えんです。","vn":"Cái túi này giá bao nhiêu?"}]},{"title":"お～（丁寧の接頭語）","formula":"お + [từ Nhật thuần]","explain":"お～ là tiền tố kính ngữ, thêm sắc thái lịch sự cho danh từ.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"Dùng khi: Trong ngữ cảnh lịch sự: nhà hàng, cửa hàng, giao tiếp trang trọng.\n❌ おコーヒー → ✅ コーヒー — từ ngoại lai không thêm お.","compare":"","examples":[{"jp":"おちゃを ください。","vn":"Cho tôi trà."},{"jp":"おいくつですか。","vn":"Bạn bao nhiêu tuổi? (lịch sự)"},{"jp":"いっしょに ひるごはんを たべませんか。","vn":"Cùng ăn trưa không?"}]},{"title":"助数詞: Bảng trợ từ đếm theo loại vật","formula":"[Danh từ] + số đếm + 助数詞 (人/個/本/枚/冊/杯...)","explain":"Mỗi loại danh từ có trợ từ đếm (助数詞) riêng, giống 'cái/chiếc/con/quyển' trong tiếng Việt - không thể dùng chung 1 từ cho mọi vật.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.\nほん có 3 cách đọc biến âm theo số trước nó: いっぽん, にほん, さんぼん - cần học thuộc bảng biến âm.","usage":"Dùng khi: Dùng khi hỏi/nói số lượng người, đồ vật, cần chọn đúng 助数詞 theo hình dạng/loại vật.\n❌ 3にんの がくせい dat danh tu sau → ✅ がくせいが 3にん — Trật tự tiếng Nhật: Danh từ trước, rồi mới đến số + 助数詞","compare":"","examples":[{"jp":"あそこに せんせいが 3にん います。","vn":"Ở đằng kia có 3 giáo viên."},{"jp":"ボールペンを 2ほん かいました。","vn":"Tôi đã mua 2 cái bút bi."},{"jp":"これは なんですか。","vn":"Cái này là cái gì?"}]}],"7":[{"title":"[場所] に N が あります／います","formula":"[Nơi] に N が あります／います","explain":"Giới thiệu sự tồn tại MỚI: '(Ở nơi X) có N'. Dùng khi người nghe chưa biết về N.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ こうえんで こどもがいます → ✅ こうえんに こどもがいます — tồn tại dùng に, không phải で.","compare":"あります  vs  います\nあります | います\nDùng cho | Đồ vật, thực vật | Người, động vật\nVí dụ | ほんがあります | ねこがいます\nRobot? | ロボットがあります (vô sinh) | ロボットがいます (nếu có AI/tự di chuyển)\nCá trong bể? | — | さかながいます (sinh vật)","examples":[{"jp":"つくえの うえに ほんが あります。","vn":"Trên bàn có sách."},{"jp":"こうえんに こどもが います。","vn":"Trong công viên có trẻ em."},{"jp":"ロボットがあります","vn":"vô sinh"},{"jp":"ロボットがいます","vn":"nếu có AI/tự di chuyển"},{"jp":"さかながいます","vn":"sinh vật"}]},{"title":"N は [場所] に あります／います","formula":"N は [Nơi] に あります／います","explain":"Hỏi/nói về vị trí của vật/người ĐÃ BIẾT. Dùng は vì N là thông tin cũ (đã nhắc đến).\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.\n2 pattern: (1) ここにNが ← giới thiệu: 'ở đây CÓ N'. (2) Nはここに ← hỏi vị trí: 'N Ở đâu'.","usage":"❌ やまださんはどこにいますか → ✅ やまださんはどこにいますか — đúng rồi! Nhưng: やまださんはどこにありますか → ✅ います — người dùng います.","compare":"","examples":[{"jp":"えきは どこに ありますか。　― あそこに あります。","vn":"Ga tàu ở đâu?"},{"jp":"やまださんは いま どこに いますか。","vn":"Bây giờ anh Yamada đang ở đâu?"},{"jp":"つくえの うえに ほんが あります。","vn":"Trên bàn có sách."}]},{"title":"N（道具）で V ます","formula":"[Công cụ/Phương tiện] で [動詞]","explain":"で chỉ công cụ hoặc phương tiện dùng để thực hiện hành động.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"Dùng khi: Dùng khi nói đến công cụ, vật liệu dùng để làm gì: viết bằng bút, ăn bằng đũa, gọi bằng điện thoại.\n❌ えんぴつに かきます → ✅ えんぴつで かきます — công cụ dùng で.","compare":"","examples":[{"jp":"えんぴつで かきます。","vn":"Viết bằng bút chì."},{"jp":"はしで たべます。","vn":"Ăn bằng đũa."},{"jp":"つくえの うえに ほんが あります。","vn":"Trên bàn có sách."},{"jp":"えきは どこに ありますか。　― あそこに あります。","vn":"Ga tàu ở đâu?"}]},{"title":"～語で なんですか","formula":"[言語] で [Từ/Câu] は なんですか ／ ～は ～語で ～です","explain":"'～語で' = 'bằng tiếng ～'. ～語でなんですか = 'Tiếng ～ gọi là gì?'\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"Dùng khi: Hỏi cách gọi một từ trong ngôn ngữ khác — rất thực tế khi học ngôn ngữ.\n❌ ～ごがなんですか → ✅ ～語でなんですか — dùng で (phương tiện ngôn ngữ).","compare":"","examples":[{"jp":"「ありがとう」は ベトナムごで なんですか。","vn":"'Arigatou' tiếng Việt là gì?"},{"jp":"にほんごで「おはようございます」は えいごで なんですか。","vn":"Tiếng Anh 'ohayou gozaimasu' là gì?"},{"jp":"えんぴつで かきます。","vn":"Viết bằng bút chì."}]},{"title":"N に あげます ／ N に もらいます","formula":"N₁ は N₂（人）に N₃ を あげます ／ N₁ は N₂（人）に N₃ を もらいます\nHướng | Ví dụ | Nghĩa\nあげます (cho) | わたしは ともだちに ほんを あげます | Tôi cho bạn cuốn sách\nもらいます (nhận) | わたしは ともだちに ほんを もらいます | Tôi nhận sách từ bạn","explain":"あげます = tôi/ai đó CHO người khác. もらいます = tôi/ai đó NHẬN từ người khác.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"Dùng khi: Nói về việc tặng quà, cho/nhận đồ vật trong các dịp đặc biệt hoặc hàng ngày.\n❌ たなかさんをほんをあげます → ✅ たなかさんにほんをあげます — người nhận dùng に.","compare":"あげます（cho）  vs  もらいます（nhận）\nあげます（cho） | もらいます（nhận）\nChủ thể | Người cho (ngôi 1) | Người nhận (ngôi 1)\nに = ai | Người nhận | Người cho\nVí dụ | たなかさんにほんをあげます | たなかさんにほんをもらいます\nNghĩa | Cho Tanaka sách | Nhận sách từ Tanaka","examples":[{"jp":"たんじょうびに ははに はなを あげました。","vn":"Vào ngày sinh nhật, tôi đã tặng hoa cho mẹ."},{"jp":"せんせいに じしょを もらいました。","vn":"Tôi đã nhận từ điển từ giáo viên."},{"jp":"わたしは ともだちに ほんを あげます","vn":"Tôi cho bạn cuốn sách"},{"jp":"わたしは ともだちに ほんを もらいます","vn":"Tôi nhận sách từ bạn"},{"jp":"もらいます","vn":"nhận"}]},{"title":"もう V ました（完了）","formula":"もう V ました ／ もう ～ましたか","explain":"もう + V ました = đã làm xong rồi (hoàn thành và còn hiệu lực hiện tại).\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"Dùng khi: Nói rằng một việc đã được hoàn thành; hỏi xem ai đó đã làm xong việc gì chưa.\n❌ いいえ、まだしませんでした → ✅ いいえ、まだです — trả lời 'chưa' chỉ cần まだです.","compare":"","examples":[{"jp":"もう おひるごはんを たべましたか。　― はい、もう たべました。","vn":"Ăn trưa chưa?"},{"jp":"もう しゅくだいを しましたか。　― いいえ、まだです。","vn":"Làm bài tập chưa?"},{"jp":"たんじょうびに ははに はなを あげました。","vn":"Vào ngày sinh nhật, tôi đã tặng hoa cho mẹ."}]}],"8":[{"title":"A と B と どちらが ～ですか","formula":"A と B と どちらが [Adj] ですか ⇒ A のほうが ～です","explain":"So sánh 2 đối tượng. どちら = cái nào (trong 2). Trả lời: [A] のほうが [Adj] です.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ AはBよりどちらが → ✅ AとBとどちらが — so sánh 2 vế dùng と…と…どちら.","compare":"","examples":[{"jp":"にくと さかなと どちらが すきですか。　― さかなの ほうが すきです。","vn":"Thịt và cá, bạn thích cái nào hơn?"},{"jp":"でんしゃと バスと どちらが はやいですか。　― でんしゃの ほうが はやいです。","vn":"Tàu điện và xe buýt, cái nào nhanh hơn?"},{"jp":"にほんは どうですか。　― とても おもしろいです。","vn":"Nhật Bản thế nào?"},{"jp":"この３つの なかで どれが いちばん やすいですか。","vn":"Trong 3 cái này, cái nào rẻ nhất?"},{"jp":"くだものの なかで なにが いちばん すきですか。　― りんごが いちばん すきです。","vn":"Trong số hoa quả, bạn thích loại nào nhất?"}]},{"title":"イA ／ ナA — 4 dạng chia","formula":"イA: い→くない/かった/くなかった ／ ナA: だ→じゃない/だった/じゃなかった\n+HT | −HT | +QK | −QK\nHiện tại + | Hiện tại − | Quá khứ + | Quá khứ −\nたかい (đắt) | たかいです | たかくないです | たかかったです | たかくなかったです\nしずか (yên tĩnh) | しずかです | しずかじゃないです | しずかでした | しずかじゃなかったです\nいい (tốt) ⚠️ | いいです | よくないです | よかったです | よくなかったです","explain":"Tính từ Nhật chia theo giống động từ — 4 dạng: hiện tại +/−, quá khứ +/−.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"Dùng khi: Dùng mọi ngữ cảnh — diễn tả cảm giác, nhận xét, trả lời câu hỏi về tính chất.\n❌ たかいくないです → ✅ たかくないです — bỏ い rồi mới thêm くない.","compare":"","examples":[{"jp":"きのうは あまり さむくなかったです。","vn":"Hôm qua không lạnh lắm."},{"jp":"あのみせは しずかじゃなかったです。うるさかったです。","vn":"Quán đó không yên tĩnh. Ồn ào."},{"jp":"このケーキは とても おいしいです。","vn":"Bánh này rất ngon."}]},{"title":"イA ／ ナA ＋ N（修飾）","formula":"[イA] + N ／ [ナA] な + N\nLoại | Ví dụ | Nghĩa\nイA trực tiếp | おいしい りょうり | đồ ăn ngon\nナA + な | しずかな みせ | quán yên tĩnh\nナA + な | きれいな ひと | người đẹp\nいい (tốt) | いい ところ | nơi tốt","explain":"Tính từ đứng trước danh từ để bổ nghĩa. Đây gọi là 連体修飾 (modifier).\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"Dùng khi: Mô tả danh từ: 'đồ ăn ngon', 'quán yên tĩnh', 'người giỏi'.\n❌ しずかみせ → ✅ しずかなみせ — ナA phải thêm な trước danh từ.","compare":"","examples":[{"jp":"これは おいしい ケーキです。","vn":"Đây là bánh ngon."},{"jp":"にぎやかな まちが すきです。","vn":"Tôi thích thành phố sôi động."},{"jp":"にほんごは おもしろいですが、むずかしいです。","vn":"Tiếng Nhật thú vị, nhưng khó."}]},{"title":"とても ／ あまり ／ ちょっと（程度副詞）","formula":"とても [A肯定] ／ あまり [A否定] ／ ちょっと [A]\nCấu trúc | Ví dụ | Nghĩa\nとても + A肯定 | とても おいしいです | rất ngon\nあまり + A否定 | あまり おいしくないです | không ngon lắm\nちょっと + A | ちょっと たかいです | hơi đắt\nぜんぜん + A否定 | ぜんぜん おいしくないです | không ngon tí nào","explain":"とても = rất (dùng với khẳng định). あまり = không lắm (dùng với phủ定).\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"Dùng khi: Thêm mức độ cho tính từ/cảm xúc. あまり + phủ定 = 'không lắm' (khác ぜんぜん = không chút nào).\n❌ あまりすきです → ✅ あまりすきじゃないです — あまり luôn đi với phủ定.","compare":"あまり（不完全否定）  vs  ぜんぜん（完全否定）\nあまり（不完全否定） | ぜんぜん（完全否定）\nMức độ | Không lắm (có nhưng ít) | Không tí nào\nVí dụ | あまりすきじゃないです | ぜんぜんすきじゃないです\nNghĩa | Không thích lắm | Không thích tí nào","examples":[{"jp":"このケーキは とても おいしいです。","vn":"Bánh này rất ngon."},{"jp":"えいごは あまり じょうずじゃないです。","vn":"Tiếng Anh tôi không giỏi lắm."},{"jp":"とても おいしいです","vn":"rất ngon"},{"jp":"あまり おいしくないです","vn":"không ngon lắm"},{"jp":"ちょっと たかいです","vn":"hơi đắt"}]},{"title":"N はどうですか（印象・意見）","formula":"N は どうですか ⇒ ～です / [Adj] です","explain":"どうですか = 'thế nào, như thế nào' — hỏi ý kiến, cảm nhận về N.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"Dùng khi: Hỏi nhận xét sau khi ai đó trải nghiệm điều gì; hoặc đề nghị nhẹ nhàng.\n❌ にほんはどんなですか → ✅ にほんはどうですか — どうですか hỏi ý kiến/cảm nhận; どんなNですか hỏi đặc điểm.","compare":"","examples":[{"jp":"にほんは どうですか。　― とても おもしろいです。","vn":"Nhật Bản thế nào?"},{"jp":"このりょうりは どうですか。　― おいしいですね。","vn":"Món ăn này thế nào?"},{"jp":"とうきょうは おおさかより おおきいです。","vn":"Tokyo lớn hơn Osaka."}]},{"title":"S1 が、S2（逆接）","formula":"文₁ が、文₂（nhưng, tuy nhiên）","explain":"が nối 2 mệnh đề với nghĩa 'nhưng/tuy nhiên' — thể hiện sự tương phản nhẹ.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"Dùng khi: Khi muốn nói điều gì đó nhưng có vế tương phản — 'A nhưng B'.\n❌ が đứng đầu câu (bài 8) → ✅ が trong bài 8 nối 2 mệnh đề. が đầu câu = 'Xin lỗi nhưng…' (bài 14).","compare":"","examples":[{"jp":"にほんごは おもしろいですが、むずかしいです。","vn":"Tiếng Nhật thú vị, nhưng khó."},{"jp":"このレストランは やすいですが、おいしいです。","vn":"Nhà hàng này rẻ nhưng ngon."},{"jp":"にくと さかなと どちらが すきですか。　― さかなの ほうが すきです。","vn":"Thịt và cá, bạn thích cái nào hơn?"}]},{"title":"どれ（3つ以上から選ぶ）","formula":"どれが ～ですか ／ どれが いちばん ～ですか","explain":"どれ = cái nào (trong 3 vật trở lên). どちら = cái nào (trong 2 vật).\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"Dùng khi: Khi có 3 lựa chọn trở lên: 'Bạn thích cái nào nhất trong số này?'\n❌ Dùng どれ khi chỉ có 2 lựa chọn → ✅ 2 lựa chọn dùng どちら.","compare":"どちら（2 vật）  vs  どれ（3+ vật）\nどちら（2 vật） | どれ（3+ vật）\nSố lượng | Chọn trong 2 | Chọn trong 3+\nVí dụ | AとBとどちらが… | どれが いちばん…\nTrả lời | Aのほうが… | これが いちばん…","examples":[{"jp":"この３つの なかで どれが いちばん やすいですか。","vn":"Trong 3 cái này, cái nào rẻ nhất?"},{"jp":"どれが やまださんの かばんですか。　― これです。","vn":"Cái nào là túi của anh Yamada?"},{"jp":"にくと さかなと どちらが すきですか。　― さかなの ほうが すきです。","vn":"Thịt và cá, bạn thích cái nào hơn?"}]},{"title":"N は N より ～です","formula":"N₁ は N₂ より [Adj] です","explain":"より = 'hơn'. N₁ [Adj] hơn N₂. Tiếng Nhật không có dạng so sánh đặc biệt cho tính từ.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ AはBよりもっとおおきいです → ✅ AはBよりおおきいです — tiếng Nhật không dùng もっと trong so sánh hơn.","compare":"","examples":[{"jp":"とうきょうは おおさかより おおきいです。","vn":"Tokyo lớn hơn Osaka."},{"jp":"でんしゃは バスより はやいです。","vn":"Tàu điện nhanh hơn xe buýt."},{"jp":"にくと さかなと どちらが すきですか。　― さかなの ほうが すきです。","vn":"Thịt và cá, bạn thích cái nào hơn?"},{"jp":"きのうは あまり さむくなかったです。","vn":"Hôm qua không lạnh lắm."},{"jp":"これは おいしい ケーキです。","vn":"Đây là bánh ngon."}]},{"title":"～の なかで ～が いちばん ～","formula":"[Nhóm] の なかで [N] が いちばん [Adj] です","explain":"So sánh nhất trong một nhóm. いちばん = nhất. のなかで = trong số.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ くだものいちばんすきなのはりんごです → ✅ くだもののなかでりんごがいちばんすきです — cấu trúc chuẩn: のなかで+N+がいちばん.","compare":"","examples":[{"jp":"くだものの なかで なにが いちばん すきですか。　― りんごが いちばん すきです。","vn":"Trong số hoa quả, bạn thích loại nào nhất?"},{"jp":"にほんで いちばん たかい やまは ふじさんです。","vn":"Núi cao nhất ở Nhật là núi Fuji."},{"jp":"この３つの なかで どれが いちばん やすいですか。","vn":"Trong 3 cái này, cái nào rẻ nhất?"}]}],"9":[{"title":"V たいです","formula":"V ます幹 + たいです ／ たくないです ／ たかったです\nV ます → 幹 | ＋たいです | Nghĩa\nたべます → たべ | → たべたいです | muốn ăn\nいきます → いき | → いきたいです | muốn đi\nのみます → のみ | → のみたいです | muốn uống\nします → し | → したいです | muốn làm","explain":"Diễn tả mong muốn của NGƯỜI NÓI (ngôi 1). Cách tạo: bỏ ます, thêm たいです.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ やまださんはいきたいです → ✅ やまださんはいきたがっています — người khác dùng たがっています.","compare":"","examples":[{"jp":"にほんへ いきたいです。","vn":"Tôi muốn đi đến Nhật Bản."},{"jp":"つめたい みずが のみたいです。","vn":"Tôi muốn uống nước lạnh."},{"jp":"＋たいです","vn":"Nghĩa"},{"jp":"→ たべたいです","vn":"muốn ăn"},{"jp":"→ いきたいです","vn":"muốn đi"}]},{"title":"V に いきます","formula":"V ます幹 + に いきます／きます／かえります","explain":"Diễn tả mục đích di chuyển: 'đi để làm gì'. V ます幹 + に = mục đích.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ かいものをいきます → ✅ かいものにいきます — mục đích di chuyển dùng に, không phải を.","compare":"","examples":[{"jp":"かいものに いきます。","vn":"Tôi đi mua sắm."},{"jp":"すしを たべに いきましょう。","vn":"Đi ăn sushi đi."},{"jp":"にほんへ いきたいです。","vn":"Tôi muốn đi đến Nhật Bản."}]},{"title":"なにも／だれも／どこも ～ません","formula":"[疑問詞] + も + [動詞 phủ định]","explain":"Phủ định tuyệt đối. なにも = không gì, だれも = không ai, どこも = không đâu.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ なにもたべます → ✅ なにもたべません — なにも luôn đi với phủ định.","compare":"～か (gì đó / ai đó)  vs  ～も ～ない (không gì / không ai)\n～か (gì đó / ai đó) | ～も ～ない (không gì / không ai)\nLoại câu | Khẳng định / Hỏi | Phủ định\nなに | なにか たべますか | なにも たべません\nだれ | だれか きましたか | だれも きませんでした\nどこ | どこかへ いきたいです | どこも いきたくないです","examples":[{"jp":"なにも たべたくないです。","vn":"Tôi không muốn ăn gì cả."},{"jp":"きのう だれも きませんでした。","vn":"Hôm qua không ai đến cả."},{"jp":"かいものに いきます。","vn":"Tôi đi mua sắm."}]},{"title":"N が あります（所有・能力）","formula":"N が あります（持っている）／ N が わかります（hiểu được）","explain":"Ngoài nghĩa 'tồn tại' (bài 7), が あります còn nghĩa 'có' (sở hữu) và 'hiểu được' (năng lực).\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"Dùng khi: Nói về sở hữu vô hình (thời gian, tiền, năng lực) hoặc sự hiểu biết.\n❌ じかんをあります → ✅ じかんがあります — sở hữu/tồn tại dùng が.","compare":"","examples":[{"jp":"あしたは じかんが ありますか。　― はい、あります。","vn":"Ngày mai bạn có thời gian không?"},{"jp":"にほんごが わかりますか。　― すこし わかります。","vn":"Bạn hiểu tiếng Nhật không?"},{"jp":"が わかります","vn":"hiểu được"}]},{"title":"N が すき／きらい／じょうず／へた です","formula":"N が [すき/きらい/じょうず/へた] です\nCấu trúc | Ví dụ | Nghĩa\nN が すきです | さかながすきです | Tôi thích cá.\nN が きらいです | にんじんがきらいです | Tôi ghét cà rốt.\nN が じょうずです | えいごがじょうずです | Giỏi tiếng Anh.\nN が へたです | うたがへたです | Hát kém.","explain":"Diễn tả sở thích và năng lực. Tất cả đều là ナA, dùng が làm trợ từ.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"Dùng khi: Nói về sở thích ăn uống, hoạt động, môn học; năng lực ngôn ngữ, thể thao.\n❌ さかなをすきです → ✅ さかながすきです — すき/きらい/じょうず/へた dùng が.","compare":"","examples":[{"jp":"わたしは スポーツが だいすきです。","vn":"Tôi rất thích thể thao."},{"jp":"やまださんは りょうりが じょうずですね。","vn":"Anh Yamada nấu ăn giỏi nhỉ."},{"jp":"さかながすきです","vn":"Tôi thích cá."},{"jp":"にんじんがきらいです","vn":"Tôi ghét cà rốt."},{"jp":"えいごがじょうずです","vn":"Giỏi tiếng Anh."}]},{"title":"どんな N（特徴・種類）","formula":"どんな N が すきですか ／ どんな N ですか","explain":"どんな = 'loại nào, kiểu gì, như thế nào'. Hỏi đặc điểm, tính chất, thể loại.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"Dùng khi: Hỏi về sở thích, đặc điểm: 'Bạn thích loại nhạc nào?', 'Người đó như thế nào?'\n❌ どんなですか → ✅ どんなNですか — どんな là liên thể từ, phải đi kèm danh từ.","compare":"","examples":[{"jp":"どんな おんがくが すきですか。　― ジャズが すきです。","vn":"Bạn thích loại nhạc nào?"},{"jp":"どんな しごとを したいですか。　― えいごを つかう しごとが したいです。","vn":"Bạn muốn làm công việc loại gì?"},{"jp":"なにも たべたくないです。","vn":"Tôi không muốn ăn gì cả."}]},{"title":"よく／だいたい／たくさん／すこし／あまり／ぜんぜん","formula":"[Trạng từ] + V（khẳng định） ／ あまり/ぜんぜん + V ません\nCấu trúc | Ví dụ | Nghĩa\nよく V | よく えいがを みます | Hay xem phim\nだいたい V | だいたい ８じに ねます | Thường ngủ lúc 8h\nすこし V | すこし わかります | Hiểu một chút\nあまり V ません | あまり やさいを たべません | Không hay ăn rau\nぜんぜん V ません | ぜんぜん わかりません | Không hiểu tí nào","explain":"Nhóm trạng từ chỉ tần suất và mức độ — dùng trước động từ hoặc tính từ.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"Dùng khi: Nói về mức độ thường xuyên, số lượng, mức độ của cảm giác hay năng lực.\n❌ あまりすきです → ✅ あまりすきじゃないです — あまり luôn đi với phủ định.","compare":"","examples":[{"jp":"まいにち よく べんきょうしています。","vn":"Mỗi ngày tôi học chăm chỉ."},{"jp":"にほんごは すこし わかります。","vn":"Tiếng Nhật tôi hiểu một chút."},{"jp":"よく えいがを みます","vn":"Hay xem phim"},{"jp":"だいたい ８じに ねます","vn":"Thường ngủ lúc 8h"},{"jp":"すこし わかります","vn":"Hiểu một chút"}]},{"title":"S₁ から、S₂（理由）","formula":"S₁ から、S₂ ／ どうして S₂ですか ⇒ S₁ から です\nCấu trúc | Ví dụ | Nghĩa\nLý do (から) → Kết quả | さむいから、コートをきます。 | Vì lạnh nên mặc áo khoác.\nHỏi lý do | どうして にほんごを べんきょうしますか | Sao bạn học tiếng Nhật?\nTrả lời lý do | にほんへ いきたいからです。 | Vì muốn đi Nhật.","explain":"から = 'vì, bởi vì' khi nêu lý do. Đặt ở cuối mệnh đề nguyên nhân.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"Dùng khi: Giải thích lý do cho hành động, quyết định, cảm xúc.\n❌ さむいだから → ✅ さむいから — イA không cần だ trước から.","compare":"","examples":[{"jp":"つかれたから、はやく ねます。","vn":"Vì mệt nên tôi ngủ sớm."},{"jp":"どうして にほんごを べんきょうしますか。　― にほんが すきだから です。","vn":"Sao bạn học tiếng Nhật?"},{"jp":"さむいから、コートをきます。","vn":"Vì lạnh nên mặc áo khoác."},{"jp":"どうして にほんごを べんきょうしますか","vn":"Sao bạn học tiếng Nhật?"},{"jp":"にほんへ いきたいからです。","vn":"Vì muốn đi Nhật."}]}],"10":[{"title":"もう ～ましたか","formula":"もう ～ましたか ⇒ はい、もう～ました ／ いいえ、まだです","explain":"もう + V ました = hành động đã hoàn thành. Hỏi: もう V ましたか (đã V chưa?).\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ いいえ、まだしませんでした → ✅ いいえ、まだです — trả lời chưa xong dùng まだです.","compare":"もう V ました  vs  まだ V ていません\nもう V ました | まだ V ていません\nTrạng thái | Hoàn thành | Chưa hoàn thành\nTrả lời câu hỏi | はい、もう Vました | いいえ、まだです\nĐang làm dở | — | まだ Vています (đang làm)\nVí dụ | もう たべました | まだ たべていません","examples":[{"jp":"もう ひるごはんを たべましたか。　― はい、もう たべました。","vn":"Ăn trưa chưa?"},{"jp":"もう しゅくだいを しましたか。　― いいえ、まだです。","vn":"Làm bài tập chưa?"},{"jp":"まだ Vています","vn":"đang làm"},{"jp":"「しゅくだいは もう しましたか。」「いいえ、これから します。」","vn":"'Bài tập đã làm chưa?' 'Chưa, sắp làm đây.'"}]},{"title":"V てから","formula":"V₁ て形 + から、V₂","explain":"Diễn tả trình tự: 'sau khi V₁ xong, rồi V₂'. V₁ phải hoàn thành TRƯỚC khi V₂ bắt đầu.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ たべるから → ✅ たべてから — phải dùng thể て + から, không phải thể từ điển + から.","compare":"V₁て、V₂ (nối tiếp)  vs  V₁てから、V₂ (trình tự)\nV₁て、V₂ (nối tiếp) | V₁てから、V₂ (trình tự)\nNhấn mạnh | Liệt kê hành động liên tiếp | V₁ phải xong trước V₂\nVí dụ | おきて、たべます | おきてから、たべます\nSắc thái | Thức dậy rồi ăn (liên tiếp) | Thức dậy XONG rồi mới ăn","examples":[{"jp":"シャワーを あびてから、でかけます。","vn":"Tắm xong rồi mới ra ngoài."},{"jp":"しごとが おわってから、ともだちに あいます。","vn":"Sau khi tan làm thì gặp bạn."},{"jp":"もう ひるごはんを たべましたか。　― はい、もう たべました。","vn":"Ăn trưa chưa?"}]},{"title":"N や N（例示列挙）","formula":"N₁ や N₂（や N₃…）","explain":"や nối các danh từ khi liệt kê một vài ví dụ đại diện — ngụ ý 'còn những thứ khác nữa'.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"Dùng khi: Khi muốn đưa ví dụ mà không liệt kê hết — 'ví dụ như A, B...'.\n❌ ほんとノートなどがあります (muốn nói đại diện) → ✅ ほんやノートなどがあります — liệt kê đại diện dùng や.","compare":"と（đầy đủ）  vs  や（đại diện）\nと（đầy đủ） | や（đại diện）\nÝ nghĩa | Liệt kê tất cả | Liệt kê ví dụ (còn nữa)\nVí dụ | ほんとペンがあります | ほんやペンがあります\nNgụ ý | Chỉ có sách và bút | Có sách, bút (và có thể những thứ khác)","examples":[{"jp":"かばんの なかに ほんや ノートや ペンが あります。","vn":"Trong túi có sách, vở, bút (và những thứ khác)."},{"jp":"すきな たべものは にほんりょうりや イタリアりょうりなどです。","vn":"Đồ ăn tôi thích là ẩm thực Nhật, Ý v.v."},{"jp":"ほんとノートなどがあります","vn":"muốn nói đại diện"}]},{"title":"まだ V ています（継続中）","formula":"まだ + V ています ／ まだ + V ていません","explain":"まだ ～ています = vẫn còn đang V (hành động tiếp diễn, chưa kết thúc).\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ まだ V ませんでした (đang làm chưa xong) → ✅ まだ V ています — 'đang vẫn chưa xong' dùng ています, không dùng ませんでした.","compare":"まだです  vs  まだ V ています\nまだです | まだ V ています\nNghĩa | Chưa xong (trả lời ngắn) | Vẫn đang V (mô tả trạng thái)\nVí dụ | いいえ、まだです | まだレポートをかいています\nDùng khi | Trả lời もうましたか | Mô tả việc đang tiếp tục","examples":[{"jp":"まだ しゅくだいを やっています。","vn":"Tôi vẫn đang làm bài tập (chưa xong)."},{"jp":"やまださんは まだ かいしゃに います。","vn":"Anh Yamada vẫn còn ở công ty."},{"jp":"もう ひるごはんを たべましたか。　― はい、もう たべました。","vn":"Ăn trưa chưa?"}]},{"title":"これから V ます（今後の行動）","formula":"これから + V ます","explain":"これから = 'Từ bây giờ / từ lúc này'. Diễn tả hành động sẽ thực hiện SAU THỜI ĐIỂM HIỆN TẠI.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ これからもうたべます → ✅ これからたべます — もう (đã xong) và これから (sắp làm) không dùng cùng nhau.","compare":"","examples":[{"jp":"「しゅくだいは もう しましたか。」「いいえ、これから します。」","vn":"'Bài tập đã làm chưa?' 'Chưa, sắp làm đây.'"},{"jp":"これから でかけます。また あとで！","vn":"Tôi sắp ra ngoài. Hẹn gặp lại!"},{"jp":"シャワーを あびてから、でかけます。","vn":"Tắm xong rồi mới ra ngoài."},{"jp":"かばんの なかに ほんや ノートや ペンが あります。","vn":"Trong túi có sách, vở, bút (và những thứ khác)."},{"jp":"まだ しゅくだいを やっています。","vn":"Tôi vẫn đang làm bài tập (chưa xong)."}]}],"11":[{"title":"て形 — cách tạo","formula":"Nhóm I: く→いて, ぐ→いで, す→して, む/ぶ/ぬ→んで, つ/る/う→って  |  Nhóm II: ます→て  |  Nhóm III: します→して, きます→きて\nV ます | → V て | Quy tắc\nかきます (き→) | → かいて | Nhóm I: く→いて\nいそぎます (ぎ→) | → いそいで | Nhóm I: ぐ→いで\nはなします (し→) | → はなして | Nhóm I: す→して\nのみます (み→) | → のんで | Nhóm I: む→んで\nあそびます (び→) | → あそんで | Nhóm I: ぶ→んで\nしにます (に→) | → しんで | Nhóm I: ぬ→んで\nもちます (ち→) | → もって | Nhóm I: つ→って\nかえります (り→) | → かえって | Nhóm I: る→って\nかいます (い→) | → かって | Nhóm I: う→って\nたべます | → たべて | Nhóm II: ます→て\nみます | → みて | Nhóm II: ます→て\nします | → して | Nhóm III bất quy tắc\nきます | → きて | Nhóm III bất quy tắc\nいきます ⚠️ | → いって | Ngoại lệ duy nhất! (không phải いいて)","explain":"て形 là dạng kết nối — nền tảng cho RẤT NHIỀU ngữ pháp từ bài 10 đến bài 25.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"Dùng khi: て形 là cốt lõi — nếu chia sai て形, tất cả các mẫu câu dùng て形 đều sai. Hãy luyện tập hàng ngày.\n❌ いきて → ✅ いって — いきます là ngoại lệ DUY NHẤT trong Nhóm I.","compare":"","examples":[{"jp":"おきて、かおを あらって、ごはんを たべます。","vn":"Thức dậy, rửa mặt, rồi ăn cơm."},{"jp":"えきへ いって、でんしゃに のって、かいしゃへ いきます。","vn":"Đến ga, lên tàu, rồi đi đến công ty."},{"jp":"このりょうりは やすくて、おいしいです。","vn":"Món này vừa rẻ vừa ngon."}]},{"title":"Adj て (nối tính từ)","formula":"いAdj: ～くて ／ なAdj: ～で\nAdj | → て形 | Quy tắc\nやすい (rẻ) | → やすくて | いAdj: bỏ い → くて\nおおきい (to) | → おおきくて | いAdj: bỏ い → くて\nいい (tốt) | → よくて ⚠️ | Bất quy tắc: いい → よ~\nしずか(な) (yên tĩnh) | → しずかで | なAdj: bỏ な → で\nべんり(な) (tiện lợi) | → べんりで | なAdj: bỏ な → で","explain":"Nối tính từ khi mô tả nhiều đặc điểm. いAdj: bỏ い, thêm くて. なAdj: bỏ な, thêm で.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ やすいで → ✅ やすくて — いAdj bỏ い, thêm くて (KHÔNG thêm で).","compare":"","examples":[{"jp":"このりょうりは やすくて、おいしいです。","vn":"Món này vừa rẻ vừa ngon."},{"jp":"やまださんは しんせつで、おもしろいです。","vn":"Anh Yamada vừa tốt bụng vừa hài hước."},{"jp":"おきて、かおを あらって、ごはんを たべます。","vn":"Thức dậy, rửa mặt, rồi ăn cơm."}]},{"title":"V て V（動作の連続）","formula":"V₁て形、V₂て形、V₃ます","explain":"Nối nhiều hành động liên tiếp theo trình tự: 'V₁ rồi V₂ rồi V₃'. Chỉ動詞 cuối chia thì.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ たべた、シャワーをあびた → ✅ たべて、シャワーをあびて — liên tiếp dùng て形, không dùng た形.","compare":"","examples":[{"jp":"あさ おきて、シャワーを あびて、ごはんを たべます。","vn":"Sáng thức dậy, tắm, rồi ăn cơm."},{"jp":"えきへ いって、きっぷを かって、でんしゃに のりました。","vn":"Đến ga, mua vé, rồi lên tàu."},{"jp":"しゅくだいを してから、テレビを みます。","vn":"Làm bài tập xong rồi mới xem TV."}]},{"title":"V てから（先後順序）","formula":"V て形 + から、[hành động tiếp theo]","explain":"'Sau khi V₁ xong, rồi mới V₂'. Nhấn mạnh V₁ PHẢI xong trước rồi mới làm V₂.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ たべるから、ねます → ✅ たべてから、ねます — てから dùng て形, không dùng 辞書形.","compare":"V て V（連続）  vs  V てから V（先後）\nV て V（連続） | V てから V（先後）\nNghĩa | Làm A rồi tiếp B (liệt kê) | Sau khi A xong mới B (điều kiện)\nNhấn mạnh | Trình tự hành động | A phải hoàn thành trước\nVí dụ | おきて、かおをあらって、たべます | しゅくだいをしてから、テレビをみます","examples":[{"jp":"しゅくだいを してから、テレビを みます。","vn":"Làm bài tập xong rồi mới xem TV."},{"jp":"にほんへ きてから、３ねん たちました。","vn":"Sau khi đến Nhật đã được 3 năm rồi."},{"jp":"あさ おきて、シャワーを あびて、ごはんを たべます。","vn":"Sáng thức dậy, tắm, rồi ăn cơm."}]},{"title":"V ないで（否定の連続）","formula":"V ない形 + で、[hành động tiếp theo]\nV ます → V ない | → V ないで | Nghĩa\nたべます → たべない | → たべないで | không ăn mà…\nかきます → かかない | → かかないで | không viết mà…\nします → しない | → しないで | không làm mà…","explain":"'Không V mà (làm gì khác)' — diễn tả hành động được thực hiện trong trạng thái KHÔNG làm V.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ たべなくて、いきました → ✅ たべないで、いきました — 'không V mà làm' dùng ないで, không dùng なくて (なくて thường nối tính từ/lý do).","compare":"","examples":[{"jp":"あさごはんを たべないで、がっこうへ いきました。","vn":"Không ăn sáng mà đến trường."},{"jp":"でんきを けさないで、ねてしまいました。","vn":"Không tắt đèn mà ngủ mất rồi."},{"jp":"おきて、かおを あらって、ごはんを たべます。","vn":"Thức dậy, rửa mặt, rồi ăn cơm."}]}],"12":[{"title":"V ています (đang tiến hành)","formula":"V て形 + います","explain":"Hành động ĐANG diễn ra ở thời điểm nói. Tương đương Present Continuous (I am V-ing).\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"","compare":"","examples":[{"jp":"いま テレビを みています。","vn":"Bây giờ tôi đang xem TV."},{"jp":"こどもたちは こうえんで あそんでいます。","vn":"Bọn trẻ đang chơi ở công viên."},{"jp":"とうきょうに すんでいます。","vn":"Tôi đang sống ở Tokyo (= hiện tại ở Tokyo)."}]},{"title":"V ています (trạng thái kết quả)","formula":"V て形 + います (trạng thái)","explain":"Với động từ KẾT QUẢ (住む, 結婚する, 知る, 持つ, 着る...), ています = trạng thái HIỆN TẠI, không phải đang làm.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ しっていません → ✅ しりません — 知る phủ定 dùng 知りません, không dùng ていません.","compare":"V ています (tiến hành)  vs  V ています (trạng thái)\nV ています (tiến hành) | V ています (trạng thái)\nLoại động từ | Hành động (食べる, 見る, 遊ぶ…) | Kết quả (住む, 結婚する, 知る…)\nNghĩa | Đang làm (ngay lúc này) | Trạng thái hiện tại (kết quả vẫn còn)\nVí dụ | いまテレビをみています | とうきょうにすんでいます\nDịch | Đang xem TV (bây giờ) | Đang sống ở Tokyo (≠ đang chuyển đến)","examples":[{"jp":"とうきょうに すんでいます。","vn":"Tôi đang sống ở Tokyo (= hiện tại ở Tokyo)."},{"jp":"けっこんしています。こどもが ふたり います。","vn":"Tôi đã kết hôn. Có 2 con."},{"jp":"ています","vn":"tiến hành"},{"jp":"いま テレビを みています。","vn":"Bây giờ tôi đang xem TV."}]},{"title":"V ましょうか（申し出）","formula":"V ます形（除ます） + ましょうか","explain":"'Để tôi V cho nhé?' — chủ động đề nghị giúp đỡ người khác. Sắc thái quan tâm, lịch sự.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ いきましょうか → ✅ いっしょにいきましょうか (rủ cùng đi) hoặc いきましょうか (tôi đi thay cho bạn nhé?) — ましょうか có 2 nghĩa tùy ngữ cảnh.","compare":"V ましょう（勧誘）  vs  V ましょうか（申し出）\nV ましょう（勧誘） | V ましょうか（申し出）\nNghĩa | Cùng nhau V nào (rủ rê) | Để tôi V cho nhé (giúp đỡ)\nChủ thể | Cả hai cùng làm | Người nói làm cho người nghe\nVí dụ | いっしょに いきましょう | にもつを もちましょうか\nTrả lời phù hợp | ええ、いきましょう | ありがとうございます","examples":[{"jp":"にもつを もちましょうか。","vn":"Để tôi xách hành lý cho nhé?"},{"jp":"まどを しめましょうか。","vn":"Để tôi đóng cửa sổ cho nhé?"},{"jp":"いきましょうか → ✅ いっしょにいきましょうか","vn":"rủ cùng đi"}]},{"title":"ところです（進行の局面）","formula":"V 辞書形 + ところです ／ V ている + ところです ／ V た + ところです\nCấu trúc | Ví dụ | Nghĩa\nV 辞書形 + ところです | たべる ところです | sắp ăn (chưa bắt đầu)\nV ている + ところです | たべている ところです | đang ăn (giữa chừng)\nV た + ところです | たべた ところです | vừa mới ăn xong","explain":"Diễn tả GIAI ĐOẠN cụ thể của hành động: 'sắp/đang/vừa xong'. Chi tiết hơn ています.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ たべるところです (vừa ăn xong) → ✅ たべたところです — vừa xong dùng た形.","compare":"","examples":[{"jp":"いま でかける ところです。","vn":"Tôi sắp ra ngoài đây."},{"jp":"いま しょくじを している ところです。","vn":"Tôi đang ăn cơm (giữa chừng)."},{"jp":"たべる ところです","vn":"sắp ăn (chưa bắt đầu)"},{"jp":"たべている ところです","vn":"đang ăn (giữa chừng)"},{"jp":"たべた ところです","vn":"vừa mới ăn xong"}]}],"13":[{"title":"V てください (yêu cầu lịch sự)","formula":"V て形 + ください ／ V ないで ください (đừng)","explain":"Yêu cầu hoặc hướng dẫn lịch sự: 'Xin hãy V'. Lịch sự hơn mệnh lệnh trực tiếp.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ はなしてくださいません → ✅ はなしてくださいませんか — cần か ở cuối.","compare":"","examples":[{"jp":"ここに なまえを かいてください。","vn":"Hãy viết tên vào đây."},{"jp":"もうすこし ゆっくり はなしてください。","vn":"Hãy nói chậm hơn một chút."},{"jp":"しゃしんを とっても いいですか。　― はい、どうぞ。","vn":"Tôi chụp ảnh được không?"}]},{"title":"V てもいいですか (xin phép)","formula":"V て形 + もいいですか ⇒ はい、どうぞ ／ すみません、ちょっと…","explain":"Xin phép: 'Tôi V có được không?'. もいいですか = có tốt/ổn không?\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.\nNgười Nhật hiếm khi nói いいえ、だめです (Không, không được) — quá thẳng thừng. Thay bằng ちょっと… hoặc giải thích lý do.","usage":"Dùng khi: Dùng khi muốn làm gì đó mà cần sự đồng ý của người khác (trong lớp, nơi công cộng, nhà người khác).","compare":"","examples":[{"jp":"しゃしんを とっても いいですか。　― はい、どうぞ。","vn":"Tôi chụp ảnh được không?"},{"jp":"まどを あけても いいですか。　― ええ、いいですよ。","vn":"Tôi mở cửa sổ được không?"},{"jp":"いいえ、だめです","vn":"Không, không được"}]},{"title":"V てはいけません (cấm đoán)","formula":"V て形 + はいけません","explain":"Cấm đoán: 'KHÔNG ĐƯỢC V'. Mạnh hơn ないでください (yêu cầu nhẹ).\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"","compare":"V ないでください (nhẹ)  vs  V てはいけません (mạnh)\nV ないでください (nhẹ) | V てはいけません (mạnh)\nMức độ | Yêu cầu nhẹ nhàng | Cấm đoán / quy定\nNgữ cảnh | Nói chuyện hàng ngày | Nội quy, trường học, bệnh viện\nSắc thái | Tôi xin bạn đừng… | Bạn KHÔNG ĐƯỢC…\nVí dụ | しゃしんをとらないでください | しゃしんをとってはいけません","examples":[{"jp":"ここで タバコを すってはいけません。","vn":"Không được hút thuốc ở đây."},{"jp":"じゅぎょうちゅうに でんわを つかってはいけません。","vn":"Không được dùng điện thoại trong giờ học."},{"jp":"てはいけません","vn":"mạnh"}]},{"title":"N が ほしいです（欲求）","formula":"N が ほしいです ／ N が ほしくないです\nCấu trúc | Ví dụ | Nghĩa\nN が ほしいです | くるまが ほしいです | muốn có xe\nN が ほしくないです | おかねが ほしくないです | không muốn tiền\nN が ほしかったです | プレゼントが ほしかったです | đã muốn có quà","explain":"'Muốn có N' — diễn tả mong muốn sở hữu vật gì. Trợ từ PHẢI là が, không dùng を.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ くるまをほしいです → ✅ くるまがほしいです — ほしい luôn dùng が, không dùng を.","compare":"N が ほしいです  vs  V たいです\nN が ほしいです | V たいです\nĐối tượng | Danh từ (vật/thứ muốn có) | Động từ (hành động muốn làm)\nTrợ từ | N が ほしい | V たい\nVí dụ | くるまが ほしいです | くるまを かいたいです\nNghĩa | Tôi muốn có xe | Tôi muốn mua xe","examples":[{"jp":"あたらしい パソコンが ほしいです。","vn":"Tôi muốn có máy tính mới."},{"jp":"いま なにが いちばん ほしいですか。","vn":"Bây giờ bạn muốn gì nhất?"},{"jp":"くるまが ほしいです","vn":"muốn có xe"},{"jp":"おかねが ほしくないです","vn":"không muốn tiền"},{"jp":"プレゼントが ほしかったです","vn":"đã muốn có quà"}]},{"title":"S₁ が、S₂（前置き・逆接）","formula":"[Nền tảng/Đối lập] が、[Nội dung chính]","explain":"が nối 2 mệnh đề: nghĩa TUY NHIÊN hoặc NHƯNG MÀ. Cũng dùng như lời mở đầu lịch sự trước khi nêu yêu cầu.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ すみません、えきはどこですか → ✅ すみませんが、えきはどこですか — すみませんが (với が) lịch sự hơn khi nhờ người lạ.","compare":"","examples":[{"jp":"すみませんが、えきは どこですか。","vn":"Xin lỗi (nhưng mà)... nhà ga ở đâu ạ?"},{"jp":"たかいですが、とても おいしいです。","vn":"Tuy đắt nhưng rất ngon."},{"jp":"ここに なまえを かいてください。","vn":"Hãy viết tên vào đây."}]}],"14":[{"title":"～から (nguyên nhân)","formula":"[Nguyên nhân/Lý do] から、[Kết quả]","explain":"から đặt sau mệnh đề nguyên nhân: 'Vì A nên B'. Mệnh đề A (lý do) đứng trước から.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ からあめがふっています → ✅ あめがふっていますから — から đứng SAU lý do, không phải trước.","compare":"から (bài 4: từ)  vs  から (bài 14: vì)\nから (bài 4: từ) | から (bài 14: vì)\nNghĩa | Từ, kể từ (điểm bắt đầu) | Vì, bởi vì (nguyên nhân)\nVị trí | Sau danh từ chỉ nơi/thời gian | Sau mệnh đề hoàn chỉnh\nVí dụ | ９じから はたらきます | さむいですから コートをきます","examples":[{"jp":"あめが ふっていますから、うちに います。","vn":"Vì trời đang mưa nên tôi ở nhà."},{"jp":"やすいですから、いつも この みせで かいます。","vn":"Vì rẻ nên lúc nào cũng mua ở quán này."},{"jp":"どうして にほんへ きたんですか。　― にほんごが すきですから。","vn":"Sao bạn đến Nhật?"}]},{"title":"N が できます / V ことができます","formula":"N が できます ／ V 辞書形 + ことが できます\nCấu trúc | Ví dụ | Nghĩa\nN + が + できます | にほんごができます | Biết tiếng Nhật\nりょうり + が + できます | りょうりができます | Biết nấu ăn\nV辞書形 + ことが + できます | およぐことができます | Có thể bơi\nV辞書形 + ことが + できます | ピアノをひくことができます | Có thể chơi piano","explain":"Diễn tả KHẢ NĂNG: 'có thể, biết làm'. Với danh từ: N が できます. Với động từ: V る + ことができます.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ にほんごをできます → ✅ にほんごができます — khả năng dùng が, không dùng を.","compare":"","examples":[{"jp":"わたしは にほんごが できます。","vn":"Tôi biết tiếng Nhật."},{"jp":"ここで りょうりを つくることが できます。","vn":"Ở đây có thể nấu ăn."},{"jp":"にほんごができます","vn":"Biết tiếng Nhật"},{"jp":"りょうりができます","vn":"Biết nấu ăn"},{"jp":"およぐことができます","vn":"Có thể bơi"}]},{"title":"どうして〜から（理由の問答）","formula":"どうして〜ですか ／ なぜ〜ですか ⇒ 〜から","explain":"どうして / なぜ = 'Tại sao'. Câu hỏi lý do → trả lời bằng ～から.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ どうしてですから → ✅ どうしてですか — câu HỎI dùng ですか, không dùng ですから.","compare":"","examples":[{"jp":"どうして にほんへ きたんですか。　― にほんごが すきですから。","vn":"Sao bạn đến Nhật?"},{"jp":"どうして きのう がっこうを やすみましたか。　― かぜを ひいていましたから。","vn":"Sao hôm qua nghỉ học?"},{"jp":"あめが ふっていますから、うちに います。","vn":"Vì trời đang mưa nên tôi ở nhà."}]},{"title":"V まえに（前後関係）","formula":"V 辞書形 + まえに、〜 ／ N の + まえに、〜\nCấu trúc | Ví dụ | Nghĩa\nV 辞書形 + まえに | ねる まえに | trước khi ngủ\nN の まえに | しょくじの まえに | trước bữa ăn","explain":"'Trước khi V' — hành động trong dấu ngoặc xảy ra TRƯỚC hành động chính.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ きたまえに → ✅ くるまえに — まえに luôn dùng 辞書形 (không chia thì).","compare":"","examples":[{"jp":"ねる まえに、はを みがきます。","vn":"Trước khi ngủ, tôi đánh răng."},{"jp":"にほんへ くる まえに、にほんごを べんきょうしました。","vn":"Trước khi đến Nhật, tôi đã học tiếng Nhật."},{"jp":"わたしは にほんごが できます。","vn":"Tôi biết tiếng Nhật."}]},{"title":"V たことがあります（経験）","formula":"V た形 + ことが あります ／ ありません","explain":"'Đã từng V'. Diễn tả KINH NGHIỆM trong quá khứ (ít nhất một lần). Không xác định thời gian cụ thể.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ にほんへいくことがあります → ✅ にほんへいったことがあります — kinh nghiệm dùng た形+ことがあります.","compare":"","examples":[{"jp":"にほんへ いったことが あります。","vn":"Tôi đã từng đến Nhật."},{"jp":"なっとうを たべたことが ありますか。　― いいえ、ありません。","vn":"Bạn đã từng ăn natto chưa?"},{"jp":"ねる まえに、はを みがきます。","vn":"Trước khi ngủ, tôi đánh răng."}]}],"15":[{"title":"V たり V たりします","formula":"V₁た形 + り、V₂た形 + り します\nVた形 + り | → Vたり | Nghĩa\nたべた + り | → たべたり | khi thì ăn\nみた + り | → みたり | khi thì xem\nした + り | → したり | khi thì làm","explain":"Liệt kê hành động tiêu biểu — KHÔNG LIỆT KÊ HẾT. Ý: 'khi thì làm A, khi thì làm B (và những thứ khác)'.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ えいがをみたりおんがくをきいた → ✅ ～たり～たりします — PHẢI kết thúc bằng します/しました.","compare":"","examples":[{"jp":"やすみの ひは おんがくを きいたり、えいがを みたりします。","vn":"Ngày nghỉ khi thì nghe nhạc, khi thì xem phim."},{"jp":"にちようびは そうじを したり、せんたくを したりします。","vn":"Chủ nhật tôi dọn nhà, giặt đồ."},{"jp":"おとなに なりました。","vn":"Đã trở thành người lớn."}]},{"title":"N になります","formula":"N に なります ／ いAdj → くなります ／ なAdj → になります\nGốc | → + なります | Nghĩa\nおとな (N) | → おとなになりました | trở thành người lớn\nくらい (いAdj) | → くらくなりました | trở nên tối\nじょうず (なAdj) | → じょうずになりたいです | muốn trở nên giỏi","explain":"なります = thay đổi trạng thái: 'trở thành, trở nên'. Khác です (trạng thái hiện tại).\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ くらいになりました → ✅ くらくなりました — いAdj: bỏ い → く + なります.","compare":"","examples":[{"jp":"おとなに なりました。","vn":"Đã trở thành người lớn."},{"jp":"そとが くらく なりました。","vn":"Bên ngoài đã tối."},{"jp":"→ + なります","vn":"Nghĩa"},{"jp":"→ おとなになりました","vn":"trở thành người lớn"},{"jp":"→ くらくなりました","vn":"trở nên tối"}]},{"title":"V ようになります（変化の過程）","formula":"V 辞書形 / V ない形 + ようになります","explain":"'Dần dần trở nên có thể V' — diễn tả quá trình thay đổi theo thời gian, thường là kỹ năng hoặc thói quen.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ はなすになりました → ✅ はなせるようになりました — ようになります dùng 辞書形 (khả năng) + ように.","compare":"N に なります  vs  V ようになります\nN に なります | V ようになります\nĐối tượng | Danh từ / Tính từ (trạng thái) | Động từ (khả năng / thói quen)\nNghĩa | Trở thành N | Dần trở nên có thể V\nVí dụ | せんせいになりました | にほんごがはなせるようになりました","examples":[{"jp":"べんきょうして、にほんごが はなせる ようになりました。","vn":"Nhờ học, dần tôi nói được tiếng Nhật."},{"jp":"まいにち れんしゅうして、ピアノが ひける ようになりました。","vn":"Tập mỗi ngày, giờ tôi chơi được đàn piano rồi."},{"jp":"やすみの ひは おんがくを きいたり、えいがを みたりします。","vn":"Ngày nghỉ khi thì nghe nhạc, khi thì xem phim."}]},{"title":"～し、～し","formula":"～し、～し、[kết luận]","explain":"Liệt kê lý do / đặc điểm: 'vừa A, lại vừa B (nên C)'. Mang sắc thái giải thích / liệt kê lý do.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"","compare":"","examples":[{"jp":"このみせは やすいし、おいしいし、いいですよ。","vn":"Quán này vừa rẻ lại ngon, tốt lắm."},{"jp":"からだも いたいし、ねつも あるし、びょういんへ いきます。","vn":"Người đau, lại sốt, tôi đi bệnh viện."},{"jp":"べんきょうして、にほんごが はなせる ようになりました。","vn":"Nhờ học, dần tôi nói được tiếng Nhật."}]},{"title":"イA/ナA + なる: Trở nên...","formula":"Tính từ -i (bỏ い) + く + なります / Tính từ -na (bỏ な) + に + なります","explain":"Diễn tả sự THAY ĐỔI trạng thái theo thời gian - khác N になります (đã học ở điểm 2 cùng bài) vốn dùng cho danh từ.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"Dùng khi: Dùng khi so sánh trạng thái hiện tại với trước đây và có sự thay đổi rõ rệt.\n❌ おおきいなりました → ✅ おおきくなりました — Tính từ -i phải bỏ い + く trước なる, không giữ nguyên い","compare":"","examples":[{"jp":"あの子は おおきく なりました。","vn":"Đứa bé đó đã lớn hơn rồi."},{"jp":"かのじょは きれいに なりました。","vn":"Cô ấy đã trở nên xinh đẹp hơn."},{"jp":"になります","vn":"đã học ở điểm 2 cùng bài"}]}],"16":[{"title":"V てみます (thử làm)","formula":"V て形 + みます","explain":"Thử nghiệm hành động để trải nghiệm/xem kết quả. みます figurative = 'xem (sao)'.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"Dùng khi: Khi lần đầu thử một trải nghiệm, hoặc muốn ai đó thử something mới.\n❌ まいにちたべてみます (thói quen) → ✅ てみます chỉ dùng cho việc thử lần đầu / chưa biết kết quả.","compare":"","examples":[{"jp":"このおかしを たべてみてください。おいしいですよ。","vn":"Hãy thử ăn bánh này xem. Ngon lắm."},{"jp":"にほんごで はなしてみました。","vn":"Tôi đã thử nói bằng tiếng Nhật."},{"jp":"まいにちたべてみます","vn":"thói quen"}]},{"title":"V ておきます (chuẩn bị trước)","formula":"V て形 + おきます","explain":"Làm hành động trước để CHUẨN BỊ cho sự kiện sắp tới. 'Làm A trước (để sẵn sàng cho B)'.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"Dùng khi: Khi muốn nhấn mạnh: hành động này là SỰ CHUẨN BỊ cho việc khác sẽ xảy ra.","compare":"V てみます (thử)  vs  V ておきます (chuẩn bị)\nV てみます (thử) | V ておきます (chuẩn bị)\nMục đích | Trải nghiệm / xem kết quả | Chuẩn bị cho sự kiện\nSắc thái | Chưa biết sẽ ra sao | Chủ動 chuẩn bị trước\nVí dụ | すしをたべてみます (thử ăn) | すしをかっておきます (mua sẵn)","examples":[{"jp":"パーティーの まえに りょうりを つくっておきます。","vn":"Trước bữa tiệc tôi nấu sẵn đồ ăn."},{"jp":"ホテルを よやくしておきました。","vn":"Tôi đã đặt khách sạn trước rồi."},{"jp":"ておきます","vn":"chuẩn bị"},{"jp":"すしをたべてみます","vn":"thử ăn"},{"jp":"すしをかっておきます","vn":"mua sẵn"}]},{"title":"V てしまいます（完了・後悔）","formula":"V て形 + しまいます\nCấu trúc | Ví dụ | Nghĩa\nV て + しまいます | たべてしまいます | ăn hết / lỡ ăn mất\nV て + しまいました | わすれてしまいました | đã lỡ quên mất rồi\nThân mật: ～ちゃう | たべちゃう | ăn hết mất / lỡ ăn","explain":"てしまいます có 2 nghĩa chính: (1) HOÀN THÀNH TRIỆT ĐỂ hành động, (2) bày tỏ TIẾC NUỐI / không mong muốn.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ たべてしまってください → ✅ たべてしまってください (có thể dùng, nghĩa: 'ăn hết đi') — nhưng てしまう thường diễn tả việc không mong muốn, nên kết hợp với ください ít tự nhiên.","compare":"","examples":[{"jp":"しゅくだいを わすれてしまいました。","vn":"Tôi đã lỡ quên mất bài tập rồi."},{"jp":"ケーキを ぜんぶ たべてしまいました。","vn":"Đã ăn hết cả bánh mất rồi."},{"jp":"たべてしまいます","vn":"ăn hết / lỡ ăn mất"},{"jp":"わすれてしまいました","vn":"đã lỡ quên mất rồi"}]},{"title":"N は N が A です（属性・能力）","formula":"N₁ は N₂ が [Adj / できます]","explain":"Diễn tả ĐẶC ĐIỂM / KHẢ NĂNG của một đối tượng: 'Về N₁, thì N₂ là/có thể…'.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ やまださんはにほんごをじょうずです → ✅ やまださんはにほんごがじょうずです — năng lực dùng が, không dùng を.","compare":"","examples":[{"jp":"このまちは こうえんが おおいです。","vn":"Thành phố này có nhiều công viên."},{"jp":"やまださんは にほんごが じょうずです。","vn":"Anh Yamada giỏi tiếng Nhật."},{"jp":"このおかしを たべてみてください。おいしいですよ。","vn":"Hãy thử ăn bánh này xem. Ngon lắm."}]},{"title":"どうやって（方法を尋ねる）","formula":"どうやって V ますか ⇒ ～て、～て V ます","explain":"どうやって = 'Bằng cách nào? Làm thế nào?'. Hỏi về PHƯƠNG PHÁP / CÁCH THỨC thực hiện.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ どうやってですから → ✅ どうやってですか — câu hỏi dùng ですか.","compare":"どうして（理由）  vs  どうやって（方法）\nどうして（理由） | どうやって（方法）\nHỏi về | Lý do / nguyên nhân | Cách thức / phương pháp\nTrả lời bằng | ～から (vì) | ～て、～て / ～で (bằng)\nVí dụ | どうしてにほんへきましたか | どうやってがっこうへいきますか","examples":[{"jp":"がっこうへ どうやって いきますか。　― でんしゃで いきます。","vn":"Đến trường bằng cách nào?"},{"jp":"この かんじは どうやって かきますか。　― こうやって かきます。","vn":"Chữ kanji này viết thế nào?"},{"jp":"パーティーの まえに りょうりを つくっておきます。","vn":"Trước bữa tiệc tôi nấu sẵn đồ ăn."}]}],"17":[{"title":"V なければなりません","formula":"V ない形 → bỏ ない → + なければなりません\nV ない形 | → V なければなりません | Nghĩa\nたべない | → たべなければなりません | phải ăn\nいかない | → いかなければなりません | phải đi\nのまない | → のまなければなりません | phải uống\nしない | → しなければなりません | phải làm\nこない | → こなければなりません | phải đến","explain":"Nghĩa vụ bắt buộc: 'phải làm V'. Cách tạo: lấy ない形, bỏ ない, thêm なければなりません.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"","compare":"","examples":[{"jp":"まいにち くすりを のまなければなりません。","vn":"Phải uống thuốc mỗi ngày."},{"jp":"あした ８じまでに がっこうに いかなければなりません。","vn":"Ngày mai phải đến trường trước 8 giờ."},{"jp":"→ V なければなりません","vn":"Nghĩa"},{"jp":"→ たべなければなりません","vn":"phải ăn"},{"jp":"→ いかなければなりません","vn":"phải đi"}]},{"title":"V なくてもいいです","formula":"V ない形 → V なくて + もいいです","explain":"Miễn trừ nghĩa vụ: 'không cần phải V, được phép không V'.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"","compare":"なければなりません (phải)  vs  なくてもいいです (không cần)\nなければなりません (phải) | なくてもいいです (không cần)\nNghĩa | BẮT BUỘC phải làm | KHÔNG CẦN phải làm\nVí dụ | いかなければなりません | いかなくてもいいです\nDịch | Phải đi | Không cần đi","examples":[{"jp":"あしたは こなくても いいですよ。","vn":"Ngày mai không cần đến đâu."},{"jp":"スーツを きなくても いいですか。　― はい、カジュアルで いいですよ。","vn":"Không cần mặc vest được không?"},{"jp":"なければなりません","vn":"phải"},{"jp":"なくてもいいです","vn":"không cần"}]},{"title":"V ないでください","formula":"V ない形 + でください","explain":"Yêu cầu ĐỪNG làm. Nhẹ nhàng hơn てはいけません (cấm đoán, bài 13).\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"","compare":"","examples":[{"jp":"ここで タバコを すわないでください。","vn":"Đừng hút thuốc ở đây."},{"jp":"しんぱいしないでください。だいじょうぶですよ。","vn":"Đừng lo lắng. Không sao đâu."},{"jp":"てはいけません","vn":"cấm đoán, bài 13"}]},{"title":"N は（対比の は）","formula":"N₁ は [Adj/V]. N₂ は [Adj/V].","explain":"は dùng để SO SÁNH đối lập: nêu N₁ với thuộc tính A, rồi nêu N₂ với thuộc tính B (khác A).\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ すしがすきです。さしみがあまりすきじゃない → ✅ すしはすきです。さしみはあまり… — đối lập 2 chủ đề dùng は, không dùng が.","compare":"","examples":[{"jp":"すしは すきです。でも さしみは あまり すきじゃないです。","vn":"Sushi thì tôi thích. Nhưng sashimi thì không mấy thích."},{"jp":"コーヒーは のみます。おさけは のみません。","vn":"Cà phê thì uống. Rượu thì không uống."},{"jp":"まいにち くすりを のまなければなりません。","vn":"Phải uống thuốc mỗi ngày."}]},{"title":"N までに（期限）","formula":"時間 / 日時 + までに + V","explain":"までに = 'trước (thời điểm)' — hành động phải hoàn thành TRƯỚC thời điểm được nêu.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ ８じまでかえります → ✅ ８じまでにかえります — 'trước 8 giờ' dùng までに, không phải まで.","compare":"まで（継続）  vs  までに（期限）\nまで（継続） | までに（期限）\nNghĩa | Cho đến (kéo dài đến) | Trước (deadline)\nHành động | Tiếp tục, không ngắt | Phải hoàn thành trước đó\nVí dụ | ７じまでがっこうにいます | ７じまでにうちにかえります\nDịch | Ở trường đến 7 giờ | Về nhà trước 7 giờ","examples":[{"jp":"あしたの ８じまでに レポートを だしてください。","vn":"Hãy nộp báo cáo trước 8 giờ ngày mai."},{"jp":"きんようびまでに しゅくだいを しなければなりません。","vn":"Phải làm bài tập trước thứ Sáu."},{"jp":"あしたは こなくても いいですよ。","vn":"Ngày mai không cần đến đâu."}]}],"18":[{"title":"～と思います","formula":"[普通形] と 思います\nDạng | 普通形 | + とおもいます\nV ます形 → 普通形 | ふります → ふる | ふるとおもいます\nV ません → ない形 | ふりません → ふらない | ふらないとおもいます\nV ました → た形 | ふりました → ふった | ふったとおもいます\nいAdj | おもしろい | おもしろいとおもいます\nなAdj + だ | べんり + だ | べんりだとおもいます","explain":"Diễn tả ý kiến/nhận定 cá nhân. Mệnh đề trước と chia ở 普通形 (thể thường, KHÔNG dùng ます形).\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ ふりますとおもいます → ✅ ふるとおもいます — trước と phải dùng 普通形.","compare":"","examples":[{"jp":"あしたは あめが ふると おもいます。","vn":"Tôi nghĩ ngày mai trời sẽ mưa."},{"jp":"この えいがは おもしろいと おもいます。","vn":"Tôi nghĩ phim này hay."},{"jp":"やまださんは あした くると いっています。","vn":"Anh Yamada nói ngày mai sẽ đến."}]},{"title":"～と言っています／言いました","formula":"[普通形] と 言っています／言いました","explain":"Truyền đạt lời nói của người khác. と đánh dấu nội dung lời nói.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ やまださんはきますといっています → ✅ やまださんはくるといっています — と の trước PHẢI là 普通形 (くる).","compare":"","examples":[{"jp":"やまださんは あした くると いっています。","vn":"Anh Yamada nói ngày mai sẽ đến."},{"jp":"せんせいは しゅくだいを わすれないで と いいました。","vn":"Thầy giáo nói đừng quên bài tập."},{"jp":"あしたは あめが ふると おもいます。","vn":"Tôi nghĩ ngày mai trời sẽ mưa."}]},{"title":"～でしょう（推量・確認）","formula":"[普通形] + でしょう ／ [Adj/N] + でしょう\nCấu trúc | Ví dụ | Nghĩa\nV 辞書形 + でしょう | あめがふるでしょう | chắc trời sẽ mưa\nV ない + でしょう | こないでしょう | chắc sẽ không đến\nAdj + でしょう | さむいでしょう | chắc trời lạnh\nN + でしょう | やすみでしょう | chắc là ngày nghỉ","explain":"でしょう = 'chắc là, có lẽ' — diễn tả suy đoán mà người nói CHƯA CHẮC CHẮN 100%.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ さむいですでしょう → ✅ さむいでしょう — いAdj trước でしょう không cần です.","compare":"","examples":[{"jp":"あしたは さむいでしょう。","vn":"Ngày mai chắc trời lạnh."},{"jp":"やまださんは もう かえったでしょう。","vn":"Anh Yamada chắc đã về rồi."},{"jp":"あめがふるでしょう","vn":"chắc trời sẽ mưa"},{"jp":"こないでしょう","vn":"chắc sẽ không đến"},{"jp":"さむいでしょう","vn":"chắc trời lạnh"}]},{"title":"～んです（説明・強調）","formula":"[普通形] + んです ／ んですか\nLoại từ | Ví dụ | Sắc thái\nV 普通形 + んです | いくんです | thực ra tôi đang đi...\nいAdj + んです | いたいんです | thực ra đau lắm...\nなAdj + な + んです | たいへんなんです | thực ra khó lắm...\nN + な + んです | がくせいなんです | thực ra là sinh viên...","explain":"んです (= のです) thêm sau câu để: (1) GIẢI THÍCH lý do / tình huống, (2) hỏi giải thích, (3) nhấn mạnh.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ いきますんです → ✅ いくんです — んです đứng sau 普通形, không phải ます形.","compare":"","examples":[{"jp":"どうしたんですか。　― あたまが いたいんです。","vn":"Có chuyện gì vậy?"},{"jp":"どうして おくれたんですか。　― でんしゃが おくれたんです。","vn":"Sao đến muộn vậy?"},{"jp":"いくんです","vn":"thực ra tôi đang đi..."},{"jp":"いたいんです","vn":"thực ra đau lắm..."},{"jp":"たいへんなんです","vn":"thực ra khó lắm..."}]}],"19":[{"title":"V ことができます","formula":"V 辞書形 + ことができます","explain":"Khả năng: 'có thể V'. こと biến động từ thành danh từ.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"","compare":"","examples":[{"jp":"ピアノを ひくことが できます。","vn":"Tôi có thể chơi piano."},{"jp":"にほんごで てがみを かくことが できますか。","vn":"Bạn có thể viết thư bằng tiếng Nhật không?"},{"jp":"うたうのが すきです。","vn":"Tôi thích hát."}]},{"title":"V のが 好き/上手/下手/苦手","formula":"V 辞書形 + の + が + [Adj/N]","explain":"の biến động từ thành danh từ (nominalizer), dùng với すき/きらい/じょうず/へた/にがて/むずかしい...\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ うたうがすきです → ✅ うたうのがすきです — cần の danh từ hóa.","compare":"","examples":[{"jp":"うたうのが すきです。","vn":"Tôi thích hát."},{"jp":"りょうりを つくるのが とくいです。","vn":"Tôi giỏi nấu ăn."},{"jp":"ピアノを ひくことが できます。","vn":"Tôi có thể chơi piano."}]},{"title":"V まえに","formula":"V 辞書形 + まえに","explain":"'Trước khi V'. Luôn dùng thể từ điển trước まえに, BẤT KỂ thì của câu chính.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ たべたまえに → ✅ たべるまえに — trước まえに LUÔN dùng thể từ điển.","compare":"","examples":[{"jp":"ねる まえに、はを みがきます。","vn":"Trước khi ngủ, đánh răng."},{"jp":"にほんへ いく まえに、にほんごを べんきょうしました。","vn":"Trước khi đi Nhật, đã học tiếng Nhật."},{"jp":"わたしの しゅみは えを かくことです。","vn":"Sở thích của tôi là vẽ tranh."}]},{"title":"わたしのしゅみは V ことです（名詞化）","formula":"N は V 辞書形 + こと です","explain":"こと biến động từ thành danh từ (nominalizer) — dùng khi muốn nói về HÀNH ĐỘNG như một khái niệm.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ しゅみはうたうのです → ✅ しゅみはうたうことです — giới thiệu sở thích/mục tiêu dùng こと, không dùng の.","compare":"V の (cụ thể)  vs  V こと (khái quát)\nV の (cụ thể) | V こと (khái quát)\nNghĩa | Hành động cụ thể, trực tiếp | Hành động trừu tượng, khái quát\nDùng với | すき/きらい/じょうず (cảm giác) | しゅみ/もくひょう (khái niệm)\nVí dụ | うたうのがすきです | しゅみはうたうことです","examples":[{"jp":"わたしの しゅみは えを かくことです。","vn":"Sở thích của tôi là vẽ tranh."},{"jp":"わたしの もくひょうは にほんごが じょうずに なることです。","vn":"Mục tiêu của tôi là trở nên giỏi tiếng Nhật."},{"jp":"ねる まえに、はを みがきます。","vn":"Trước khi ngủ, đánh răng."}]},{"title":"なかなか ～ない（思うようにいかない）","formula":"なかなか + V ない / Adj くない","explain":"なかなか + 否定 = 'mãi mà không, cứ không, không dễ gì'. Diễn tả tình trạng mong muốn nhưng không đạt được.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ なかなかできます (muốn nói 'mãi không được') → ✅ なかなかできません — なかなか PHẢI đi với phủ定.","compare":"","examples":[{"jp":"にほんごは なかなか おぼえられません。","vn":"Tiếng Nhật mãi mà không thể nhớ được."},{"jp":"ダイエットしていますが、なかなか やせません。","vn":"Tôi đang ăn kiêng nhưng mãi không sút được."},{"jp":"なかなかできます","vn":"muốn nói 'mãi không được'"}]}],"20":[{"title":"V たことがあります","formula":"V た形 + ことがあります ／ ことがありません","explain":"Diễn tả kinh nghiệm trong TOÀN BỘ cuộc đời: 'đã từng V (bao giờ)'. こと biến câu thành danh từ.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ いくことがあります → ✅ いったことがあります — kinh nghiệm PHẢI dùng た形.","compare":"V たことがあります (kinh nghiệm)  vs  V ました (quá khứ cụ thể)\nV たことがあります (kinh nghiệm) | V ました (quá khứ cụ thể)\nNghĩa | Đã từng (trong đời) | Đã làm (lúc cụ thể)\nThời gian | Bất kỳ, không cần nói cụ thể | Thời điểm cụ thể (hôm qua, năm ngoái)\nVí dụ | にほんへいったことがあります | きょねんにほんへいきました\nHỏi | Bạn đã từng…chưa? | Bạn đã… (lúc đó) chưa?","examples":[{"jp":"にほんへ いったことが あります。にどいきました。","vn":"Tôi đã từng đến Nhật. Đi 2 lần rồi."},{"jp":"ふじさんに のぼったことが ありますか。　― いいえ、ありません。","vn":"Bạn đã từng leo núi Fuji chưa?"},{"jp":"たことがあります","vn":"kinh nghiệm"},{"jp":"ふじさんに いちど のぼったことが あります。","vn":"Tôi đã từng leo núi Fuji một lần."}]},{"title":"はじめて V ました（初めての経験）","formula":"はじめて + V ました","explain":"はじめて = 'lần đầu tiên'. Đặt trước động từ để nhấn mạnh đây là lần đầu tiên trải nghiệm.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ はじめてにほんへいったことがあります → ✅ はじめてにほんへいきました — はじめて thường dùng với ました (sự kiện cụ thể), không kết hợp たことがあります.","compare":"","examples":[{"jp":"はじめて すしを たべました。おいしかったです。","vn":"Lần đầu tiên ăn sushi. Ngon lắm."},{"jp":"にほんへ はじめて きたのは ３ねんまえです。","vn":"Lần đầu tiên đến Nhật là 3 năm trước."},{"jp":"にほんへ いったことが あります。にどいきました。","vn":"Tôi đã từng đến Nhật. Đi 2 lần rồi."},{"jp":"もう しゅくだいを しましたか。　― はい、もう しました。","vn":"Bài tập đã làm rồi chưa?"}]},{"title":"もう V ましたか ／ まだ V ていません（完了の確認）","formula":"もう [V ました]か ⇒ はい、もう ～ました ／ いいえ、まだ V ていません","explain":"もう + V ました = 'đã V rồi'. Hỏi: もう V ましたか = 'Đã V rồi chưa?'.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ まだいきませんでした → ✅ まだいっていません — 'vẫn chưa' dùng まだ + ていません (không dùng ませんでした).","compare":"もう ～ました（완료）  vs  まだ ～ていません（미완료）\nもう ～ました（완료） | まだ ～ていません（미완료）\nNghĩa | Đã làm rồi | Vẫn chưa làm\nDùng khi | Hoàn thành | Chưa hoàn thành\nVí dụ | もうたべました | まだたべていません\nDịch | Ăn rồi | Chưa ăn","examples":[{"jp":"もう しゅくだいを しましたか。　― はい、もう しました。","vn":"Bài tập đã làm rồi chưa?"},{"jp":"いいえ、まだ していません。これから します。","vn":"Chưa, chưa làm. Sắp làm."},{"jp":"はじめて すしを たべました。おいしかったです。","vn":"Lần đầu tiên ăn sushi. Ngon lắm."}]},{"title":"V たことがあります + 回数（経験回数）","formula":"いちど／にど／なんども + V たことがあります","explain":"Thêm số lần vào kinh nghiệm: いちど (1 lần), にど (2 lần), さんど (3 lần), なんども (nhiều lần).\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ いちどいきましたことがあります → ✅ いちどいったことがあります — số lần + た形 + ことがあります.","compare":"","examples":[{"jp":"ふじさんに いちど のぼったことが あります。","vn":"Tôi đã từng leo núi Fuji một lần."},{"jp":"ディズニーランドへ なんども いったことが あります。","vn":"Tôi đã đến Disneyland nhiều lần rồi."},{"jp":"にほんへ いったことが あります。にどいきました。","vn":"Tôi đã từng đến Nhật. Đi 2 lần rồi."}]}],"21":[{"title":"[普通形] + N (mệnh đề quan hệ)","formula":"[Mệnh đề bổ nghĩa 普通形] + N\nMệnh đề + N | → Kết quả | Nghĩa\nあそこにいる + ひと | → あそこにいるひと | người đang ở kia\nきのうたべた + りょうり | → きのうたべたりょうり | món ăn hôm qua\nにほんごをおしえている + せんせい | → にほんごをおしえているせんせい | thầy đang dạy tiếng Nhật\nわたしがすんでいる + まち | → わたしがすんでいるまち | thành phố tôi đang sống","explain":"Tiếng Nhật: mệnh đề bổ nghĩa đứng TRƯỚC danh từ — ngược tiếng Anh (which/who AFTER noun).\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ ひとはあそこにいるやまださんです → ✅ あそこにいるひとはやまださんです — mệnh đề bổ nghĩa đứng TRƯỚC N.","compare":"","examples":[{"jp":"あそこに いる ひとは やまださんです。","vn":"Người đang ở kia là anh Yamada."},{"jp":"きのう たべた りょうりは おいしかったです。","vn":"Món tôi ăn hôm qua rất ngon."},{"jp":"まだ たべていない りょうりが たくさん あります。","vn":"Còn nhiều món chưa ăn."}]},{"title":"[普通形] + N（否定・過去形での修飾）","formula":"V ない + N ／ V た + N\nDạng | Ví dụ | Nghĩa\nV ない + N | まだたべないりょうり | món chưa ăn\nV た + N | もらったプレゼント | món quà được tặng\nV ている + N | にほんごをはなしているひと | người đang nói tiếng Nhật\nいAdj + N | たかいレストラン | nhà hàng đắt\nなAdj な + N | しずかなところ | nơi yên tĩnh","explain":"Mệnh đề quan hệ chia theo từng thì/dạng. Phủ định: V ない + N. Quá khứ: V た + N. Tiến hành: V ている + N.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ たべますりょうり → ✅ たべるりょうり — trong mệnh đề bổ nghĩa, phải dùng 普通形 (たべる), không dùng ます形.","compare":"","examples":[{"jp":"まだ たべていない りょうりが たくさん あります。","vn":"Còn nhiều món chưa ăn."},{"jp":"きのう かれに もらった プレゼントは とても きれいです。","vn":"Món quà anh ấy tặng hôm qua rất đẹp."},{"jp":"あそこに いる ひとは やまださんです。","vn":"Người đang ở kia là anh Yamada."}]},{"title":"従属節内のが→の（主語の格変換）","formula":"Mệnh đề bổ nghĩa: [N₁ の/が + V] + N₂","explain":"Trong mệnh đề bổ nghĩa, chủ ngữ có thể dùng が HOẶC の (thay thế nhau).\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"","compare":"","examples":[{"jp":"わたしが かいた てがみ ＝ わたしの かいた てがみ","vn":"Bức thư tôi đã viết (2 cách đều đúng)."},{"jp":"やまださんが おしえている クラス ＝ やまださんの おしえている クラス","vn":"Lớp anh Yamada đang dạy."},{"jp":"らいねん にほんへ いく よていです。","vn":"Năm tới có kế hoạch đi Nhật."}]},{"title":"辞書形 + 予定です／つもりです（計画・意志）","formula":"V 辞書形 + 予定です (kế hoạch) ／ V 辞書形 + つもりです (ý định)","explain":"予定です = kế hoạch đã sắp xếp (có thể kiểm chứng, mang tính lịch). つもりです = ý định cá nhân (quyết tâm của bản thân).\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ いきますつもりです → ✅ いくつもりです — つもりです đứng sau 辞書形 (不変化形).","compare":"V 予定です（計画）  vs  V つもりです（意志）\nV 予定です（計画） | V つもりです（意志）\nNghĩa | Có kế hoạch/lịch V | Có ý định V (cá nhân)\nTính chất | Khách quan, đã lên lịch | Chủ quan, quyết tâm\nVí dụ | らいねんにほんへいくよていです | にほんごをもっとべんきょうするつもりです","examples":[{"jp":"らいねん にほんへ いく よていです。","vn":"Năm tới có kế hoạch đi Nhật."},{"jp":"にほんごを もっと べんきょうする つもりです。","vn":"Tôi định học tiếng Nhật nhiều hơn."},{"jp":"わたしが かいた てがみ ＝ わたしの かいた てがみ","vn":"Bức thư tôi đã viết (2 cách đều đúng)."}]}],"22":[{"title":"～とき (khi, lúc)","formula":"V辞書形/Vた形 + とき ／ いAdj + とき ／ なAdj な + とき ／ N の + とき","explain":"とき = 'khi, lúc'. Điểm QUAN TRỌNG NHẤT: thì của動詞 trước とき quyết định nghĩa:\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ いくときにすしをたべました → ✅ いったときにすしをたべました — đã đến mới ăn → dùng た形.","compare":"V る + とき (chưa xong)  vs  V た + とき (đã xong)\nV る + とき (chưa xong) | V た + とき (đã xong)\nTrạng thái V | CHƯA hoàn thành | ĐÃ hoàn thành\nVí dụ | にほんへいくとき、かさをかいます | にほんへいったとき、すしをたべました\nNghĩa | Khi sắp đi (chưa đi = mua trước) | Khi đã đến (đi xong = ăn ở Nhật)\nMẹo nhớ | V chưa xảy ra → 辞書形 | V đã xảy ra → た形","examples":[{"jp":"にほんへ いくとき、おみやげを かいます。","vn":"Khi (sắp) đi Nhật, tôi mua quà."},{"jp":"にほんへ いったとき、すしを たべました。","vn":"Khi (đã) đến Nhật, tôi ăn sushi."},{"jp":"ごはんを たべたあとで、さんぽします。","vn":"Sau khi ăn cơm, tôi đi dạo."}]},{"title":"V たあとで (sau khi V xong)","formula":"V た形 + あとで","explain":"Sau khi V₁ xong thì V₂. Luôn dùng た形 trước あとで.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ たべるあとで → ✅ たべたあとで — trước あとで LUÔN dùng た形.","compare":"","examples":[{"jp":"ごはんを たべたあとで、さんぽします。","vn":"Sau khi ăn cơm, tôi đi dạo."},{"jp":"しごとが おわったあとで、ともだちと のみにいきます。","vn":"Sau khi tan làm đi uống với bạn."},{"jp":"にほんへ いくとき、おみやげを かいます。","vn":"Khi (sắp) đi Nhật, tôi mua quà."}]},{"title":"V 辞書形 + と（自然条件・必然）","formula":"V 辞書形 + と、[kết quả tự nhiên]","explain":"と sau động từ/tính từ = 'nếu / khi A thì B TỰ NHIÊN xảy ra'. Hàm ý: B là kết quả TẤT YẾU, không thể tránh.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ このみちをいくと、いってください → ✅ このみちをいくと、えきがあります — Sau と không dùng mệnh lệnh.","compare":"～と（自然・必然）  vs  ～たら（仮定・条件）\n～と（自然・必然） | ～たら（仮定・条件）\nNghĩa | Nếu A thì B tự nhiên | Nếu/Khi A thì B (linh hoạt)\nKết quả B | Tất yếu / tự nhiên | Có thể là ý kiến/yêu cầu\nVí dụ | このボタンをおすとでます | あめがふったらうちにいます","examples":[{"jp":"このボタンを おすと、ドアが あきます。","vn":"Bấm nút này thì cửa mở."},{"jp":"まっすぐ いくと、えきが あります。","vn":"Đi thẳng thì có nhà ga."},{"jp":"おんがくを きき ながら、べんきょうします。","vn":"Vừa nghe nhạc vừa học."}]},{"title":"V ながら（同時進行）","formula":"V₁ ます形（除ます） + ながら、V₂","explain":"'Vừa V₁ vừa V₂' — hai hành động diễn ra ĐỒNG THỜI. V₁ là hành động phụ; V₂ là hành động chính.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ たべながら、あるきます (2 người) → ✅ ながら chỉ dùng khi CÙNG 1 người làm 2 việc.","compare":"","examples":[{"jp":"おんがくを きき ながら、べんきょうします。","vn":"Vừa nghe nhạc vừa học."},{"jp":"コーヒーを のみながら、しんぶんを よみます。","vn":"Vừa uống cà phê vừa đọc báo."},{"jp":"たべながら、あるきます","vn":"2 người"}]}],"23":[{"title":"V てあげます","formula":"[Người làm] が [Người nhận] に V てあげます","explain":"Tôi / nhóm tôi làm hành động VÌ LỢI ÍCH của người khác. Quan điểm: từ phía NGƯỜI LÀM.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ せんせいにおしえてあげました → ✅ せんせいにおしえていただきました — với người trên dùng いただきました (rất lịch sự).","compare":"","examples":[{"jp":"ともだちに えいごを おしえてあげました。","vn":"Tôi đã dạy tiếng Anh cho bạn."},{"jp":"おばあさんに にもつを もってあげました。","vn":"Tôi đã xách đồ cho bà cụ."},{"jp":"やまださんに にほんごを おしえてもらいました。","vn":"Tôi được anh Yamada dạy tiếng Nhật."}]},{"title":"V てもらいます","formula":"[Người nhận] が [Người làm] に V てもらいます","explain":"Tôi là người NHẬN lợi ích. 'Tôi được/nhờ [người] V cho tôi'. Quan điểm: từ phía NGƯỜI NHẬN.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"","compare":"","examples":[{"jp":"やまださんに にほんごを おしえてもらいました。","vn":"Tôi được anh Yamada dạy tiếng Nhật."},{"jp":"ともだちに たすけてもらいました。","vn":"Tôi được bạn bè giúp đỡ."},{"jp":"ともだちに えいごを おしえてあげました。","vn":"Tôi đã dạy tiếng Anh cho bạn."}]},{"title":"V てくれます","formula":"[Người làm] が [Tôi/nhóm tôi] に V てくれます","explain":"Người khác TỰ NGUYỆN làm cho tôi/nhóm tôi. Nhấn mạnh tình cảm BIẾT ƠN của người nhận.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ わたしがてつだってくれました → ✅ ともだちがてつだってくれました — chủ語 của てくれます là NGƯỜI LÀM, không phải tôi.","compare":"てあげます (tôi→khác)  vs  てもらいます (tôi←khác)\nてあげます (tôi→khác) | てもらいます (tôi←khác)\nAi làm | TÔI làm cho NGƯỜI KHÁC | NGƯỜI KHÁC làm cho TÔI\nQuan điểm | Người cho (tôi) | Người nhận (tôi)\nChủ ngữ | わたしが…てあげます | わたしが[人]に…てもらいます\nVí dụ | ともだちにおしえてあげました | ともだちにおしえてもらいました","examples":[{"jp":"ともだちが てつだってくれました。","vn":"Bạn bè đã giúp tôi (biết ơn)."},{"jp":"せんせいが かんじを おしえてくれました。","vn":"Thầy đã dạy tôi Kanji (biết ơn)."},{"jp":"てあげます","vn":"tôi→khác"},{"jp":"てもらいます","vn":"tôi←khác"}]},{"title":"N を あげます／もらいます／くれます（基本授受）","formula":"N(người) に N(vật) を あげます ／ N(người) に N(vật) を もらいます ／ N(người) が N(vật) を くれます\nCấu trúc | Ví dụ | Nghĩa\nN に N を あげます | ともだちにプレゼントをあげます | cho bạn món quà\nN に N を もらいます | ともだちにプレゼントをもらいます | nhận quà từ bạn\nN が N を くれます | ともだちがプレゼントをくれます | bạn cho tôi quà","explain":"Dạng cơ bản (không て) của hệ thống cho-nhận: dùng khi CHO / NHẬN một đồ vật (không phải hành động).\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ ともだちがほんをもらいます (muốn nói 'bạn cho tôi') → ✅ ともだちがほんをくれます — 'cho tôi' dùng くれます (người cho là chủ語).","compare":"","examples":[{"jp":"たんじょうびに ともだちに ほんを あげました。","vn":"Sinh nhật tôi tặng sách cho bạn."},{"jp":"せんせいに おかしを もらいました。","vn":"Tôi nhận kẹo từ thầy giáo."},{"jp":"ともだちにプレゼントをあげます","vn":"cho bạn món quà"},{"jp":"ともだちにプレゼントをもらいます","vn":"nhận quà từ bạn"},{"jp":"ともだちがプレゼントをくれます","vn":"bạn cho tôi quà"}]},{"title":"疑問詞 + が V（新情報の焦点）","formula":"だれが / なにが / どこが + V ますか","explain":"Khi muốn hỏi CHỦ NGỮ (ai/cái gì là người làm), dùng 疑問詞 + が. KHÔNG dùng は.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ だれはきましたか → ✅ だれがきましたか — hỏi ai làm dùng が, không dùng は.","compare":"","examples":[{"jp":"だれが この てがみを くれましたか。","vn":"Ai đã cho bạn bức thư này?"},{"jp":"なにが いちばん おいしかったですか。","vn":"Cái gì ngon nhất?"},{"jp":"ともだちが てつだってくれました。","vn":"Bạn bè đã giúp tôi (biết ơn)."}]}],"24":[{"title":"V たら (điều kiện)","formula":"V た形 → V たら ⇒ [Kết quả]\nた形 | → ～たら | Nghĩa\nたべた | → たべたら | nếu ăn\nいった | → いったら | nếu đi\nやすかった | → やすかったら | nếu rẻ\nしずかだった | → しずかだったら | nếu yên tĩnh\nがくせいだった | → がくせいだったら | nếu là sinh viên","explain":"たら = nếu/khi V xảy ra. Cách tạo: lấy た形, đổi た → たら.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ いくたら → ✅ いったら — lấy た形, đổi た → たら.","compare":"","examples":[{"jp":"もし あめが ふったら、うちに います。","vn":"Nếu trời mưa thì tôi ở nhà."},{"jp":"しゅくだいが おわったら、でかけましょう。","vn":"Khi làm xong bài tập, đi ra ngoài."},{"jp":"もし じかんが あったら、にほんへ いきたいです。","vn":"Giả sử có thời gian thì muốn đến Nhật."},{"jp":"うちへ かえったら、だれも いませんでした。","vn":"Khi về nhà thì phát hiện không có ai cả."}]},{"title":"もし ～たら（仮定の強調）","formula":"もし + [条件] + たら、[結果]","explain":"もし = 'nếu (giả sử như)'. Thêm vào trước たら để NHẤN MẠNH tính giả thuyết, chưa chắc xảy ra.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ もし → 不要 (không bắt buộc) — もし chỉ là từ nhấn mạnh, không bắt buộc có mặt. たら vẫn đủ.","compare":"","examples":[{"jp":"もし じかんが あったら、にほんへ いきたいです。","vn":"Giả sử có thời gian thì muốn đến Nhật."},{"jp":"もし おかねが たくさん あったら、なにを したいですか。","vn":"Nếu có nhiều tiền thì muốn làm gì?"},{"jp":"もし あめが ふったら、うちに います。","vn":"Nếu trời mưa thì tôi ở nhà."},{"jp":"うちへ かえったら、だれも いませんでした。","vn":"Khi về nhà thì phát hiện không có ai cả."}]},{"title":"V たら ～た（後件の発見）","formula":"V たら、[Phát hiện bất ngờ — V た/でした]","explain":"Khi đã làm V₁ rồi, PHÁT HIỆN ra điều gì đó (bất ngờ, không chủ động). Kết quả trong mệnh đề sau thường là た/でした.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ うちへかえると、だれもいませんでした → ✅ うちへかえったら — phát hiện bất ngờ chỉ dùng たら, không dùng と.","compare":"","examples":[{"jp":"うちへ かえったら、だれも いませんでした。","vn":"Khi về nhà thì phát hiện không có ai cả."},{"jp":"れいぞうこを あけたら、なにも ありませんでした。","vn":"Mở tủ lạnh ra thì không có gì."},{"jp":"もし あめが ふったら、うちに います。","vn":"Nếu trời mưa thì tôi ở nhà."},{"jp":"もし じかんが あったら、にほんへ いきたいです。","vn":"Giả sử có thời gian thì muốn đến Nhật."}]},{"title":"V ばよかった（後悔・失望）","formula":"V ば形 + よかった ／ V なければよかった\nV | → ば形 + よかった | Nghĩa\nいく | → いけば + よかった | Giá mà đã đi thì tốt\nたべる | → たべれば + よかった | Giá mà đã ăn thì tốt\nする | → すれば + よかった | Giá mà đã làm thì tốt\nV なければよかった | いかなければよかった | Giá mà đã không đi thì tốt","explain":"'Giá mà đã V thì tốt rồi' — diễn tả HỐI TIẾC về điều đã không làm hoặc đã làm sai.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ いったらよかった → ✅ いけばよかった — hối tiếc dùng ば形 + よかった (không dùng たら).","compare":"","examples":[{"jp":"もっと べんきょうすれば よかったです。","vn":"Giá mà đã học nhiều hơn thì tốt rồi."},{"jp":"あの えいがを みれば よかったです。","vn":"Giá mà đi xem phim đó thì tốt rồi."},{"jp":"「にほんごを べんきょうしています。」「にほんごなら、あの ほんが いいですよ。」","vn":"'Đang học tiếng Nhật.' 'Nếu tiếng Nhật thì cuốn sách đó tốt.'"}]},{"title":"～なら","formula":"N/普通形 + なら ⇒ [Gợi ý/Phản ứng]","explain":"なら = 'NẾU thật sự là vậy thì…'. Phản ứng dựa trên THÔNG TIN VỪA NGHE từ người khác.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"","compare":"～たら (giả thuyết/tương lai)  vs  ～なら (phản ứng thông tin)\n～たら (giả thuyết/tương lai) | ～なら (phản ứng thông tin)\nKhi dùng | Giả thuyết / sự kiện sẽ xảy ra | Phản ứng với thông tin vừa nghe\nVí dụ | あめがふったら、うちにいます | 「にほんへいきます」「にほんなら、すしをたべてください」\nAi quyết định | Mình quyết định hành động | Đưa gợi ý cho NGƯỜI KHÁC","examples":[{"jp":"「にほんごを べんきょうしています。」「にほんごなら、あの ほんが いいですよ。」","vn":"'Đang học tiếng Nhật.' 'Nếu tiếng Nhật thì cuốn sách đó tốt.'"},{"jp":"「とうきょうへ いきます。」「とうきょうなら、スカイツリーへ いってください。」","vn":"'Tôi đi Tokyo.' 'Nếu Tokyo thì hãy đi Skytree.'"},{"jp":"もっと べんきょうすれば よかったです。","vn":"Giá mà đã học nhiều hơn thì tốt rồi."}]}],"25":[{"title":"V ても (dù cho — trung tính)","formula":"V て形 + も ／ いAdj: ～くても ／ なAdj/N: ～でも\nGốc | → ～ても | Nghĩa\nたべて | → たべても | dù ăn\nあめがふって | → あめがふっても | dù trời mưa\nたかい | → たかくても | dù đắt\nしずか(な) | → しずかでも | dù yên tĩnh\nにちようび(N) | → にちようびでも | dù là chủ nhật","explain":"Nhượng bộ: 'dù A, vẫn B'. Sắc thái TRUNG LẬP — kết quả bất chấp điều kiện, không có cảm xúc tiêu cực mạnh.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"","compare":"","examples":[{"jp":"あめが ふっても、がっこうへ いきます。","vn":"Dù trời mưa tôi vẫn đi học."},{"jp":"たかくても、このかばんを かいたいです。","vn":"Dù đắt tôi vẫn muốn mua túi này."},{"jp":"いくら べんきょうしても、なかなか おぼえられません。","vn":"Dù học bao nhiêu cũng mãi không nhớ được."}]},{"title":"～のに (mặc dù — thất vọng)","formula":"[普通形] + のに","explain":"Tương phản + cảm xúc TIÊU CỰC: thất vọng, phàn nàn, bất mãn. 'Mặc dù A mà lại B (thật đáng tiếc)'.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ あめがふるのにいきます (muốn nói: dù mưa vẫn đi) → ✅ あめがふってもいきます — trung tính dùng ても, không phải のに.","compare":"～ても (trung tính)  vs  ～のに (thất vọng)\n～ても (trung tính) | ～のに (thất vọng)\nCảm xúc | Trung lập — chấp nhận | Thất vọng — phàn nàn\nVí dụ | べんきょうしてもわかりません | べんきょうしたのにわかりません\nHàm ý | Dù thế, tôi chấp nhận | Tôi đã cố mà vẫn không được (buồn)\nKhi dùng | Nói chung chung | Kết quả cụ thể đã xảy ra, đáng tiếc","examples":[{"jp":"いっしょうけんめい べんきょうしたのに、しけんに おちました。","vn":"Dù đã học chăm chỉ mà lại thi trượt."},{"jp":"やくそくしたのに、きませんでした。","vn":"Đã hẹn mà lại không đến."},{"jp":"あめがふるのにいきます","vn":"muốn nói: dù mưa vẫn đi"}]},{"title":"いくら ～ても（程度強調の逆接）","formula":"いくら + [Adj/V て形] + も、～ない","explain":"いくら ～ても = 'Dù bao nhiêu/dù thế nào đi nữa cũng không…'. Nhấn mạnh mức độ nhượng bộ.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ いくらべんきょうしてもおぼえます → ✅ おぼえられません — いくら～ても thường đi với phủ定.","compare":"","examples":[{"jp":"いくら べんきょうしても、なかなか おぼえられません。","vn":"Dù học bao nhiêu cũng mãi không nhớ được."},{"jp":"いくら たかくても、あのかばんが ほしいです。","vn":"Dù đắt bao nhiêu tôi cũng muốn cái túi đó."},{"jp":"あめが ふっても、がっこうへ いきます。","vn":"Dù trời mưa tôi vẫn đi học."}]},{"title":"～はずです（期待・論理的推測）","formula":"[普通形] + はずです ／ [普通形] + はずがありません\nCấu trúc | Ví dụ | Nghĩa\nV 辞書形 + はずです | くるはずです | lẽ ra sẽ đến\nV た + はずです | おわったはずです | chắc đã xong rồi\nいAdj + はずです | やすいはずです | lẽ ra phải rẻ\nなAdj な + はずです | しずかなはずです | lẽ ra phải yên tĩnh","explain":"はずです = 'lẽ ra phải / chắc chắn là' — suy luận dựa trên THÔNG TIN / LOGIC, kỳ vọng hợp lý.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.","usage":"❌ べんりなはずです → OK. べんりのはずです → ✅ べんりなはずです — なAdj dùng な trước はず.","compare":"","examples":[{"jp":"やまださんは もう きているはずです。３０ぷんまえに でたと いっていましたから。","vn":"Anh Yamada chắc đã đến rồi. Vì anh ấy nói đã ra 30 phút trước."},{"jp":"このくすりを のめば、なおるはずです。","vn":"Uống thuốc này thì lẽ ra sẽ khỏi."},{"jp":"くるはずです","vn":"lẽ ra sẽ đến"},{"jp":"おわったはずです","vn":"chắc đã xong rồi"},{"jp":"やすいはずです","vn":"lẽ ra phải rẻ"}]},{"title":"疑問詞まとめ: Tổng hợp từ nghi vấn N5","formula":"なに/だれ/いつ/どこ/いくら/いくつ/どのくらい/どうして...","explain":"Bảng ôn tập toàn bộ từ nghi vấn đã học xuyên suốt N5 - dùng để ôn trước khi chuyển sang N4.\nCấp độ: N5  |  Độ lịch sự: phù hợp giao tiếp cơ bản hàng ngày.\nどなた lịch sự hơn だれ, どちら lịch sự hơn どこ/どれ - dùng khi nói chuyện với người lớn tuổi/cấp trên.","usage":"Dùng khi: Ôn tập tổng hợp - dùng làm bảng tra cứu nhanh khi làm bài tập hoặc trước kỳ thi N5.\n❌ なんにんの がくせいが いますか → ✅ きょうしつに がくせいが なんにん いますか — なんにん đặt sau danh từ + trợ từ が, không đặt trước danh từ như tính từ","compare":"","examples":[{"jp":"これは なんですか。- ほんです。","vn":"Cái này là gì? - Là sách."},{"jp":"きょうしつに なんにん いますか。","vn":"Trong lớp có bao nhiêu người?"},{"jp":"いっしょうけんめい べんきょうしたのに、しけんに おちました。","vn":"Dù đã học chăm chỉ mà lại thi trượt."}]}],"26":[{"title":"Vる/Vた/Vている・イA/イAかった・ナA(な)/ナAだった・N(な)/Nだった + んです","formula":"Loại từ | Khẳng định | Phủ định | Quá khứ khẳng định | Quá khứ phủ định\nĐộng từ | V(る) + んです | V(ない) + んです | V(た) + んです | V(なかった) + んです\nTính từ đuôi い | い + んです | くない + んです | かった + んです | くなかった + んです\nTính từ đuôi な | な + んです | じゃない + んです | だった + んです | じゃなかった + んです\nDanh từ | な + んです | じゃない + んです | だった + んです | じゃなかった + んです\nんですか – dùng khi hỏi lại/xác nhận lý do, hoặc yêu cầu người nghe cung cấp thêm thông tin.\n疑問詞 + んですか – ví dụ どこで買ったんですか (Bạn đã mua ở đâu vậy?)\n① Phỏng đoán rồi xác nhận nguyên nhân/lý do với điều mình đã nghe/nhìn thấy.\n例: たまに関西弁を使いますね。大阪に住んでいたんですか。\n(Thỉnh thoảng cậu dùng tiếng Kansai nhỉ. Cậu từng sống ở Osaka à?)\n② Yêu cầu người nghe cung cấp thêm thông tin về điều mình vừa nghe/nhìn thấy (thường đi kèm từ để hỏi).\n例: その靴、デザインがいいですね。どこで買ったんですか。\n(Đôi giày đó thiết kế đẹp nhỉ. Cậu mua ở đâu vậy?)\n③ Muốn được giải thích nguyên nhân/lý do với điều mình nghe/nhìn thấy — thường đi với từ để hỏi どうして／なぜ.\n例: どうして泣いているんですか。(Tại sao con lại khóc vậy?)\n④ Muốn được giải thích về một tình hình/tình trạng đang diễn ra — thường dùng câu hỏi ngắn どうしたんですか.\n例: どうしたんですか。 (Có chuyện gì vậy?)\nTrả lời cho câu hỏi ở cách ③ và ④: dùng lại んです ở câu trả lời để giải thích lý do/tình trạng.\n例: A: どうして泣いているんですか。 B: お金がないんです。\n(A: Tại sao con khóc? B: Vì con không có tiền.)","explain":"diễn đạt lời giải thích, xác nhận nguyên nhân – lý do, hoặc mong muốn/yêu cầu người nghe cung cấp thêm thông tin, dựa trên điều người nói đã nghe/nhìn thấy.\nCấp độ: N4  |  Độ lịch sự: trung tính đến thân mật; dạng lịch sự là んです → んですか / thể trang trọng hơn là のです・のですか.\nんです mang tính chất khẩu ngữ, dùng rất nhiều trong hội thoại đời sống hàng ngày và trong các bài nghe/đọc hiểu ở trình độ cao hơn (N3, N2). Người nói dùng んです để \"mở lòng\" giải thích bối cảnh, khiến câu nói tự nhiên và có tính liên kết logic với ngữ cảnh, khác với câu chỉ dùng です/ます đơn thuần mang tính liệt kê sự việc.","usage":"N3/N2: trong câu hỏi どうして có thể thay thế bằng んですか mà không cần から ở cuối — cách nói tự nhiên, hiện đại hơn cách học ở N5.\nDùng khi: giải thích lý do, xác nhận điều đã phỏng đoán, xin thêm thông tin, hỏi/đáp về tình huống đang diễn ra.\nKhông dùng khi: chỉ đơn thuần tường thuật sự thật khách quan không có ngữ cảnh, không cần giải thích (lúc đó dùng です/ます bình thường).\nhọc viên Việt Nam hay quên đổi danh từ/tính từ đuôi な về dạng な trước んです (ví dụ nhầm 元気んです thay vì 元気なんです).\ndùng んです trong văn viết trang trọng/báo cáo công việc — làm câu văn nghe khẩu ngữ, thiếu trang trọng.","compare":"んです vs から: から chỉ nêu lý do một cách trực tiếp, khách quan; んです mang sắc thái giải thích, kết nối với ngữ cảnh, thường dùng trong hội thoại.\nんです vs ので: ので lịch sự, trang trọng, dùng nêu lý do khách quan trong câu phức; んです thiên về giải thích cá nhân, khẩu ngữ.","examples":[{"jp":"頭が痛いんです。","vn":"Đầu tôi đau."},{"jp":"どこでその靴を買ったんですか。","vn":"Bạn đã mua đôi giày đó ở đâu vậy? (Xin thêm thông tin)"},{"jp":"日本語が下手なんですが、どう勉強したらいいですか。","vn":"Tiếng Nhật của em còn kém, em nên học thế nào thì tốt ạ?"},{"jp":"会議の資料についてお聞きしたいことがあるんですが、少しよろしいでしょうか。","vn":"Em có điều muốn hỏi về tài liệu cuộc họp, anh/chị có thể dành chút thời gian được không ạ? (Mở lời trang trọng)"},{"jp":"エアコンが壊れているんですが、見ていただけませんか。","vn":"Điều hòa nhà em bị hỏng, anh có thể xem giúp em được không ạ?"}]},{"title":"Vて + いただけませんか","formula":"Dạng | Cấu trúc | Ghi chú\nKhẳng định (đề nghị) | Vて + いただけませんか | Yêu cầu lịch sự, dùng với người trên\nTương đương thân mật | Vて + もらえませんか / Vて + ください | Dùng với bạn bè, đồng nghiệp ngang hàng\nTrả lời đồng ý | はい、いいですよ／かしこまりました | —\nTrả lời từ chối lịch sự | すみません、ちょっと… | —","explain":"nhờ/yêu cầu người nghe làm một việc gì đó cho mình, với độ lịch sự rất cao.\nCấp độ: N4  |  Độ lịch sự: rất cao — dùng với người trên, cấp trên, người mới gặp lần đầu.\nいただく là khiêm nhường ngữ của もらう (nhận). ～ていただけませんか vì thế lịch sự hơn hẳn ～てもらえませんか và ～てください, vì mang tính khiêm tốn, hạ thấp bản thân người nói để tôn trọng người nghe — phù hợp môi trường công sở, giao tiếp với khách hàng, người lớn tuổi, người mới quen.","usage":"Dùng khi: nhờ cấp trên, khách hàng, người lạ, người lớn tuổi làm gì đó cho mình.\nKhông dùng khi: nói chuyện với bạn bè thân thiết, người dưới — lúc đó dùng ～てくれない？ hoặc ～てもらえない？ để tự nhiên hơn, dùng ～ていただけませんか sẽ nghe xa cách, khách sáo.\nnhầm chủ thể hành động — ～ていただけませんか luôn yêu cầu NGƯỜI NGHE thực hiện hành động cho mình, khác với ～てもいいですか (xin phép NGƯỜI NÓI tự thực hiện hành động).\nchia sai động từ いただく như động từ thông thường, quên rằng đây là dạng khiêm nhường ngữ của もらう chứ không phải của くれる.","compare":"～ていただけませんか vs ～てもらえませんか: cùng nghĩa \"nhờ ai làm gì cho mình\" nhưng ～ていただけませんか lịch sự, trang trọng hơn nhiều.\n～ていただけませんか vs ～てもいいですか: ～ていただけませんか là NHỜ người nghe làm; ～てもいいですか là XIN PHÉP để bản thân người nói làm.","examples":[{"jp":"電話を貸していただけませんか。","vn":"Anh có thể cho em mượn điện thoại được không ạ?"},{"jp":"この漢字の書き方を教えていただけませんか。","vn":"Anh/chị có thể chỉ cho em cách viết chữ Hán này được không ạ?"},{"jp":"これを持っていただけませんか。","vn":"Anh/chị có thể cầm giúp em cái này được không ạ?"},{"jp":"日本語で書いたレポートを見ていただけませんか。","vn":"Anh/chị có thể xem giúp em bản báo cáo viết bằng tiếng Nhật này được không ạ?"},{"jp":"お金を貸していただけませんか。","vn":"Anh/chị có thể cho tôi vay tiền được không ạ?"}]},{"title":"疑問詞 + Vたら + いいですか","formula":"Dạng | Cấu trúc | Ví dụ\nNghi vấn (chuẩn) | 疑問詞 + Vたら + いいですか | どこで買ったらいいですか\nThân mật | 疑問詞 + Vたら + いい？ / いいだろう | どうしたらいい？\nTrả lời | Vたら + いいです / Vたほうがいいです | そこで買ったらいいですよ","explain":"hỏi xin ý kiến, lời khuyên của người nghe về việc nên làm gì trong một tình huống cụ thể.\nCấp độ: N4  |  Độ lịch sự: lịch sự, trung tính — phù hợp cả giao tiếp thân mật lẫn trang trọng.\nCấu trúc luôn cần một từ để hỏi (どこ, だれ, なに, どう…) đứng trước ～たらいいですか. Đây là cách hỏi xin lời khuyên phổ biến, tự nhiên trong đời sống, khác hẳn cách hỏi khô cứng kiểu N5.","usage":"Dùng khi: người nói đang phân vân, chưa biết nên làm gì và muốn xin lời khuyên/tư vấn từ người nghe.\nKhông dùng khi: câu hỏi không mang tính xin lời khuyên (chỉ hỏi thông tin đơn thuần) — lúc đó chỉ cần です/ますか bình thường.\nquên từ để hỏi (どこ/だれ/なに/どう…) đứng trước たら, khiến câu mất nghĩa \"xin lời khuyên\".\nchia sai thể たら của động từ nhóm 2, 3 (ví dụ nhầm 食べたら thành 食べったら).","compare":"～たらいいですか vs ～ばいいですか: cùng nghĩa xin lời khuyên; ～たら thông dụng, tự nhiên hơn trong khẩu ngữ; ～ば trang trọng, hay gặp trong văn viết.\n～たらいいですか vs ～たほうがいいですか: ～たらいいですか hỏi \"nên làm gì\"; ～たほうがいいですか hỏi xác nhận \"có nên làm X hay không\".","examples":[{"jp":"彼女が好きなんですが、どうしたらいいですか。","vn":"Em rất thích cô ấy, bây giờ em nên làm gì?"},{"jp":"この問題が難しくて、誰に聞いたらいいですか。","vn":"Vấn đề này khó quá, tôi nên hỏi ai thì tốt?"},{"jp":"スーツはどこで買ったらいいですか。","vn":"Tôi nên mua vest ở đâu thì tốt?"},{"jp":"階のパソコンが壊れてしまったんですが、どうしたらいいですか。","vn":"Máy tính ở tầng 2 bị hỏng rồi, bây giờ em nên làm gì?"},{"jp":"日本人の友達が結婚するんですが、何をあげたらいいですか。","vn":"Bạn người Nhật của tôi sắp kết hôn, tôi nên tặng gì thì tốt?"}]}],"27":[{"title":"Động từ thể khả năng (可能形) — \"có thể làm...\"","formula":"Nhóm | Quy tắc chia | Ví dụ\nNhóm 1 (u-verbs) | Đổi âm cuối hàng い (i) → hàng え (e), giữ nguyên đuôi ます | 泳ぎます → 泳げます  (bơi → có thể bơi)\n書きます → 書けます  (viết → có thể viết)\n話します → 話せます  (nói → có thể nói)\nNhóm 2 (ru-verbs) | Bỏ ます, thêm られます | 食べます → 食べられます  (ăn → có thể ăn)\n覚えます → 覚えられます  (nhớ → có thể nhớ)\nNhóm 3 (bất quy tắc) | します → できます／来ます → 来られます | 勉強します → 勉強できます  (học → có thể học)","explain":"diễn tả năng lực/khả năng của một người có thể thực hiện một hành động nào đó. Chủ yếu dùng với động từ chỉ hành động có ý chí (bay, bơi, nói, đọc, viết...).\nĐây là cách nói ngắn gọn, tự nhiên thay thế cho mẫu N5: động từ thể từ điển + ことができます. Từ N3 trở lên không còn mẫu nào thay thế 可能形 nữa — bắt buộc phải nắm chắc.\nTrợ từ を của tân ngữ chuyển thành が khi dùng với động từ thể khả năng. Các trợ từ khác (に, へ, で...) giữ nguyên.\n日本語を書きます → 日本語が書けます  (viết tiếng Nhật → có thể viết tiếng Nhật)\nわかります (hiểu), できます, 会えます... bản thân đã mang nghĩa khả năng nên KHÔNG chia thể khả năng lần nữa.\nVì sao không học 可能形 ngay từ N5 mà học ことができます trước?\n(1) Cách chia 可能形 phức tạp hơn, người mới học dễ rối;\n(2) Ở bài 49-50, chính động từ thể khả năng còn đóng vai trò tôn kính ngữ — học ことができます trước giúp tránh nhầm lẫn.","usage":"","compare":"Tiêu chí | 動詞辞書形＋ことができます | 動詞可能形\nĐộ dài | Dài, trang trọng hơn | Ngắn gọn, tự nhiên\nCấp độ | N5 | N4 trở lên — thay thế hoàn toàn\nMức độ dùng thực tế | Ít dùng trong hội thoại tự nhiên | Người Nhật dùng phổ biến","examples":[{"jp":"泳ぎます → 泳げます","vn":"bơi → có thể bơi"},{"jp":"書きます → 書けます","vn":"viết → có thể viết"},{"jp":"話します → 話せます","vn":"nói → có thể nói"},{"jp":"食べます → 食べられます","vn":"ăn → có thể ăn"},{"jp":"覚えます → 覚えられます","vn":"nhớ → có thể nhớ"}]},{"title":"見えます／聞こえます (không chủ ý) và 見られます／聞けます (có chủ ý)","formula":"","explain":"Cả 2 cặp đều dịch là \"có thể nhìn thấy / có thể nghe thấy\", nhưng khác nhau hoàn toàn về bản chất hành động:\nNhóm | Từ | Bản chất | Ví dụ tình huống\nKhông chủ ý | 見えます／聞こえます | Sự vật/âm thanh tự lọt vào mắt/tai — người nói KHÔNG cố ý nhìn/nghe | Đang ngủ, tự nhiên nghe thấy tiếng bước chân trên mái nhà\nCó chủ ý | 見られます／聞けます | Người nói cố tình dùng thời gian/giác quan để nhìn/nghe (dạng 可能形 của 見ます/聞きます) | Cố tình lắng tai tìm tiếng mèo kêu; cố tình đi ngắm ai đó\nNghĩa tiếng Việt của hai cặp giống nhau, nhưng chọn sai sẽ tạo hình ảnh hoàn toàn khác trong đầu người Nhật (vô tình bắt gặp ↔ cố tình rình/tìm).\n猫の鳴き声が聞こえます。  (Tôi nghe thấy tiếng mèo kêu — vô tình nghe thấy, không cố ý.)\n猫を探していたら、鳴き声が聞けました。  (Đang tìm mèo thì nghe được tiếng kêu của nó — cố tình lắng nghe.)","usage":"","compare":"","examples":[{"jp":"見えます／聞こえます","vn":"Sự vật/âm thanh tự lọt vào mắt/tai — người nói KHÔNG cố ý nhìn/nghe"},{"jp":"猫の鳴き声が聞こえます。","vn":"Dịch: Tôi nghe thấy tiếng mèo kêu."},{"jp":"猫を探していたら、鳴き声が聞けました。","vn":"Đang tìm mèo thì nghe được tiếng kêu của nó — cố tình lắng nghe."}]},{"title":"できます — 3 nghĩa chính","formula":"","explain":"Nghĩa | Cấu trúc | Ví dụ\n1. Có thể làm (khả năng) | N + ができます | 料理ができます。  (Tôi có thể nấu ăn.)\n2. Được hoàn thành / xây dựng nên | Địa điểm + に + N + ができます | 大阪に新しい空港ができました。  (Ở Osaka có một sân bay mới được xây.)\n3. Phát sinh (việc đột xuất) | N + ができました | 急に用事ができました。  (Đột nhiên tôi có việc bận phát sinh.)\nNghĩa \"phát sinh\" ít gặp ở trình độ N4-N5 nhưng người Nhật dùng rất nhiều trong hội thoại lịch sự/công việc, ví dụ khi xin phép về sớm hoặc báo bận đột xuất với đối tác.\nレポートはいつできますか。  (Báo cáo bao giờ thì xong?)\n先生、急に用事ができて、先に帰ってもいいですか。  (Thưa cô, em có việc bận đột xuất, em về trước được không ạ?)","usage":"","compare":"","examples":[{"jp":"料理ができます。","vn":"Tôi có thể nấu ăn."},{"jp":"大阪に新しい空港ができました。","vn":"Ở Osaka có một sân bay mới được xây."},{"jp":"急に用事ができました。","vn":"Đột nhiên tôi có việc bận phát sinh."},{"jp":"レポートはいつできますか。","vn":"Dịch: Báo cáo bao giờ thì xong?"}]},{"title":"Ôn tập: だけ và しか…ない (chỉ có)","formula":"","explain":"Mẫu | Đi với | Ý nghĩa\nN + だけ | Câu khẳng định | Chỉ có... (trung tính)\nN + しか + phủ định | Bắt buộc câu phủ định | Chỉ có... mà thôi (nhấn mạnh số ít, số lượng ít hơn mong đợi)\nしか luôn đi với động từ/tính từ ở thể phủ định — quên phủ định là lỗi sai phổ biến nhất.\n私の心の中にはあなただけです。  (Trong trái tim anh chỉ có một mình em.)\nゆうべ2時間しか眠れませんでした。  (Tối qua tôi chỉ ngủ được có 2 tiếng thôi.)","usage":"","compare":"","examples":[{"jp":"私の心の中にはあなただけです。","vn":"Dịch: Trong trái tim anh chỉ có một mình em."},{"jp":"ゆうべ2時間しか眠れませんでした。","vn":"Dịch: Tối qua tôi chỉ ngủ được có 2 tiếng thôi."},{"jp":"わたしは日本語で手紙が書けます。","vn":"Dịch: Tôi có thể viết thư bằng tiếng Nhật."}]}],"28":[{"title":"～ながら (vừa... vừa...)","formula":"V(ます-form bỏ ます) + ながら、V2  — vừa V1 vừa V2","explain":"Diễn tả một chủ thể thực hiện đồng thời 2 hành động trong cùng một khoảng thời gian; hành động V2 (vế sau) được nhấn mạnh hơn V1\nCấp độ: N4\nĐộ lịch sự: Trung tính, dùng được cả văn nói lẫn văn viết\nChỉ dùng khi CÙNG MỘT CHỦ THỂ thực hiện 2 hành động — đây là điểm learners hay sai nhất\n2 hành động phải diễn ra trong cùng khoảng thời gian nhất định, không dùng cho 2 hành động nối tiếp nhau","usage":"KHÔNG dùng ながら khi 2 hành động do 2 chủ thể khác nhau thực hiện\nKHÔNG dùng ながら khi 2 hành động diễn ra tuần tự, có trước có sau (ví dụ: \"để cửa mở rồi đi ngủ\" — đây là 2 hành động nối tiếp, không phải đồng thời liên tục, nên KHÔNG dùng ながら)","compare":"So với てから (làm xong V1 rồi mới làm V2): ながら là đồng thời, てから là tuần tự","examples":[{"jp":"音楽を聞きながら、勉強します。","vn":"Vừa nghe nhạc vừa học bài."},{"jp":"歩きながら、たばこを吸わないでください。","vn":"Đừng vừa đi bộ vừa hút thuốc."},{"jp":"音楽を聞きながら、勉強しました。","vn":"Đã vừa nghe nhạc vừa học bài."},{"jp":"テレビを見ながら、ご飯を食べますか。","vn":"Bạn có vừa xem tivi vừa ăn cơm không?"},{"jp":"・ガムを噛みながら運転すると、眠くなりませんよ。","vn":"Nếu vừa nhai kẹo cao su vừa lái xe thì sẽ đỡ buồn ngủ đấy."}]},{"title":"Vて + います (diễn tả thói quen)","formula":"V(て-form) + います  — thường/hay V\nKhẳng định: 毎朝6時に起きています。 (Hàng sáng tôi thường thức dậy lúc 6 giờ.)\nPhủ định: 休みの日はあまり勉強していません。 (Ngày nghỉ tôi thường không học mấy.)\nQuá khứ (thói quen trong quá khứ): 学生のころ、よく小説を読んでいました。 (Hồi còn là học sinh, tôi thường hay đọc tiểu thuyết.)\nNghi vấn: 毎朝何時に起きていますか。 (Hàng sáng bạn thường thức dậy lúc mấy giờ?)","explain":"Diễn tả một hành động lặp đi lặp lại đều đặn, trở thành thói quen/nhịp sinh học của chủ thể\nCấp độ: N4 (ý nghĩa mới của mẫu ています đã học ở N5)\nĐộ lịch sự: Trung tính\nĐây KHÔNG phải nghĩa \"đang làm gì\" (hiện tại tiếp diễn) đã học ở N5, mà là nghĩa \"thường làm gì\" (thói quen lặp lại)\nCâu đi kèm thường có phó từ tần suất: 毎朝/毎日/よく, hoặc câu tương phản với きょう/きのう để làm rõ đây là ngoại lệ so với thói quen","usage":"học viên nhầm ています ở đây với nghĩa \"đang diễn ra\" đã quen từ N5, dẫn đến dịch sai toàn câu\nCách phân biệt: nếu câu có ý lặp lại đều đặn theo thời gian (hàng ngày/hàng sáng) → nghĩa thói quen; nếu là hành động tại thời điểm nói → nghĩa tiếp diễn","compare":"So với ています (N5, hiện tại tiếp diễn): cùng hình thức nhưng khác nghĩa — phải dựa vào ngữ cảnh","examples":[{"jp":"毎朝6時に起きています。","vn":"Hàng sáng tôi thường thức dậy lúc 6 giờ."},{"jp":"休みの日はあまり勉強していません。","vn":"Ngày nghỉ tôi thường không học mấy."},{"jp":"毎朝何時に起きていますか。","vn":"Hàng sáng bạn thường thức dậy lúc mấy giờ?"}]},{"title":"～し～し (vừa... vừa..., vì... nên...)","formula":"普通形（Thể thông thường） + し、普通形 + し、...  — vừa... vừa...; vì... (và...) nên...\nChia thể thông thường trước し:\ntính từ đuôi い giữ nguyên (+し);\ntính từ đuôi な + だ (+し);\ndanh từ + だ (+し);\nđộng từ giữ nguyên thể thông thường (+し)\nKhẳng định (liệt kê tích cực):\nはまじめだし、だし、日本語も上手になると思います。\n(Cô ấy vừa chăm chỉ vừa nhiệt tình, nên tôi nghĩ tiếng Nhật cô ấy sẽ giỏi lên.)\nKhẳng định (liệt kê tiêu cực):\n経験もないし、パソコンも使えないし、この仕事はできません。\n(Vừa không có kinh nghiệm vừa không dùng được máy tính, nên không thể làm công việc này.)\nNêu lý do:\n仕事もし、給料もいいし、この会社で働きたいです。\n(Công việc thú vị, lương cũng cao, nên tôi muốn làm ở công ty này.)\nNghi vấn:\nこの靴はデザインもいいし、サイズもちょうどいいですか。\n(Đôi giày này vừa đẹp vừa vừa cỡ à?)","explain":"Nối các mệnh đề/đặc điểm CÙNG một chiều (cùng tích cực hoặc cùng tiêu cực) của cùng một chủ thể; Liệt kê các lý do dẫn đến một kết luận, hàm ý \"còn nhiều lý do khác nữa\"\nCấp độ: N4\nĐộ lịch sự: Trung tính, phổ biến trong văn nói\nTrợ từ も thường xuất hiện sau danh từ được liệt kê (パソコンも, 給料も) để nhấn mạnh \"cũng... nữa\"\nMuốn nhấn mạnh thêm 1 nội dung đặc biệt: dùng それに (\"hơn thế nữa\") thay vì し ở mệnh đề cuối","usage":"KHÔNG được trộn 1 đặc điểm tích cực với 1 đặc điểm tiêu cực trong cùng chuỗi し～し (ví dụ không nói \"cao ráo NHƯNG hôi\" bằng し)\nhọc viên quên chia đúng thể thông thường trước し (đặc biệt tính từ な và danh từ phải thêm だ)","compare":"So với て (liệt kê đã học ở N5): て là văn viết/trang trọng hơn, thường chỉ liệt kê thuần tuý; し mang tính khẩu ngữ và có thể hàm ý lý do\nSo với から/ので (lý do, Bài 26): から/ので chỉ nêu 1 lý do rõ ràng; し ngụ ý còn nhiều lý do khác chưa nói hết","examples":[{"jp":"彼女はまじめだし、親切だし、日本語も上手になると思います。","vn":"Cô ấy vừa chăm chỉ vừa nhiệt tình, nên tôi nghĩ tiếng Nhật cô ấy sẽ giỏi lên."},{"jp":"経験もないし、パソコンも使えないし、この仕事はできません。","vn":"Vừa không có kinh nghiệm vừa không dùng được máy tính, nên không thể làm công việc này."},{"jp":"仕事も面白いし、給料もいいし、この会社で働きたいです。","vn":"Công việc thú vị, lương cũng cao, nên tôi muốn làm ở công ty này."}]},{"title":"それで (do đó, vì vậy)","formula":"[Câu nêu nguyên nhân/lý do]。それで、[Câu nêu kết quả]。","explain":"Liên từ mở đầu câu, dùng để nêu KẾT QUẢ từ nguyên nhân/lý do đã trình bày ở câu trước\nCấp độ: N4\nĐộ lịch sự: Trung tính, dùng trong cả văn nói và văn viết\nそれで luôn đứng ĐẦU CÂU MỚI (sau dấu chấm), khác với し và ながら nối trong cùng một câu\nVế sau それで là KẾT LUẬN/KẾT QUẢ, không phải nội dung nhấn mạnh thêm (khác với それに)","usage":"học viên nhầm それで (kết quả) với それに (hơn thế nữa, nhấn mạnh thêm) vì phát âm gần giống nhau","compare":"So với それに: それで = kết quả (do đó); それに = nhấn mạnh, bổ sung thêm (hơn thế nữa)\nSo với から/ので/し (lý do trong 1 câu): それで đứng đầu câu MỚI, tách nguyên nhân và kết quả thành 2 câu riêng biệt","examples":[{"jp":": ゆうべ  （夕べ）熱がありました。それで、今日学校を休みました。","vn":"(Tối qua tôi bị sốt. Do đó hôm nay tôi đã nghỉ học.)"},{"jp":"子どものとき、海でがあります。それで、海が好きになれません。","vn":"Khi còn nhỏ tôi có một kỷ niệm đáng sợ ở biển. Vì vậy tôi không thể thích biển."},{"jp":"小さい字が見えなくなりました。それで、新しい眼鏡を買いました。","vn":"Chữ nhỏ tôi dần không nhìn rõ nữa. Do đó tôi đã mua kính mới."},{"jp":"ゆうべ熱がありました。それで、今日学校を休みました。","vn":"Tối qua tôi bị sốt. Do đó hôm nay tôi đã nghỉ học."},{"jp":"子どものとき、海で怖い思い出があります。それで、海が好きになれません。","vn":"Khi còn nhỏ tôi có một kỷ niệm đáng sợ ở biển. Vì vậy tôi không thể thích biển."}]}],"29":[{"title":"自動詞・他動詞 (Tự động từ và Tha động từ)","formula":"","explain":"Tự động từ (自動詞/じどうし) diễn tả trạng thái/hành vi của sự vật, sự việc xảy ra một cách tự nhiên, KHÔNG có chủ ý tác động của ai; đi kèm trợ từ が. Tha động từ (他動詞/たどうし) diễn tả hành động CÓ chủ ý của người thực hiện, tác động trực tiếp lên một đối tượng; đi kèm trợ từ を.\nCấp độ: N4 (kiến thức nền, dùng xuyên suốt N4 → N1). Độ lịch sự: trung tính, dùng trong cả văn nói và văn viết.\nBảng ví dụ cặp tự động từ – tha động từ thường gặp:\nTự động từ (が) | Nghĩa | Tha động từ (を)\n開きます (あきます) | cửa tự mở | 開けます (あけます) | mở cửa (có chủ ý)\n閉まります (しまります) | cửa tự đóng | 閉めます (しめます) | đóng cửa\n消えます (きえます) | đèn tự tắt | 消します (けします) | tắt đèn\nつきます | đèn tự sáng | つけます | bật đèn\n出ます (でます) | chó tự chạy ra | 出します (だします) | thả/cho ra\n変わります (かわります) | lịch tự thay đổi | 変えます (かえます) | thay đổi lịch\n壊れます (こわれます) | đồ tự hỏng | 壊します (こわします) | làm hỏng đồ\n倒れます (たおれます) | cây tự đổ (do gió) | 倒します (たおします) | chặt cho cây đổ\n見つかります | tự tìm thấy/được phát hiện | 見つけます | tìm thấy (chủ động tìm)\nMẹo nhận diện nhanh (theo bài giảng gốc):\nĐộng từ có đuôi kết thúc bằng す/します hầu như luôn là THA động từ (ví dụ: 出します, 倒します, 消します).\nTrong một cặp tự động từ – tha động từ, nếu một từ thuộc nhóm 1 và từ kia thuộc nhóm 2, thì thường nhóm 1 = tự động từ, nhóm 2 = tha động từ — TRỪ khi từ nhóm 2 đó có đuôi す (khi đó ưu tiên quy tắc “đuôi す = tha động từ”, từ còn lại là tự động từ).\nDanh từ + が đứng trước động từ → động từ đó là tự động từ. Danh từ + を đứng trước động từ → động từ đó là tha động từ (danh từ đó phải là đối tượng bị tác động, không phải chỉ địa điểm).\nĐộng từ thể khả năng (khả năng làm được gì) luôn đi với trợ từ が chứ không phải を, vì đối tượng lúc này được nói tới như một chủ thể, không phải bị tác động trực tiếp — ví dụ: 新聞が読めます (báo mà tôi có thể đọc được), không nói 新聞を読めます.","usage":"/ khi nào KHÔNG dùng:\nNhầm trợ từ đi kèm: dùng を với tự động từ hoặc が với tha động từ (ví dụ nói 窓が開けます thay vì 窓を開けます).\nNhầm 出ます/出します: 出ます (tự động từ, chó tự chạy ra) khác 出します (tha động từ, chủ động thả/lấy ra).\nDanh từ chỉ địa điểm đi với が/に (ví dụ 部屋を出ます — 出る đi với を nhưng đó là trợ từ chỉ điểm xuất phát, không biến 出ます thành tha động từ) — cần phân biệt を chỉ đối tượng và を chỉ điểm rời khỏi.","compare":"","examples":[{"jp":"つきます","vn":"đèn tự sáng"},{"jp":"見つかります","vn":"tự tìm thấy/được phát hiện"},{"jp":"出します","vn":"tha động từ, chủ động thả/lấy ra"}]},{"title":"～ています (nghĩa 3: trạng thái kết quả tự nhiên)","formula":"Dạng | Công thức | Ví dụ\nKhẳng định | Vて + います | 木が倒れています (cây đang trong tình trạng đổ)\nPhủ định | Vて + いません | エアコンがついていません\nQuá khứ (đã kết thúc, hiện tại không còn) | Vて + いました | 道が混んでいました（今は違う）\nNghi vấn | Vて + いますか | 窓が開いていますか","explain":"Ngoài 2 nghĩa đã học ở N5 (hành động đang diễn ra) và Bài 27 (thói quen/nhịp sinh học), ～ています còn có nghĩa 3: diễn tả trạng thái của sự vật/sự việc đã xảy ra từ quá khứ, vẫn tiếp diễn đến hiện tại và tương lai — gọi nôm na là \"thì quá khứ hiện tại tiếp diễn\". Thường đi kèm TỰ ĐỘNG TỪ vì diễn tả sự việc xảy ra tự nhiên, không có chủ ý.","usage":"Dùng ～ています khi trạng thái vẫn còn đúng tại thời điểm nói (ví dụ: buổi tối kể lại \"đường vẫn đang tắc\" → 道が混んでいます).\nDùng ～ていました khi trạng thái đó CHỈ đúng trong quá khứ, hiện tại không còn nữa (ví dụ: buổi tối kể lại \"sáng nay đường bị tắc nhưng giờ hết rồi\" → 朝、道が混んでいました).\nLỗi phổ biến: học viên Việt Nam coi nhẹ sự khác biệt giữa ています và ていました, dùng lẫn lộn khiến người Nhật hiểu sai là sự việc còn đang xảy ra hay đã kết thúc.","compare":"～ています (nghĩa 3, thường đi với tự động từ, diễn tả trạng thái tự nhiên) khác với ～てあります (đi với tha động từ, diễn tả trạng thái do có người cố ý tác động và để nguyên kết quả đó).","examples":[{"jp":"電気がついています。","vn":"Đèn đang sáng — trạng thái tự nhiên."},{"jp":"木が倒れています。","vn":"Cây đang trong tình trạng bị đổ."},{"jp":"今朝、道が込んでいました。","vn":"Sáng nay đường đã bị tắc, nhưng giờ hết rồi."}]},{"title":"Phân biệt trợ từ で và に với động từ chỉ trạng thái/vị trí","formula":"Địa điểm + で + Vて (hành động, có chủ ý) — ví dụ: 財布をどこかで落としました (đánh rơi ví ở đâu đó — hành động làm rơi).\nĐịa điểm + に + Vて (sự tồn tại/trạng thái) — ví dụ: 財布がどこかにあります (ví đang ở đâu đó — trạng thái tồn tại).","explain":"Trợ từ で đi với động từ diễn tả HÀNH ĐỘNG xảy ra tại một địa điểm (có chủ ý thực hiện hành động ở đó). Trợ từ に đi với động từ diễn tả SỰ TỒN TẠI của một vật/sự việc tại một địa điểm (không phải hành động).","usage":"nhầm lẫn giữa で (thực hiện hành động ở một nơi) và に (có cái gì đó tồn tại ở một nơi) — đây là điểm ngữ pháp nhỏ nhưng hay xuất hiện trong đề thi N3, N2.","compare":"","examples":[{"jp":"財布をどこかで落としました。","vn":"Tôi đã đánh rơi ví ở đâu đó — hành động làm rơi."},{"jp":"財布がどこかにあります。","vn":"Ví đang ở đâu đó — trạng thái tồn tại."},{"jp":"見つかりません","vn":"tự động từ, chưa tìm ra"}]},{"title":"～てしまいました / ～てしまいます","formula":"Dạng | Công thức | Ví dụ\nKhẳng định (quá khứ) | Vて + しまいました | 宿題をやってしまいました (đã làm/lỡ làm xong bài tập)\nKhẳng định (tương lai, hoàn thành 100%) | Vて + しまいます | 明日までにやってしまいます (đến mai sẽ làm xong hết)\nRút gọn văn nói | ～ちゃいました / ～じゃいました | 忘れちゃいました (lỡ quên mất rồi)\nPhủ định | Vないで + しまいます (ít dùng, thường đổi câu) | —","explain":"diễn tả một việc đã/sẽ hoàn thành, kết thúc trọn vẹn, không còn dở dang. Thường đi kèm phó từ もう (đã) hoặc までに (đến trước khi...).; diễn tả sự bối rối, tiếc nuối, \"lỡ/chót\" làm điều gì đó không mong muốn, rơi vào tình huống khó khăn ngoài ý muốn.\nCấp độ: N4. Độ lịch sự: trung tính, phổ biến trong văn nói.","usage":"Nếu chỉ muốn nói \"đã làm\" một cách trung tính, dùng ～ました là đủ; nếu muốn nhấn mạnh đã HOÀN THÀNH TOÀN BỘ (không còn sót) thì dùng ～てしまいました. Ví dụ: 食べました (đã ăn) khác 食べてしまいました (đã ăn hết sạch — 100%).\nhọc viên Việt Nam dùng ～てしまいました khi chỉ muốn nói đơn thuần \"đã làm\" mà không phân biệt được ý \"xong hoàn toàn\" hoặc \"tiếc nuối/lỡ làm\", khiến câu bị hiểu sai sắc thái.\nKhông dùng ～てしまいました cho hành động sẽ hoàn thành trong tương lai — trường hợp đó phải chuyển sang ～てしまいます (ví dụ: 明日までに終わらせてしまいます).","compare":"～てしまいました (nghĩa 1) dễ nhầm với ～ました đơn thuần — ～てしまいました luôn hàm ý \"trọn vẹn/dứt điểm\" hoặc \"tiếc nuối\", còn ～ました chỉ đơn giản là đã xảy ra.","examples":[{"jp":"宿題をぜんぶやってしまいました。","vn":"Tôi đã làm xong hết toàn bộ bài tập rồi."},{"jp":"すみません、彼女の誕生日を忘れてしまいました。","vn":"Xin lỗi, tôi đã lỡ quên mất sinh nhật của cô ấy rồi."},{"jp":"宿題をやってしまいました","vn":"đã làm/lỡ làm xong bài tập"},{"jp":"明日までにやってしまいます","vn":"đến mai sẽ làm xong hết"},{"jp":"忘れちゃいました","vn":"lỡ quên mất rồi"}]},{"title":"見つかります (tìm thấy / được tìm thấy)","formula":"Dạng | Công thức | Ví dụ\nKhẳng định | Nが + 見つかります | 財布が見つかりました (đã tìm thấy ví rồi!)\nPhủ định | Nが + 見つかりません | 指輪がまだ見つかりません\nQuá khứ | Nが + 見つかりました | 探していた本が見つかりました\nNhấn mạnh cảm xúc | あった、あった / 見つかった、見つかった | (nói lặp lại để biểu thị vui mừng)","explain":"見つかります là tự động từ, diễn tả việc PHÁT HIỆN RA/tìm thấy được vật gì đó đang tìm, thường mang cảm xúc vui mừng của người nói. Cặp tha động từ tương ứng là 見つけます (chủ động tìm và tìm ra).","usage":"dùng あります khi thực chất muốn diễn tả \"tìm thấy\" một vật đã bị mất — あります chỉ đơn thuần diễn tả sự tồn tại, không mang sắc thái \"vừa tìm ra sau khi tìm kiếm\".","compare":"","examples":[{"jp":"財布をどこかで落として、まだ見つかりません。","vn":"Tôi đã đánh rơi ví ở đâu đó và vẫn chưa tìm thấy."},{"jp":"なくした鍵が机の下で見つかりました。","vn":"Chiếc chìa khóa bị mất đã được tìm thấy dưới gầm bàn."},{"jp":"財布が見つかりました","vn":"đã tìm thấy ví rồi!"}]}],"30":[{"title":"てあります (1) — N1 に N2 が Vてあります","formula":"Khẳng định: N1に N2が 他動詞てあります\nPhủ định: N1に N2が 他動詞てありません\nQuá khứ: N1に N2が 他動詞てありました\nNghi vấn: N1に N2が 他動詞てありますか","explain":"Ở vị trí N1 có đặt/để/treo/viết... vật N2 (miêu tả trạng thái của sự vật).\nCấp độ lịch sự: trung tính, dùng trong văn nói lẫn văn viết miêu tả.\nDiễn tả trạng thái phát sinh với tư cách là KẾT QUẢ của một hành động CÓ CHỦ Ý của ai đó. Động từ dùng là tha động từ (ngoại động từ) — động từ biểu thị chủ ý. Ví dụ: 壁に絵がかけてあります (Trên tường có treo bức tranh) — bức tranh không tự treo lên được, phải có người treo.","usage":"• Dùng khi miêu tả một cảnh vật/không gian mà người nói không phải chủ thể thực hiện hành động, chỉ quan sát kết quả.\n• KHÔNG dùng với sự việc xảy ra tự nhiên, không có ai chủ ý tác động (ví dụ cây đổ do bão) — trường hợp đó dùng Vています với tự động từ.\n• Nhầm trợ từ: dùng が cho N1 thay vì に — đúng phải là N1に N2が.\n• Dùng tự động từ (v.d. 閉まる) thay vì tha động từ (v.d. 閉める) khi chia てあります.","compare":"","examples":[{"jp":"机の上にノートが置いてあります。","vn":"Trên bàn có để cuốn vở."},{"jp":"壁に絵がかけてあります。","vn":"Trên tường có treo một bức tranh."},{"jp":"ピカソの絵は壁にかけてあります。","vn":"Bức tranh của Picasso thì được treo ở trên tường."}]},{"title":"てあります (2) — N2 は N1 に Vてあります","formula":"Khẳng định: N2は N1に 他動詞てあります\nPhủ định: N2は N1に 他動詞てありません\nQuá khứ: N2は N1に 他動詞てありました\nNghi vấn: N2は N1に 他動詞てありますか","explain":"Vật N2 (đưa lên làm chủ đề) thì được đặt/để/treo ở vị trí N1.\nCùng cấu trúc ngữ pháp てあります nhưng đảo N2 lên làm chủ đề (は) — dùng khi người nói/nghe đã có sẵn một chủ đề cụ thể muốn tập trung vào (không phải miêu tả chung chung). Ví dụ: 泥棒が「金はどこだ」と聞く → お金はベッドの下に隠してあります (Tiền thì được giấu ở dưới gầm giường) — tập trung vào chủ đề 'tiền', không miêu tả cả căn phòng.","usage":"","compare":"N1に N2が: câu văn miêu tả cảnh (giống văn tả cảnh, liệt kê những gì có trong không gian đó). N2は N1に: câu văn tập trung/nhấn mạnh vào MỘT chủ đề cụ thể mà người nói/nghe cùng quan tâm — như hỏi-đáp về một vật cụ thể (bức tranh của ai, tiền để đâu).","examples":[{"jp":"ピカソの絵は壁にかけてあります。","vn":"Bức tranh của Picasso thì được treo ở trên tường."},{"jp":"資料は机の上に置いてあります。","vn":"Tài liệu thì được để trên bàn."},{"jp":"机の上にノートが置いてあります。","vn":"Trên bàn có để cuốn vở."}]},{"title":"Phân biệt Vてあります và Vています","formula":"","explain":"","usage":"","compare":"• Vてあります: động từ đi kèm là THA ĐỘNG TỪ (tha động từ + てあります). Diễn tả trạng thái do có TÁC ĐỘNG CÓ CHỦ Ý của ai đó.\n• Vています: động từ đi kèm là TỰ ĐỘNG TỪ (tự động từ + ています). Diễn tả trạng thái xảy ra một cách TỰ NHIÊN/ngẫu nhiên, không nhấn mạnh ai gây ra.","examples":[{"jp":"てあります","vn":"tha động từ"},{"jp":"ています","vn":"tự động từ"},{"jp":"机の上にノートが置いてあります。","vn":"Trên bàn có để cuốn vở."},{"jp":"ピカソの絵は壁にかけてあります。","vn":"Bức tranh của Picasso thì được treo ở trên tường."},{"jp":"もう12時なのに、子供はまだ勉強しています。","vn":"Đã 12 giờ rồi mà đứa trẻ vẫn còn đang học."}]},{"title":"てあります — nghĩa thứ 2: đã hoàn thành/kết thúc","formula":"","explain":"Ngoài nghĩa miêu tả trạng thái, Vてあります còn mang nghĩa MỘT VIỆC ĐÃ HOÀN THÀNH, ĐÃ CHUẨN BỊ XONG — gần giống Vておきました. Đây là TỪ KHOÁ (キーワード) rất quan trọng trong phần nghe hiểu N3, N2: khi nghe thấy Vてあります nghĩa là hành động đó ĐÃ LÀM XONG rồi, không phải sắp làm.","usage":"cho luyện nghe: trong hội thoại, nếu nhân vật trả lời bằng てあります (ví dụ コピーしてあります), nghĩa là việc đó ĐÃ LÀM XONG — không được chọn đáp án 'sắp làm/đang làm' việc đó.","compare":"","examples":[{"jp":"飛行機の切符はもう買ってあります。","vn":"Vé máy bay thì tôi đã mua xong rồi."},{"jp":"宿題はもうやってあります。","vn":"Bài tập thì tôi đã làm xong rồi."},{"jp":"机の上にノートが置いてあります。","vn":"Trên bàn có để cuốn vở."},{"jp":"ピカソの絵は壁にかけてあります。","vn":"Bức tranh của Picasso thì được treo ở trên tường."}]},{"title":"ておきます (1) — làm trước một hành động","formula":"Khẳng định: Vて形 + おきます\nPhủ định: Vて形 + おきません\nQuá khứ: Vて形 + おきました\nMệnh lệnh: Vて形 + おいて／Vとけ (khẩu ngữ)\nKhuyên nhủ: Vて形 + おいたほうがいいです","explain":"Thực hiện xong một hành động/động tác nào đó trước một thời điểm/sự kiện khác sẽ diễn ra.\nĐi với động từ có ý chí (ý muốn chủ động). Ví dụ: パーティーの前に飲み物を冷蔵庫に入れておきます (Trước khi bữa tiệc diễn ra, tôi để đồ uống vào tủ lạnh trước) — hành động 'để đồ uống vào tủ lạnh' được làm TRƯỚC thời điểm bữa tiệc.","usage":"• Dùng khi nói về việc chuẩn bị trước cho một sự kiện/thời điểm sắp tới.\n• Thể khuyên nhủ Vておいたほうがいいです chỉ dùng trong hoàn cảnh THÂN THIẾT, không dùng với người mới gặp lần đầu hoặc người trên/cấp trên.\n• Nhầm với Vてあります (miêu tả trạng thái) — ておきます nhấn mạnh HÀNH ĐỘNG chuẩn bị trước, còn てあります nhấn mạnh TRẠNG THÁI kết quả.\n• Quên chia thể mệnh lệnh/khuyên nhủ khi ngữ cảnh yêu cầu lời khuyên (điểm ngữ pháp liên quan Bài 26: Vたほうがいいです).","compare":"","examples":[{"jp":"旅行の前にかばんに荷物を入れておきました。","vn":"Trước khi đi du lịch, tôi đã để đồ vào cặp trước."},{"jp":"パーティーの前に飲み物を冷蔵庫に入れておきます。","vn":"Trước khi bữa tiệc bắt đầu, tôi để đồ uống vào tủ lạnh trước."},{"jp":"てあります","vn":"miêu tả trạng thái"}]},{"title":"ておきます (2) — giữ nguyên trạng thái","formula":"Mệnh lệnh (thường dùng nhất): Vて形 + おいてください／おいて\nTrần thuật: Vて形 + おきます","explain":"Cứ để nguyên như thế / giữ nguyên hoặc duy trì một trạng thái nào đó.\nĐi với động từ ý chí, thường xuất hiện cùng そのまま (cứ như vậy). Ví dụ: ドアは開けておいてください (Hãy cứ để cửa mở như thế) hoặc rút gọn thành そのままにしておいてください / そのままで. Người Nhật hay chỉ nói ngắn gọn そのまま là đủ hiểu.","usage":"","compare":"ておきます(1): làm TRƯỚC một hành động, chuẩn bị sẵn cho việc khác. ておきます(2): GIỮ NGUYÊN một trạng thái đã có, không thay đổi gì cả. Cùng ngữ pháp nhưng ngữ cảnh và nghĩa khác nhau — cần dựa vào ngữ cảnh câu để phân biệt.","examples":[{"jp":"会議は明日なので、椅子はそのままにしておいてください。","vn":"Vì ngày mai có cuộc họp nên hãy cứ để ghế như vậy."},{"jp":"ドアは開けておいてください。","vn":"Hãy cứ để cửa mở như vậy."},{"jp":"机の上にノートが置いてあります。","vn":"Trên bàn có để cuốn vở."}]},{"title":"まだ — vẫn còn / vẫn chưa","formula":"まだ + thể khẳng định (Vています) = vẫn còn đang…\nまだ + thể phủ định (Vていません) = vẫn chưa…","explain":"Diễn tả một việc/trạng thái kéo dài liên tục, vẫn đang tiếp diễn hoặc vẫn chưa xảy ra.\nĐã học まだ ở bài trước đi với phủ định (vẫn chưa làm gì). Bài 30 bổ sung まだ đi với KHẲNG ĐỊNH (Vています) mang nghĩa 'vẫn còn đang…'. Ví dụ: 子供はもう夜中の1時半なのに、まだ勉強しています (Đã 1h30 sáng rồi mà đứa trẻ vẫn còn đang học).","usage":"","compare":"","examples":[{"jp":"もう12時なのに、子供はまだ勉強しています。","vn":"Đã 12 giờ rồi mà đứa trẻ vẫn còn đang học."},{"jp":"雨はまだ降っています。","vn":"Trời vẫn còn đang mưa."},{"jp":"宿題はまだ終わっていません。","vn":"Bài tập vẫn chưa xong."},{"jp":"雨はもう止みましたか","vn":"Trời tạnh mưa chưa?"}]},{"title":"それ — đại từ tóm tắt (đọc hiểu N3/N2)","formula":"","explain":"それ thay thế cho toàn bộ cụm/ý đứng NGAY TRƯỚC nó (thường là hết một câu, tính đến dấu chấm gần nhất phía trước).","usage":"làm bài đọc hiểu: khi đề gạch chân それ và hỏi 'それは何を指しますか' (それ chỉ cái gì), đáp án luôn nằm ở đoạn văn NGAY TRƯỚC それ (tính từ dấu chấm gần nhất), không nằm ở câu sau hay câu quá xa phía trước. Đề thi thường không lặp nguyên văn đáp án mà thay bằng từ đồng nghĩa — cần nhận diện từ đồng nghĩa để chọn đúng.","compare":"","examples":[{"jp":"地震で家が倒れています。","vn":"Nhà bị đổ do động đất."},{"jp":"机の上にノートが置いてあります。","vn":"Trên bàn có để cuốn vở."},{"jp":"ピカソの絵は壁にかけてあります。","vn":"Bức tranh của Picasso thì được treo ở trên tường."}]}],"31":[{"title":"Thể ý định (意向形 / いこうけい) — cách chia","formula":"","explain":"thể rút gọn, thông thường của ～ましょう. Dùng để rủ rê, đề nghị giúp đỡ, hoặc tự nhủ bản thân sẽ làm gì.\nCấp độ: N4  |  Độ lịch sự: thể thông thường (kết hợp với と思っています/vv. sẽ ra câu lịch sự tùy đuôi câu)\nNhóm động từ | Quy tắc chia | Ví dụ (từ điển → ý định)\nNhóm 1 (五段) | Đổi âm い→お (cột i → cột o) + う | 行く → 行こう / 頑張る → 頑張ろう / 飲む → 飲もう\nNhóm 2 (一段) | Bỏ る + よう | 見る → 見よう / 起きる → 起きよう / 食べる → 食べよう\nNhóm 3 (bất quy tắc) | する → しよう ／ 来る → 来よう | 散歩する → 散歩しよう / 来る → 来よう","usage":"thể ý định KHÔNG chia theo khẳng định/phủ định/quá khứ/nghi vấn như động từ thường — nó chỉ có 1 dạng duy nhất, dùng độc lập cuối câu hoặc làm gốc cho các mẫu câu tiếp theo (～と思っています).","compare":"","examples":[{"jp":"疲れたから、少し休もう。","vn":"Vì mệt rồi nên nghỉ một chút thôi."},{"jp":"来年、国へ帰ろうと思っています。","vn":"Tôi dự định sang năm sẽ về nước."},{"jp":"パリへ旅行に行くつもりです。","vn":"Tôi dự định đi du lịch Paris."}]},{"title":"～よう (thể ý định dùng độc lập cuối câu)","formula":"","explain":"thể thông thường tương đương ～ましょう nhưng suồng sã hơn, dùng giữa bạn bè/người thân hoặc tự nói với bản thân.\nCấp độ: N4  |  Độ lịch sự: thân mật, KHÔNG dùng với người trên/khách hàng\nRủ rê ai đó cùng làm gì: 食べよう！ (Cùng ăn thôi!)\nĐề nghị giúp đỡ (Để tôi...): 手伝おう。 (Để tớ giúp cho.)\nTự nhủ bản thân / cổ vũ: 頑張ろう！ (Cố lên nào!)","usage":"dùng ～よう với người lớn tuổi hơn/cấp trên → mất lịch sự. Nhầm âm 「よ」với 「ろ」khi chia nhóm 1 (行く phải là 行こう, không phải 行ころ).","compare":"Mẫu câu | Độ lịch sự | Đối tượng dùng\n～ましょう | Lịch sự, trung tính | Đồng nghiệp, người mới quen, giáo viên với học sinh\n～よう (thể ý định) | Thân mật, suồng sã | Bạn bè thân, người dưới, tự nói với bản thân","examples":[{"jp":"～ましょう","vn":"Lịch sự, trung tính"},{"jp":"天気がいいから、出かけようと思います。","vn":"Vì trời đẹp nên tôi định ra ngoài."},{"jp":"食べよう！","vn":"Cùng ăn thôi!"}]},{"title":"～よう と思っています (Youtei/Ý định mức thấp, ~20–25%)","formula":"Dạng | Cấu trúc | Ví dụ\nÝ định nảy sinh ngay lúc nói | Vよう + と思います | 天気がいいから、出かけようと思います。(Vì trời đẹp nên tôi định ra ngoài.)\nÝ định đã có từ trước, vẫn đang duy trì | Vよう + と思っています | 来年、国へ帰ろうと思っています。(Tôi dự định sang năm sẽ về nước.)","explain":"bày tỏ dự định còn đang nhen nhóm trong suy nghĩ, chưa chắc chắn sẽ thực hiện.\nCấp độ: N4  |  Độ lịch sự: trung tính, dùng được cả văn nói lẫn văn viết\nと思います nhấn mạnh ý định vừa nảy sinh tại thời điểm nói; と思っています nhấn mạnh ý định đã có từ trước và vẫn đang tồn tại đến hiện tại.","usage":"dự định cá nhân, mức độ chắc chắn thấp, có thể thay đổi. Khi nào KHÔNG dùng: khi kế hoạch đã chốt chắc chắn (nên dùng ～つもりです hoặc ～予定です).\nchia nhầm động từ thường thay vì thể ý định trước と思っています (VD: 食べるto思っています ❌ → 食べようと思っています ✔).","compare":"","examples":[{"jp":"天気がいいから、出かけようと思います。","vn":"Vì trời đẹp nên tôi định ra ngoài."},{"jp":"来年、国へ帰ろうと思っています。","vn":"Tôi dự định sang năm sẽ về nước."},{"jp":"たばこを吸わないつもりです。","vn":"Tôi dự định sẽ không hút thuốc."}]},{"title":"～つもりです (Tsumori — dự định cá nhân, ~80%)","formula":"Thể | Cấu trúc | Ví dụ\nKhẳng định | V(từ điển) + つもりです | パリへ旅行に行くつもりです。(Tôi dự định đi du lịch Paris.)\nPhủ định | V(ない形) + つもりです | たばこを吸わないつもりです。(Tôi dự định sẽ không hút thuốc.)\nĐặc điểm: chủ ngữ luôn là ngôi thứ nhất (tôi); nêu sự việc đã được quyết định từ trước, không phải nảy sinh tại thời điểm nói.","explain":"dự định làm hoặc không làm gì đó, mức độ chắc chắn cao hơn ～ようと思っています, đã được cá nhân quyết định từ trước.\nCấp độ: N4  |  Độ lịch sự: trung tính","usage":"dùng chủ ngữ ngôi thứ 2, 3 với つもりです (chỉ dùng cho ngôi thứ nhất khi khẳng định thông thường); chia nhầm động từ sang thể ý định thay vì giữ nguyên thể từ điển/ない形.","compare":"không có sự khác biệt lớn về nghĩa, nhưng khi muốn diễn đạt một quyết định dứt khoát/chắc chắn hơn thì dùng ～つもりです (động từ thể từ điển/ない形, KHÔNG chia thể ý định).","examples":[{"jp":"パリへ旅行に行くつもりです。","vn":"Tôi dự định đi du lịch Paris."},{"jp":"たばこを吸わないつもりです。","vn":"Tôi dự định sẽ không hút thuốc."},{"jp":"つもりです","vn":"chỉ dùng cho ngôi thứ nhất khi khẳng định thông thường"}]},{"title":"～予定です (Yotei — kế hoạch, ~99%)","formula":"V(từ điển) + 予定です  ／  N + の予定です\nVí dụ | Dịch nghĩa\n会議は10時に始まる予定です。 | Buổi họp dự kiến bắt đầu lúc 10 giờ (theo kế hoạch).\n3月10日にアメリカへ出張する予定です。 | Ngày 10/3 tôi có kế hoạch đi công tác ở Mỹ.\n来年から会社はたばこを禁止する予定です。 | Từ năm sau công ty có kế hoạch cấm hút thuốc.","explain":"kế hoạch đã được quyết định chắc chắn, thường là do tổ chức/công ty/lịch trình quyết định, hoặc kế hoạch cá nhân đã chốt.\nCấp độ: N4  |  Độ lịch sự: trung tính, thường dùng trong ngữ cảnh công việc/lịch trình chính thức","usage":"lịch trình/kế hoạch đã lên giấy tờ hoặc đã được tổ chức quyết định chính thức. Khi nào KHÔNG dùng: dự định cá nhân còn mơ hồ, chưa chốt (dùng ～ようと思っています hoặc ～つもりです).\nnhầm lẫn dùng 予定です cho một dự định còn chưa chắc chắn, khiến người nghe hiểu sai mức độ cam kết.","compare":"Mẫu câu | Mức độ chắc chắn | Chủ ngữ | Tính chất\n～ようと思っています | ~20–25% | Ngôi 1 | Ý định cá nhân, còn nhen nhóm\n～つもりです | ~80% | Ngôi 1 | Quyết định cá nhân, khá chắc chắn\n～予定です | ~99% | Ngôi 1 hoặc tổ chức/công ty | Kế hoạch đã chốt, có lịch trình cụ thể","examples":[{"jp":"会議は10時に始まる予定です。","vn":"Buổi họp dự kiến bắt đầu lúc 10 giờ (theo kế hoạch)."},{"jp":"月10日にアメリカへ出張する予定です。","vn":"Ngày 10/3 tôi có kế hoạch đi công tác ở Mỹ."},{"jp":"来年から会社はたばこを禁止する予定です。","vn":"Từ năm sau công ty có kế hoạch cấm hút thuốc."}]},{"title":"～まだ～ていません (Vẫn chưa)","formula":"まだ + V(て形) + いません\nVí dụ | Dịch nghĩa\nまだ、レポートを書いていません。 | Tôi vẫn chưa viết xong báo cáo.\n今朝、寝坊したので、まだ朝ごはんを食べていません。 | Sáng nay tôi ngủ quên nên vẫn chưa ăn sáng.","explain":"diễn tả một việc dự định làm nhưng đến thời điểm nói vẫn chưa thực hiện xong/chưa hoàn thành.\nCấp độ: N4  |  Độ lịch sự: trung tính","usage":"nhầm ～ています và ～ていません; quên trợ từ まだ ở đầu câu khiến câu mất sắc thái nhấn mạnh 'vẫn chưa'.","compare":"～ています (vẫn còn/đang) khác với ～ていません (vẫn chưa) — hai cấu trúc trái nghĩa nhau, học viên dễ nhầm.","examples":[{"jp":"まだ、レポートを書いていません。","vn":"Tôi vẫn chưa viết xong báo cáo."},{"jp":"今朝、寝坊したので、まだ朝ごはんを食べていません。","vn":"Sáng nay tôi ngủ quên nên vẫn chưa ăn sáng."},{"jp":"ています","vn":"vẫn còn/đang"}]}],"32":[{"title":"～ほうがいい (nên / không nên làm gì)","formula":"Dạng | Cấu trúc\nKhẳng định (nên làm) | V thể た + ほうがいい\nPhủ định (không nên làm) | V thể ない + ほうがいい (chỉ chia được ở dạng ない, không dùng V ます)\nQuá khứ | Bản thân ほうがいい là lời khuyên cho hiện tại/tương lai, không có dạng quá khứ riêng — thời điểm hành động được khuyên nằm ở thì của động từ đứng trước (た/ない)\nNghi vấn | Ít dùng dạng hỏi trực tiếp; thường dùng nguyên câu trần thuật để khuyên, có thể thêm よ cuối câu để nhấn mạnh","explain":"đưa ra lời khuyên, lời tư vấn cho người nghe — \"nên làm...\" hoặc \"không nên làm...\".\nCấp độ: N4\nĐộ lịch sự: trung tính — dùng thân mật giữa bạn bè, người thân, người dưới tuổi mình. KHÔNG dùng với người trên hoặc người mới gặp lần đầu (vì mang sắc thái \"kẻ cả\", bề trên).\nNgười nói cho rằng việc đó là tốt và chủ động góp ý/khuyên nhủ người nghe làm theo.\nThường đi kèm trợ từ cuối câu よ để tăng sắc thái nhắc nhở, ví dụ: たばこを吸わないほうがいいよ（không nên hút thuốc đâu）","usage":"Dùng: khuyên bạn bè, người thân, người ít tuổi hơn (ví dụ: nên uống nhiều nước, nên đi ngủ sớm, nên học chăm chỉ).\nKHÔNG dùng: với cấp trên, người lớn tuổi hơn, hoặc người mới gặp lần đầu — vì nghe rất kẻ cả, thất lễ.\ncủa người Việt: nhầm rằng ほうがいい là mẫu câu \"an toàn\" dùng được cho mọi đối tượng như trong tiếng Việt (\"anh nên...\"). Thực tế người Nhật chỉ dùng với người ngang hàng/dưới, nếu nói với sếp hoặc người lớn tuổi sẽ bị đánh giá là bất lịch sự.\nPhủ định chỉ chia được từ V ない (không dùng V thể ます + ほうがいい).","compare":"べきです (N3): cũng mang nghĩa \"nên\" nhưng mang tính nghĩa vụ/đạo lý mạnh hơn, có thể dùng khi góp ý người trên nếu chia ở thể た + ほうがよかったです hoặc đổi hẳn sang べきです; tuy nhiên theo transcript, giáo viên nhấn mạnh ほうがいい tuyệt đối không dùng với người trên, khác với べきです có thể linh hoạt hơn trong một số ngữ cảnh trang trọng.","examples":[{"jp":"子供の前でひどいことを言わないほうがいいです。","vn":"Không nên nói những điều khó nghe trước mặt trẻ con."},{"jp":"インターネットで知り合った人には気をつけたほうがいいですよ。","vn":"Nên cẩn thận với người quen qua mạng đấy."},{"jp":"まじめに勉強したほうがいいです。しないと成績が悪くなるでしょう。","vn":"Nên học hành nghiêm chỉnh. Nếu không, thành tích sẽ xấu đi đấy."}]},{"title":"～でしょう và ～かもしれない (có lẽ / có thể là)","formula":"Cấu trúc | Cách chia\nでしょう | V/Adj-i thể thông thường + でしょう; Adj-na/N bỏ だ + でしょう\nかもしれない | V/Adj-i thể thông thường + かもしれない; Adj-na/N bỏ だ + かもしれない","explain":"chung: thể hiện sự suy đoán, phán đoán của người nói dựa trên thông tin đã có. Khác nhau ở MỨC ĐỘ CHẮC CHẮN.\nCấp độ: N4\nでしょう: mức độ tin sự việc là sự thật CAO hơn — người nói phán đoán dựa trên thông tin, số liệu cụ thể (ví dụ: dự báo thời tiết dựa trên số liệu khí tượng). Đọc phải hạ giọng cuối câu (khác với lên giọng でしょう？ mang nghĩa \"phải không?\", mong người nghe đồng tình).\nかもしれない: mức độ chắc chắn THẤP hơn — sự việc có ít khả năng xảy ra nhưng vẫn có thể. Trong văn nói thân mật thường rút gọn thành かも hoặc かもね; đôi khi lược bớt しれない thành かも.\nNghi vấn: でしょうか dùng để hỏi về sự phán đoán, suy xét của người nghe một cách lịch sự (thay vì hỏi trực tiếp bằng ですか).\nCả hai thường đi kèm たぶん hoặc きっと ở đầu câu để câu văn tự nhiên, mềm mại hơn; きっと nhấn mạnh xác suất cao hơn khi dùng với でしょう.","usage":"Dùng でしょう khi có căn cứ/thông tin rõ ràng để phán đoán (dự báo thời tiết, thành tích học tập...).\nDùng かもしれない khi chỉ là suy đoán cá nhân, ít căn cứ, xác suất thấp (khoảng 20–25%).\nngười học Việt Nam hay dùng lẫn lộn hai mẫu này vì cả hai đều dịch là \"có lẽ\"; cần nhớ でしょう chắc chắn hơn かもしれない (giáo viên ví: でしょう ~80%, かもしれない ~20-25%).\nLỗi ngữ điệu: でしょう lên giọng cuối câu sẽ đổi nghĩa thành hỏi xác nhận/mong đồng tình — người mới học dễ đọc sai ngữ điệu dẫn đến hiểu nhầm.","compare":"でしょう vs かもしれない: cùng nhóm suy đoán nhưng khác thang độ chắc chắn — でしょう cao, かもしれない thấp.\nでしょう (hạ giọng, suy đoán) vs でしょう？ (lên giọng, xác nhận/mong đồng tình) — cùng chữ nhưng khác hoàn toàn về chức năng, chỉ phân biệt qua ngữ điệu.","examples":[{"jp":"まじめに勉強したほうがいいです。しないと成績が悪くなるでしょう。","vn":"Nên học hành nghiêm chỉnh. Nếu không, thành tích sẽ xấu đi đấy."},{"jp":"天気予報によると、明日は雨が降るでしょう。","vn":"Theo dự báo thời tiết, ngày mai có lẽ trời sẽ mưa."},{"jp":"でしょう","vn":"hạ giọng, suy đoán"}]},{"title":"Lượng từ + で (mức độ cần thiết về thời gian/tiền bạc/số lượng)","formula":"Cấu trúc | Ví dụ\nLượng từ (thời gian/tiền/số lượng) + で | 30分で駅に着きます／5万円でこの電話が買えます","explain":"trợ từ で đứng sau lượng từ chỉ thời gian, tiền bạc, số lượng — biểu thị mức độ/giới hạn cần thiết để một hành động/trạng thái diễn ra.\nCấp độ: N4 (không phải mẫu câu ngữ pháp riêng mà là cách dùng trợ từ で với lượng từ)","usage":"Dùng khi muốn nói \"với mức độ X (thời gian/tiền/số lượng) thì có thể làm được Y\".\nngười học hay bỏ quên trợ từ で sau lượng từ, khiến câu thiếu tự nhiên hoặc tối nghĩa về mức độ giới hạn.","compare":"","examples":[{"jp":"これはお客さんの忘れ物かもしれません。","vn":"Cái này có thể là đồ khách để quên."},{"jp":"道が混んでいるから、間に合わないかもしれません。","vn":"Vì đường đang tắc nên có thể sẽ không kịp."},{"jp":"この電話は5万円で買えます。","vn":"Với 5 man thì có thể mua được cái điện thoại này."}]}],"33":[{"title":"動詞（命令形）— Thể mệnh lệnh","formula":"Nhóm | Quy tắc | Ví dụ\nNhóm I | Đổi đuôi い（i）→ え（e） | 書きます → 書け (hãy viết)\n待ちます → 待て (hãy đợi)\n飲みます → 飲め (hãy uống)\nNhóm II | Bỏ ます, thêm ろ | 食べます → 食べろ (hãy ăn)\n起きます → 起きろ (hãy dậy)\n寝ます → 寝ろ (hãy ngủ)\nNhóm III | Bất quy tắc | します → しろ (hãy làm)\n来ます → 来い (hãy đến)\nDạng | Ghi chú\nKhẳng định | 食べろ！ (Ăn đi!) — chính là thể mệnh lệnh\nPhủ định (cấm chỉ) | Không chia tiếp từ mệnh lệnh — dùng thể cấm chỉ riêng (xem mục 2.2): 食べるな (Cấm ăn)\nQuá khứ | Thể mệnh lệnh không có dạng quá khứ — bản chất là khẩu lệnh tức thời, không dùng để thuật lại\nNghi vấn | Không dùng dạng nghi vấn — mệnh lệnh không phải câu hỏi","explain":"Yêu cầu/ra lệnh cho người nghe BẮT BUỘC phải thực hiện một hành động. Mang sắc thái mạnh, áp đặt — gần giống\nV-なさい nhưng mạnh và trực tiếp hơn nhiều.\nCấp độ: N4–N3 (ứng dụng nhiều ở N3/N2 khi đọc hiểu, hội thoại đời sống)\nĐộ lịch sự: Rất thấp — gần như không lịch sự, chỉ dùng trong phạm vi hạn chế (xem mục cách dùng).\nCó thể thêm trợ từ\nよ vào cuối câu (giữa nam giới nói chuyện với nhau) để làm mềm sắc thái, ví dụ 黙れよ (Im mồm đi mà — bớt gay gắt hơn 黙れ trơn). Chỉ dùng thêm khi thân mật, không dùng với người trên.\nChú ý ngữ pháp: Động từ không biểu thị ý chí chủ động (VD: わかります, できます) KHÔNG có thể mệnh lệnh.","usage":"Người trên (bố mẹ, cấp trên, lớn tuổi) nói với người dưới hoặc con cái\nNam giới nói chuyện thân mật với nhau (phim ảnh, xã hội đen, quân đội)\nTình huống khẩn cấp (hỏa hoạn, động đất) — chỉ nam giới/người lớn tuổi hô\nKhẩu hiệu luyện tập thể thao/quân sự — cả nam và nữ đều dùng được\nCổ vũ thể thao — nam nữ dùng chung, VD: 頑張れ (Cố lên!)\nBiển báo giao thông, cảnh báo nguy hiểm — ưu tiên ngắn gọn, VD: 止まれ (Dừng lại)\nKHÔNG dùng: người dưới nói với người trên (rất bất lịch sự, có thể mất việc); nữ giới nói chuyện thông thường (trừ khẩu lệnh/cổ vũ)\nNhầm sắc thái — dùng thể mệnh lệnh với cấp trên/người lạ, gây mất lịch sự nghiêm trọng\nNhầm mặt chữ chia: ちます → nhầm thành ちろ thay vì て (VD: 立ちます → 立て, không phải 立ちろ)\nNhầm giữa thể mệnh lệnh và V-なさい (nasai) — なさい nhẹ nhàng hơn, mẹ/giáo viên dùng với con/học sinh; thể mệnh lệnh nặng và áp đặt hơn nhiều","compare":"V-なさい:\ncũng là ra lệnh nhưng nhẹ nhàng hơn, mẹ nói với con / thầy cô nói với học sinh đều dùng được, VD: 寝なさい (đi ngủ đi) so với 寝ろ (ngủ đi! – gắt hơn)\nVて形 + ください:\nlịch sự, nhờ vả — dùng được với mọi đối tượng, ngược hẳn sắc thái với thể mệnh lệnh","examples":[{"jp":"早く寝ろ！","vn":"Ngủ sớm đi! (bố mệnh lệnh con)"},{"jp":"ここに入るな。","vn":"Cấm vào chỗ này."},{"jp":"「無料」は、お金を払わなくてもいいという意味です。","vn":"\"Miễn phí\" nghĩa là không cần trả tiền."}]},{"title":"動詞（禁止形）— Thể cấm chỉ","formula":"Thể từ điển (辞書形) + な — áp dụng chung cho cả 3 nhóm động từ, không phân biệt nhóm.\n諦めます → thể từ điển 諦める → 諦めるな (Cấm bỏ cuộc)\n話します → 話すな (Cấm nói)\n食べます → 食べるな (Cấm ăn)\n飲みます → 飲むな (Cấm uống)\n入ります → 入るな (Cấm vào)\n触ります → 触るな (Cấm sờ)","explain":"Yêu cầu người nghe TUYỆT ĐỐI KHÔNG được thực hiện hành động nào đó — ngược lại với thể mệnh lệnh.\nCấp độ: N4–N3\nĐộ lịch sự: Rất thấp, mang tính đe dọa/áp đặt mạnh — mạnh hơn cả V-ないでください.","usage":"Giống hệt phạm vi dùng của thể mệnh lệnh (mục 2.1): người trên với người dưới, nam giới thân mật, khẩn cấp, biển cấm/cảnh báo\nBiển báo thường gặp: 立入禁止 (Cấm vào), 遊泳禁止 (Cấm bơi — nguy hiểm), 禁煙 (Cấm hút thuốc), 触るな (Cấm sờ)\nKHÔNG dùng với người trên hoặc trong giao tiếp lịch sự thông thường\nDùng nhầm với V-ないでください (thể lịch sự) trong hội thoại trang trọng — thể cấm chỉ quá gắt, dễ gây hiểu lầm là đang quát mắng\nQuên rằng thể cấm chỉ dùng THỂ TỪ ĐIỂN (không phải thể ます hay thể て)","compare":"Vないでください: lịch sự, dùng phổ biến trong giao tiếp hằng ngày với mọi đối tượng\nVてはいけません: trang trọng, dùng trong quy định/nội quy, không mang sắc thái đe dọa cá nhân như thể cấm chỉ","examples":[{"jp":"ないでください","vn":"thể lịch sự"},{"jp":"Vないでください","vn":"lịch sự, dùng phổ biến trong giao tiếp hằng ngày với mọi đối tượng"},{"jp":"Vてはいけません","vn":"trang trọng, dùng trong quy định/nội quy, không mang sắc thái đe dọa cá nhân như thể cấm chỉ"}]},{"title":"～という意味です — Giải thích ý nghĩa của một từ/ký hiệu","formula":"A は B という意味です  (A nghĩa là B)\nDanh từ/cụm từ + という意味です\nDạng | Công thức | Ví dụ\nKhẳng định | 〜という意味です | 「無料」は、お金を払わなくてもいいという意味です。 (\"Miễn phí\" nghĩa là không cần trả tiền)\nPhủ định | 〜という意味ではありません | それはそういう意味ではありません。 (Không phải nghĩa đó)\nQuá khứ | 〜という意味でした | (hiếm dùng — ý nghĩa từ vựng thường không đổi theo thời gian)\nNghi vấn | 〜はどういう意味ですか | これはどういう意味ですか。 (Cái này nghĩa là gì?)","explain":"\"... có nghĩa là ...\" — dùng khi giải thích nghĩa của một từ, ký hiệu, biển báo.\nCấp độ: N4\nĐộ lịch sự: Trung tính, dùng được trong văn nói lẫn văn viết.","usage":"Quy tắc dịch: dịch CHỦ NGỮ trước → dịch という意味です ('có nghĩa là') → sau đó mới dịch phần nội dung nghĩa nằm phía trước nó trong câu\n本日休業 は 今日は仕事をしないという意味です → \"Bản nhật hưu nghiệp\" nghĩa là hôm nay không làm việc\nDịch xuôi theo trật tự từ tiếng Nhật khiến câu tiếng Việt bị ngược nghĩa hoặc tối nghĩa\nNhầm với 〜という đơn thuần (trích dẫn danh xưng, VD: 田中という人 - người tên là Tanaka) — không mang nghĩa giải thích","compare":"","examples":[{"jp":"無料」は、お金を払わなくてもいいという意味です。","vn":"\"Miễn phí\" nghĩa là không cần trả tiền"},{"jp":"それはそういう意味ではありません。","vn":"Không phải nghĩa đó"},{"jp":"これはどういう意味ですか。","vn":"Cái này nghĩa là gì?"}]},{"title":"～と伝えていただけませんか — Nhờ truyền đạt lịch sự","formula":"[Người nhận] に「[nội dung]」と伝えていただけませんか  (Anh/chị có thể nhắn với [người nhận] rằng \"[nội dung]\" được không?)\nDạng | Công thức | Ví dụ\nKhẳng định (lịch sự cao) | 〜と伝えていただけませんか | リーさんに、好きだと伝えていただけませんか。 (Anh có thể nhắn với Ly là tôi thích cô ấy được không?)\nKhẳng định (thân mật) | 〜と伝えてくれない? | リーさんに伝えてくれない？ (Nhắn giúp Ly được không?)\nPhủ định lịch sự | 〜と伝えていただけますか | dạng khẳng định câu hỏi, lịch sự nhẹ hơn 少し —dùng khi quan hệ gần hơn\nQuá khứ | 〜と伝えていただけませんでしたか | hỏi lại xem đã nhắn hộ chưa (ít dùng, ngữ cảnh đặc biệt)\nNghi vấn (cấu trúc gốc) | 〜と伝えていただけませんか | bản thân cấu trúc đã ở dạng nghi vấn nhờ vả lịch sự\nNgười TIẾP NHẬN lời nhắn luôn đi với trợ từ に (không phải と)\nNội dung cần truyền đạt đặt trước と, chia ở thể thông thường (thể từ điển/ た/ ない...)","explain":"\"Anh/chị có thể truyền đạt/nhắn giúp tôi rằng... được không ạ?\" — nhờ một người trung gian chuyển lời đến người thứ ba.\nCấp độ: N4–N3\nĐộ lịch sự: Cao — dùng\n〜ていただけませんか (thể khiêm nhường + nghi vấn phủ định), phù hợp giao tiếp trang trọng, công sở.","usage":"Dùng khi nhờ ai đó chuyển lời một cách trang trọng, lịch sự (nhờ đồng nghiệp, nhân viên, người quen chuyển lời tới người thứ ba)\nKHÔNG dùng khi nói chuyện trực tiếp với chính người nhận thông tin (lúc đó không cần \"truyền đạt\")\nNhầm trợ từ đối tượng tiếp nhận — dùng と thay vì に\nNhầm giữa việc \"nhờ nhắn hộ\" (と伝えていただけませんか) và \"tường thuật lại điều đã nghe\" (と言っていました, mục 2.5) — bản chất khác chiều","compare":"〜と言っていました: tường thuật lại điều NGƯỜI KHÁC đã nói (chiều nhận thông tin), khác với 〜と伝えていただけませんか là NHỜ chuyển lời (chiều gửi thông tin)","examples":[{"jp":"リーさんに、好きだと伝えていただけませんか。","vn":"Anh có thể nhắn với Ly là tôi thích cô ấy được không?"},{"jp":"リーさんに伝えてくれない？","vn":"Nhắn giúp Ly được không?"},{"jp":"〜と伝えていただけませんでしたか","vn":"hỏi lại xem đã nhắn hộ chưa (ít dùng, ngữ cảnh đặc biệt)"},{"jp":"〜と伝えていただけませんか","vn":"bản thân cấu trúc đã ở dạng nghi vấn nhờ vả lịch sự"},{"jp":"課長に、あしたの会議は6時から始まると伝えていただけませんか。","vn":"Anh có thể nhắn với trưởng phòng là cuộc họp ngày mai bắt đầu từ 6 giờ được không?"}]},{"title":"～と言っていました — Tường thuật lại lời nói","formula":"[Người nói] は「[nội dung — thể thông thường]」と言っていました  ([Người nói] đã nói rằng [nội dung])\nDạng | Công thức | Ví dụ\nKhẳng định | 〜と言っていました | 南さんはリーさんが好きだと言っていました。 (Nam đã nói là thích Ly)\nPhủ định (nội dung) | 〜ないと言っていました | あしたは来ないと言っていました。 (Anh ấy nói ngày mai sẽ không đến)\nQuá khứ (nội dung) | 〜たと言っていました | レポートの締め切りに間に合わないと言っていました。 (Nói là sẽ không kịp hạn báo cáo)\nNghi vấn | 〜と言っていましたか | 先生は何と言っていましたか。 (Thầy giáo đã nói gì?)\nChủ ngữ của câu luôn là NGƯỜI ĐÃ NÓI câu đó (không phải người nghe lại)\nNội dung trước と chia ở thể thông thường (thường/ ない/ た/ だ tuỳ loại từ)","explain":"\"... đã nói rằng ...\" — thuật lại nguyên văn nội dung mà một người khác đã nói, cho một người thứ ba nghe.\nCấp độ: N4–N3\nĐộ lịch sự: Trung tính, dùng phổ biến trong hội thoại và văn viết.","usage":"Dùng khi thuật lại lời của người khác cho người thứ ba nghe (gián tiếp)\nKHÔNG dùng để tự thuật lại lời của chính mình đang nói trực tiếp\nNhầm chủ ngữ — để người NGHE lại làm chủ ngữ thay vì người NÓI gốc\nQuên chia nội dung câu trích dẫn về thể thông thường trước と","compare":"〜と伝えていただけませんか (mục 2.4): nhờ CHUYỂN lời đi, còn 〜と言っていました là THUẬT LẠI lời đã nghe được — hai chiều thông tin ngược nhau","examples":[{"jp":"南さんはリーさんが好きだと言っていました。","vn":"Nam đã nói là thích Ly"},{"jp":"あしたは来ないと言っていました。","vn":"Anh ấy nói ngày mai sẽ không đến"},{"jp":"レポートの締め切りに間に合わないと言っていました。","vn":"Nói là sẽ không kịp hạn báo cáo"},{"jp":"先生は何と言っていましたか。","vn":"Thầy giáo đã nói gì?"},{"jp":"天気予報によると、あしたは天気がいいと言っていました。","vn":"Theo dự báo thời tiết, người ta nói là ngày mai trời đẹp."}]}],"34":[{"title":"Vる/Vた/Nの + とおりに — \"Theo như...\"","formula":"Dạng | Công thức | Ví dụ\nKhẳng định | Vる/Vた/Nの + とおりに + V2 | 説明書のとおりに組み立てます。\nPhủ định | V2 phủ định (vế とおりに giữ nguyên) | 説明書のとおりに組み立てません。\nQuá khứ | V2 chia quá khứ | 先生が読んだとおりに読みました。\nNghi vấn | …とおりにV2か | これは図のとおりに並べましたか。","explain":"thực hiện hành động vế sau (V2) đúng theo hành động/quy tắc/hình mẫu ở vế trước (V1). Cấp độ: N4. Độ lịch sự: trung tính, dùng được cả văn nói lẫn văn viết, thường xuất hiện trong câu chỉ thị/hướng dẫn.\nVế trước とおりに là \"hình mẫu/chuẩn mực\" (lời nói, chữ viết, bản vẽ, hướng dẫn...); vế sau là hành động làm theo đúng hình mẫu đó.\nDanh từ + の + とおりに (VD: 図のとおりに); Động từ thể từ điển hoặc thể た + とおりに (VD: 言うとおりに、言ったとおりに).","usage":"Dùng khi đưa ra chỉ thị, hướng dẫn, muốn người nghe làm đúng theo một chuẩn mực có sẵn (bản vẽ, lời dặn, văn bản).\nhọc viên Việt Nam hay quên nối との bằng の khi danh từ đứng trước (nói nhầm 図とおりに thay vì 図のとおりに).\nnhầm lẫn thứ tự dịch — phải dịch từ vế sau (V2) lên vế trước (V1) mới đúng nghĩa tiếng Việt.","compare":"","examples":[{"jp":"先生が読んだとおりに読んでください。","vn":"Dịch: Hãy đọc theo đúng như những gì thầy/cô đã đọc."},{"jp":"切手を貼って、手紙を出してください。","vn":"Dịch: Hãy dán tem rồi gửi thư."},{"jp":"映画を見たあとで、彼女と海を見に行きました。","vn":"Dịch: Sau khi xem phim xong, tôi đã cùng cô ấy đi ngắm biển."}]},{"title":"V-た/Nの + あとで — \"Sau khi...\"","formula":"Dạng | Công thức | Ví dụ\nKhẳng định | Vた/Nの + あとで + V2 | 映画を見たあとで、食事に行きます。\nPhủ định | V2 phủ định | 映画を見たあとで、食事に行きません。\nQuá khứ | V2 chia quá khứ | 映画を見たあとで、食事に行きました。\nNghi vấn | …あとで、V2か | 映画を見たあとで、食事に行きますか。","explain":"hành động V2 xảy ra sau khi hành động V1 đã kết thúc. Cấp độ: N4. Độ lịch sự: trung tính.\nChỉ đơn thuần diễn tả V1 xảy ra trước, V2 xảy ra sau — không nhấn mạnh thứ tự chặt chẽ, không nhấn mạnh khoảng thời gian trôi qua.","usage":"KHÔNG dùng あとで trong câu cần nhấn mạnh thứ tự các bước nghiêm ngặt (quy trình) — trường hợp đó nên dùng てから.\ndùng V thể từ điển + あとで (đúng phải là V thể た + あとで).","compare":"てから nhấn mạnh trình tự trước–sau rõ ràng và/hoặc sự trôi qua của thời gian giữa hai hành động; あとで chỉ nói đơn giản \"sau khi V1 thì V2\".\nあとで vs てから: あとで = \"sau khi\" trung tính; てから = \"sau khi...(rồi mới)\", nhấn mạnh trình tự/khoảng thời gian trôi qua.","examples":[{"jp":"映画を見たあとで、彼女と海を見に行きました。","vn":"Dịch: Sau khi xem phim xong, tôi đã cùng cô ấy đi ngắm biển."},{"jp":"先生が読んだとおりに読んでください。","vn":"Dịch: Hãy đọc theo đúng như những gì thầy/cô đã đọc."},{"jp":"切手を貼って、手紙を出してください。","vn":"Dịch: Hãy dán tem rồi gửi thư."}]},{"title":"V1て/V1ないで + V2 — \"Làm/không làm V1 rồi thực hiện V2\"","formula":"Dạng | Công thức | Ví dụ\nKhẳng định (làm V1 rồi V2) | V1て + V2 | 切手を貼って、手紙を出します。\nPhủ định (không làm V1 mà V2) | V1ないで + V2 | 切手を貼らないで、手紙を出しました。\nQuá khứ | V2 chia quá khứ | 眼鏡をかけて、本を読みました。\nNghi vấn | …て/ないで、V2か | 傘を持たないで、学校へ行きましたか。","explain":"V1 diễn tả động tác/trạng thái đi kèm hoặc xảy ra trước, làm nền cho V2. Cấp độ: N4 (thường gặp nhiều ở N3/N2). Độ lịch sự: trung tính.\nV1て+V2: V1 là động tác thực hiện trước, tạo trạng thái nền cho V2 (dán tem RỒI gửi thư; đeo kính RỒI đọc sách).\nV1ないで+V2: quên/không thực hiện V1 nhưng vẫn thực hiện V2 (quên dán tem mà vẫn gửi thư; không đeo kính mà vẫn đọc sách).","usage":"Dùng khi muốn thể hiện trạng thái/động tác đi kèm theo hành động chính, không nhấn mạnh trình tự nghiêm ngặt như てから.\nchia nhầm ないで thành なくて trong cấu trúc này (なくて mang nghĩa nguyên nhân, không phù hợp ở đây).","compare":"","examples":[{"jp":"切手を貼らないで、手紙を出してしまいました。","vn":"Dịch: Tôi đã nhỡ gửi thư đi mà quên không dán tem."},{"jp":"日曜日はどこへも行かないで、家で休みました。","vn":"Dịch: Chủ nhật tôi đã không đi đâu cả mà ở nhà nghỉ ngơi."},{"jp":"日本語能力試験があるので、友達と遊びに行かないで、家で日本語を勉強します。","vn":"Dịch: Vì sắp có kỳ thi năng lực tiếng Nhật nên tôi không đi chơi với bạn mà ở nhà học tiếng Nhật."}]},{"title":"V1ないで + V2 — \"Không làm V1 mà làm V2\" (lựa chọn loại trừ)","formula":"Dạng | Công thức | Ví dụ\nKhẳng định | V1ないで + V2 | 日曜日はどこへも行かないで、家で休みました。\nĐảo chiều lựa chọn | V2ないで + V1 | 家で休まないで、遊びに行きました。\nQuá khứ | V2 chia quá khứ | 大学に行かないで、日本へ留学しました。\nNghi vấn | …ないで、V2か | 遊びに行かないで、勉強しますか。","explain":"giữa hai việc không thể làm đồng thời, người nói chọn thực hiện V2 và không thực hiện V1. Cấp độ: N4 (xuất hiện cả trong đề N3). Độ lịch sự: trung tính.\nKhác với mục 2.3 ở bản chất: đây là hai LỰA CHỌN loại trừ nhau (chỉ chọn một trong hai), không phải \"trạng thái đi kèm\".\nThường dùng để diễn tả sự quyết tâm, ưu tiên: bỏ qua việc A để làm việc B.","usage":"Dùng khi hai hành động thực sự loại trừ nhau (không thể làm cùng lúc), ví dụ: đi chơi và ở nhà học.\nnhầm lẫn giữa mục 2.3 (trạng thái đi kèm) và mục 2.4 (lựa chọn loại trừ) vì cấu trúc bề mặt giống nhau (V1ないで+V2) — cần dựa vào ngữ cảnh để phân biệt.","compare":"","examples":[{"jp":"切手を貼らないで、手紙を出してしまいました。","vn":"Dịch: Tôi đã nhỡ gửi thư đi mà quên không dán tem."},{"jp":"日曜日はどこへも行かないで、家で休みました。","vn":"Dịch: Chủ nhật tôi đã không đi đâu cả mà ở nhà nghỉ ngơi."},{"jp":"日本語能力試験があるので、友達と遊びに行かないで、家で日本語を勉強します。","vn":"Dịch: Vì sắp có kỳ thi năng lực tiếng Nhật nên tôi không đi chơi với bạn mà ở nhà học tiếng Nhật."}]}],"35":[{"title":"Thể điều kiện ば (条件形)","formula":"chia thể điều kiện:\nLoại từ | Quy tắc chia | Ví dụ (từ điển → ば形)\nĐộng từ nhóm 1 | Đuôi い → え + ば | 会います(gặp) → 会えば / 飲みます(uống) → 飲めば\nĐộng từ nhóm 2 | Bỏ ます, thêm れば | 食べます(ăn) → 食べれば / 見ます(xem) → 見れば\nĐộng từ nhóm 3 | します → すれば / 来ます → 来れば | 勉強します → 勉強すれば\nTính từ đuôi い | Bỏ い, thêm ければ | 高い(đắt) → 高ければ / 忙しい → 忙しければ\nTính từ đuôi な | Bỏ な, thêm なら(ば) | きれい(な) → きれいなら / 好き(な) → 好きなら\nDanh từ | Danh từ + なら(ば) | 私 → 私なら / 学生 → 学生なら","explain":"\"Nếu... (thì)...\" — diễn tả điều kiện giả định hoặc điều kiện cần thiết để một sự việc xảy ra.\nCấp độ: N4 · Độ lịch sự: trung tính, dùng được cả văn nói lẫn văn viết.","usage":"đặc biệt: いい/よい (tốt) → いければ；ない (không có) → なければ (rất hay dùng: ～なければ).\nCách dùng 1 — Điều kiện cần thiết:\nDiễn tả điều kiện cần thiết để một sự việc khác xảy ra, đóng vai trò như \"chất xúc tác\".\nこのボタンを押せば、水が流れます。  (Nếu bấm nút này thì nước sẽ chảy ra.)\n説明書を読めば、使い方がわかります。  (Nếu đọc sách hướng dẫn thì sẽ hiểu cách dùng.)\nCách dùng 2 — Quyết định của người nói:\nBiểu thị quyết định của người nói trong một tình huống nhất định, hoặc phản ứng lại điều người nghe vừa nói.\nそんなに言うなら、別れましょう。  (Nếu em đã nói vậy thì chia tay đi.) — lưu ý câu này thực tế dùng なら vì thể hiện ý chí + chủ ngữ trùng.\nほかに意見がなければ、これで終わります。  (Nếu không có ý kiến gì khác thì xin kết thúc ở đây.)\nKhi nào KHÔNG dùng ば:\nNếu mệnh đề trước và mệnh đề sau CÙNG chủ ngữ, và mệnh đề sau là câu thể hiện Ý CHÍ của người nói (dạng ～たい／～ましょう／mệnh lệnh／ý định), thì KHÔNG được dùng ば ở mệnh đề trước — phải đổi sang たら.\nSai: （あなたが）東京へ来れば、電話してください。 ✗ (chủ ngữ \"bạn\" trùng cả 2 vế + vế sau là mệnh lệnh/ý chí)\nĐúng: 東京へ来たら、電話してください。 ✓\nNếu chủ ngữ 2 vế KHÁC nhau thì vế sau vẫn dùng ý chí được bình thường với ば: 彼女が来れば、すぐ出発しましょう。 ✓","compare":"","examples":[{"jp":"このボタンを押せば、水が流れます。","vn":"Nếu bấm nút này thì nước sẽ chảy ra."},{"jp":"説明書を読めば、使い方がわかります。","vn":"Nếu đọc sách hướng dẫn thì sẽ hiểu cách dùng."},{"jp":"そんなに言うなら、別れましょう。","vn":"Nếu em đã nói vậy thì chia tay đi."}]},{"title":"～ばいいですか / ～ばいい (Xin lời khuyên — Đưa lời khuyên)","formula":"Hỏi lời khuyên: Vば形 + いいですか  → mong người nghe cho lời khuyên/chỉ thị.\nĐưa lời khuyên: Vば形 + いい  → bản thân người nói khuyên người khác (bỏ か).\nパスポートをなくしたんですが、どうすればいいですか。  (Tôi bị mất hộ chiếu, giờ tôi nên làm gì thì tốt?)\n漢字はどうやって覚えればいいですか。  (Tôi nên học kanji bằng cách nào thì tốt?)\n書きながら、声を出して読めばいいですよ。  (Bạn nên vừa viết vừa đọc thành tiếng là tốt nhất.) — lời khuyên, không có か","explain":"\"Nên làm gì/như thế nào thì tốt?\" — mẫu câu tương đương với ～たらいいですか đã học ở Bài 26, chỉ thay たら bằng thể điều kiện ば.\nCấp độ: N4 · Độ lịch sự: lịch sự khi có か (hỏi ý kiến); trung tính khi bỏ か (đưa lời khuyên).","usage":"nhầm giữ か khi đang đưa lời khuyên (làm câu nghe như đang hỏi lại), hoặc quên chia động từ về ば形 mà để nguyên thể từ điển.","compare":"","examples":[{"jp":"パスポートをなくしたら、どうすればいいですか。","vn":"Nếu bị mất hộ chiếu thì nên làm gì?"},{"jp":"パスポートをなくしたんですが、どうすればいいですか。","vn":"Tôi bị mất hộ chiếu, giờ tôi nên làm gì thì tốt?"},{"jp":"漢字はどうやって覚えればいいですか。","vn":"Tôi nên học kanji bằng cách nào thì tốt?"}]},{"title":"～なら","formula":"Loại từ | Công thức | Ví dụ\nDanh từ | N + なら | 電話なら → もう買いました\nĐộng từ (từ điển/quá khứ) | V(た/る) + なら | 行くなら → 一緒に行きましょう\nTính từ い | A(い) + なら | 安いなら → 買います\nTính từ な | A(な) + なら | きれいなら → いいですね\nA: スマホを買いたいんですが…  B: スマホなら、ノキアがいいですよ。  (Nếu là điện thoại thì Nokia là tốt đấy.)\nA: 海に行きたいんですが、いい所はありますか。  B: 海ならダナンがいちばんきれいです。  (Nếu là biển thì Đà Nẵng đẹp nhất.)","explain":"\"Nếu là...\" — dùng để nối tiếp/phản hồi trực tiếp chủ đề mà đối phương vừa nêu ra, không cần lặp lại toàn bộ câu.\nCấp độ: N4 · Độ lịch sự: trung tính, dùng được văn nói.","usage":"","compare":"なら không diễn tả một chuỗi nhân-quả điều kiện thời gian như ば/たら, mà nêu lại chủ đề đối phương đã nói để đưa ra nhận xét/đề xuất ngay — mang tính hội thoại, phản hồi tức thời.","examples":[{"jp":"そんなに嫌なら、別れたらどうですか。","vn":"Nếu ghét đến thế thì chia tay có được không?"},{"jp":"スマホを買いたいんですが…  B: スマホなら、ノキアがいいですよ。","vn":"Nếu là điện thoại thì Nokia là tốt đấy."},{"jp":"海に行きたいんですが、いい所はありますか。  B: 海ならダナンがいちばんきれいです。","vn":"Nếu là biển thì Đà Nẵng đẹp nhất."}]},{"title":"～ば～ほど (Càng... càng...)","formula":"Loại từ | Công thức | Ví dụ\nĐộng từ | V(ば形) + V(từ điển) + ほど | 勉強すればするほど → 難しく感じる\nTính từ い | A(ければ) + A(い) + ほど | 安ければ安いほど → いい\nTính từ な | A(なら) + A(な) + ほど | 簡単なら簡単なほど → いい\n日本語を勉強すればするほど、頭が混乱してきます。  (Càng học tiếng Nhật thì đầu óc càng rối tung.)\n給料は多ければ多いほどいいです。  (Lương càng nhiều thì càng tốt.)\n年をとればとるほど、目や歯が弱くなります。  (Càng già thì mắt và răng càng yếu.)","explain":"\"Càng... thì càng...\" — một sự việc càng tiến triển/thay đổi thì sự việc khác cũng càng tiến triển/thay đổi theo. Đôi khi mang nghĩa kết quả ngoài dự đoán.\nCấp độ: N4 · Độ lịch sự: trung tính.","usage":"chia động từ/tính từ lần 2 sai thể (phải giữ nguyên thể từ điển/thường, không chia thêm gì); quên phải lặp lại 2 lần cùng một từ.","compare":"","examples":[{"jp":"日本語は勉強すればするほど、難しく感じます。","vn":"Tiếng Nhật càng học càng thấy khó."},{"jp":"日本語を勉強すればするほど、頭が混乱してきます。","vn":"Càng học tiếng Nhật thì đầu óc càng rối tung."},{"jp":"給料は多ければ多いほどいいです。","vn":"Lương càng nhiều thì càng tốt."}]},{"title":"Phân biệt と・たら・ば","formula":"","explain":"Tiêu chí | と | たら | ば\nVăn nói/viết | Cả hai | Chỉ văn nói\nÝ chí ở mệnh đề sau | Không được | Được (kể cả chủ ngữ trùng) | Chỉ được khi chủ ngữ 2 vế khác nhau\nPhạm vi dùng | Chỉ đường, thao tác máy móc, quy luật hiển nhiên | Điều kiện giả định + thông thường\nと: 右へ曲がると、銀行があります。  (Chỉ đường) — このボタンを押すと、お金が出ます。 (máy móc). KHÔNG được: 疲れると、休んでください。 ✗\nたら: 疲れたら、休んでください。 ✓ (mệnh lệnh, chủ ngữ trùng vẫn được)\nば: 100万円あれば、家を買います。 ✓ (chủ ngữ trùng nhưng vế sau không phải mệnh lệnh/ý chí trực tiếp kiểu cầu khiến — vẫn chấp nhận ở mức N4 cơ bản, nhưng khi vế sau là câu cầu khiến/mệnh lệnh thật sự với chủ ngữ trùng thì phải đổi sang たら)\nGhi nhớ nhanh cho học viên: Chủ ngữ 2 vế GIỐNG nhau + vế sau là mệnh lệnh/rủ rê/ý chí → dùng たら, không dùng ば.","usage":"","compare":"","examples":[{"jp":"パスポートをなくしたら、どうすればいいですか。","vn":"Nếu bị mất hộ chiếu thì nên làm gì?"},{"jp":"そんなに嫌なら、別れたらどうですか。","vn":"Nếu ghét đến thế thì chia tay có được không?"},{"jp":"と: 右へ曲がると、銀行があります。","vn":"Chỉ đường"}]}],"36":[{"title":"～ように (để...)","formula":"","explain":"Vる／Vない ＋ ように、～ — Để...\nmệnh đề trước ように là MỤC ĐÍCH mong muốn đạt được (thường KHÔNG có chủ ý — động từ thể khả năng, tự động từ, hoặc động từ như わかる／聞こえる／見える); mệnh đề sau là HÀNH ĐỘNG có chủ ý được thực hiện để đạt mục đích đó. Dịch từ vế sau lên vế trước: \"Thực hiện V2 để đạt được V1\".\nCấp độ: N4. Độ lịch sự: trung tính, dùng cả văn nói lẫn văn viết.\nDạng | Công thức | Ví dụ\nKhẳng định | Vる（khả năng／tự động từ）＋ ように、V2 | 新聞が読めるように、漢字を勉強します。\nPhủ định | Vない ＋ ように、V2 | 道に迷わないように、地図を持って行きます。\nQuá khứ (vế 2) | …ように、V2ました | よく見えるように、前の方に座りました。\nNghi vấn | …ように、V2ますか | 早く治るように、何をしますか。\nquan trọng: Động từ đứng trước ように bắt buộc KHÔNG mang chủ ý (thể khả năng, tự động từ). Nếu là động từ có chủ ý (dạng từ điển, có ý chí như 勉強する、行く…) thì phải dùng ために + trợ từ の, KHÔNG dùng ように. Đây là điểm học viên N3/N2 rất hay nhầm lẫn giữa ように và ために.","usage":"hành động vế 2 nhằm đạt mục đích/kết quả mong muốn ở vế 1 (thường là điều không tự chủ đạt được, cần cố gắng). Khi nào KHÔNG dùng: khi động từ trước có chủ ý rõ ràng (phải chuyển sang ために cho tự nhiên hơn, dù ように vẫn được người Nhật hiểu ở trình độ thấp).\ndùng động từ có chủ ý (dạng từ điển thường) trước ように thay vì chia về thể khả năng/tự động từ. Ví dụ sai: ×日本語を勉強するように、日本に来ました → phải sửa thành ために hoặc đổi động từ vế trước sang dạng không chủ ý.","compare":"ように (động từ không chủ ý) vs ために (động từ có chủ ý, trợ từ の). Cấu trúc gần giống hệt nhau về mặt dịch nghĩa \"để...\" nhưng khác nhau ở tính chủ ý của động từ đứng trước.","examples":[{"jp":"新聞が読めるように、漢字を勉強しています。","vn":"Dịch: Tôi học kanji để có thể đọc được báo."},{"jp":"自転車に乗れるようになりました。","vn":"Dịch: Tôi đã trở nên biết đi xe đạp (đã có thể đi xe đạp)."},{"jp":"健康のために、毎日野菜を食べるようにしています。","vn":"Dịch: Vì sức khỏe, tôi đang cố gắng ăn rau mỗi ngày."},{"jp":"食事の時間に遅れないようにしてください。","vn":"Dịch: Hãy cố gắng đừng đến muộn giờ ăn."},{"jp":"運転するときは、シートベルトをしめるようにしてください。","vn":"Dịch: Khi lái xe, xin hãy cố gắng thắt dây an toàn."}]},{"title":"～ようになります (trở nên có thể...)","formula":"","explain":"Vる（khả năng）＋ ようになります — Trở nên/dần dần có thể...\nbiểu thị sự BIẾN ĐỔI trạng thái từ KHÔNG THỂ sang CÓ THỂ, diễn ra dần dần qua thời gian/luyện tập (không phải do một hành động tác động trực tiếp một lần).\nCấp độ: N4. Độ lịch sự: trung tính.\nDạng | Công thức | Ý nghĩa\nHiện tại/tương lai | Vれる（khả năng）＋ ようになります | sẽ dần trở nên có thể (chưa xảy ra)\nQuá khứ/hoàn thành | Vれる（khả năng）＋ ようになりました | đã trở nên có thể (tại thời điểm nói)\nPhủ định (khác nhóm) | Vれる ＋ ようになりません | sẽ không trở nên có thể\nNghi vấn | Vれる ＋ ようになりましたか | đã trở nên có thể chưa?\nkhác với なります đơn thuần (sự vật tự biến đổi, ví dụ 寒くなります — trời trở lạnh), ようになります nhấn mạnh có sự nỗ lực/tác động dẫn đến thay đổi khả năng thực hiện việc gì đó.","usage":"nói về kỹ năng/khả năng đạt được sau quá trình luyện tập (biết đi xe đạp, đọc được báo, hiểu tiếng Nhật...). Khi nào KHÔNG dùng: khi mô tả biến đổi tự nhiên không liên quan đến \"khả năng\" (lúc đó dùng ～くなります／～になります).\nnhầm lẫn thì của なります và なりました — dùng なります khi ý muốn nói \"đã\" đạt được (phải dùng なりました), khiến câu chuyển từ nghĩa \"sẽ có thể\" (tương lai) sang \"đã có thể\" (kết quả, quá khứ) sai lệch.","compare":"","examples":[{"jp":"Vれる ＋ ようになりません","vn":"sẽ không trở nên có thể"},{"jp":"Vれる ＋ ようになりましたか","vn":"đã trở nên có thể chưa?"},{"jp":"太ったので、好きなズボンがはけなくなりました。","vn":"Dịch: Vì béo lên nên tôi không còn mặc vừa được cái quần mình thích nữa."}]},{"title":"～なくなります (không còn có thể... nữa)","formula":"","explain":"Vない（khả năng）＋ くなります — Trở nên không thể... nữa\nngược lại với ようになります — biểu thị sự biến đổi trạng thái từ CÓ THỂ sang KHÔNG THỂ (mất dần khả năng thực hiện việc gì đó).\nCấp độ: N4. Độ lịch sự: trung tính.\nDạng | Công thức | Ý nghĩa\nTương lai (e sẽ mất khả năng) | Vれない ＋ くなります | sẽ dần không còn có thể\nQuá khứ/hoàn thành | Vれない ＋ くなりました | đã không còn có thể (tại thời điểm nói)\nđây thực chất là dạng phủ định của động từ khả năng (Vれない) + くなります, không phải một mẫu ngữ pháp tách biệt — cùng gốc với ようになります nhưng đảo chiều biến đổi.","usage":"mô tả kỹ năng/khả năng bị mất đi theo thời gian (già đi không đọc được chữ nhỏ, béo lên không mặc vừa quần áo cũ, sang Nhật lâu ngày quên tiếng Anh...). Lỗi thường gặp: quên chia động từ về thể khả năng trước khi phủ định + くなります (ví dụ chia sai 食べなくなります khi ý là \"không thể ăn được\" phải là 食べられなくなります).","compare":"","examples":[{"jp":"Vれない ＋ くなります","vn":"sẽ dần không còn có thể"},{"jp":"Vれない ＋ くなりました","vn":"đã không còn có thể (tại thời điểm nói)"},{"jp":"日本に来てから、英語が話せなくなりました。","vn":"Dịch: Từ khi sang Nhật, tôi không còn nói được tiếng Anh nữa."}]},{"title":"～ようにします／～ようにしています (cố gắng/nỗ lực thực hiện)","formula":"","explain":"Vる／Vない ＋ ようにします — Cố gắng, nỗ lực làm (hoặc không làm)...\ndiễn tả Ý ĐỊNH cố gắng/nỗ lực thực hiện (hoặc không thực hiện) một hành động, thường theo hướng thay đổi tích cực. します diễn tả ý định tại thời điểm nói; しています diễn tả việc đang duy trì như một THÓI QUEN đều đặn từ trước đến nay.\nCấp độ: N4. Độ lịch sự: trung tính, lịch sự thể ます.\nDạng | Công thức | Ví dụ\nKhẳng định (ý định) | Vる ＋ ようにします | 6時に起きるようにします。\nPhủ định (ý định) | Vない ＋ ようにします | 甘い物を食べないようにします。\nThói quen đang duy trì | Vる／Vない ＋ ようにしています | 毎日野菜を食べるようにしています。\nQuá khứ | …ようにしました／していました | 毎日歩くようにしていました。","usage":"nói về việc bản thân đang/sẽ cố gắng rèn thói quen (ăn uống lành mạnh, dậy sớm, không hút thuốc...). Lỗi thường gặp: nhầm ようにします (ý chí, cố gắng chủ động) với ようになります (biến đổi khách quan không nhất thiết do cố gắng) — đây là cặp dễ nhầm nhất trong bài.","compare":"","examples":[{"jp":"健康のために、毎日野菜を食べるようにしています。","vn":"Dịch: Vì sức khỏe, tôi đang cố gắng ăn rau mỗi ngày."},{"jp":"ようにします","vn":"ý chí, cố gắng chủ động"},{"jp":"ようになります","vn":"biến đổi khách quan không nhất thiết do cố gắng"}]},{"title":"～ようにしてください (hãy cố gắng...)","formula":"","explain":"Vる／Vない ＋ ようにしてください — Hãy cố gắng làm (hoặc không làm)...\nyêu cầu người nghe cố gắng thực hiện/không thực hiện một hành động — SAI KHIẾN/NHỜ VẢ GIÁN TIẾP, nhẹ nhàng và lịch sự hơn so với ～てください thông thường.\nCấp độ: N4. Độ lịch sự: lịch sự, mềm mỏng hơn てください.\nDạng | Công thức | Ví dụ\nKhẳng định | Vる ＋ ようにしてください | 規則を守るようにしてください。\nPhủ định | Vない ＋ ようにしてください | 食事の時間に遅れないようにしてください。\nKhi nào KHÔNG dùng: KHÔNG dùng ようにしてください cho yêu cầu/nhờ vả cần thực hiện NGAY TẠI CHỖ, tức thời (ví dụ nhờ ai đó cầm giúp món đồ ngay lúc đó) — trường hợp này phải dùng ～てください thông thường. ようにしてください chỉ phù hợp với yêu cầu mang tính duy trì/thói quen lâu dài hoặc lời nhắc nhở chung.","usage":"","compare":"～てください (yêu cầu trực tiếp, tức thời) vs ～ようにしてください (yêu cầu duy trì/cố gắng, gián tiếp — không dùng cho việc cần làm ngay). Ngoài ra còn có thể mệnh lệnh nhẹ ～ようにしなさい mang sắc thái ra lệnh hơn.","examples":[{"jp":"食事の時間に遅れないようにしてください。","vn":"Dịch: Hãy cố gắng đừng đến muộn giờ ăn."},{"jp":"運転するときは、シートベルトをしめるようにしてください。","vn":"Dịch: Khi lái xe, xin hãy cố gắng thắt dây an toàn."},{"jp":"てください","vn":"yêu cầu trực tiếp, tức thời"}]}],"37":[{"title":"Cách chia động từ sang thể bị động","formula":"","explain":"Động từ thể bị động (受身形) có 2 nghĩa: \"được\" (mang sắc thái tích cực) và \"bị\" (mang sắc thái tiêu cực). Cách chia theo 3 nhóm động từ:\nNhóm 1 (五段動詞)\nĐổi đuôi い (hàng い) → hàng あ + れる\nRiêng động từ kết thúc bằng う → đổi thành わ + れる (không phải あ)\nThể ます (từ điển) | Nghĩa | Thể bị động | Nghĩa bị động\n聞きます (聞く) | hỏi | 聞かれる | bị hỏi\n取ります (取る) | lấy | 取られる | bị lấy/bị lấy trộm\n噛みます (噛む) | cắn | 噛まれる | bị cắn\n叱ります (叱る) | mắng, nhắc nhở | 叱られる | bị mắng, bị nhắc nhở\n誘います (誘う) | rủ, mời | 誘われる | được rủ/được mời\n買います (買う) | mua | 買われる | được mua\n吸います (吸う) | hút | 吸われる | bị hút\nNhóm 2 (一段動詞)\nBỏ る, thêm られる\nThể từ điển | Nghĩa | Thể bị động | Nghĩa bị động\n寝る | ngủ | 寝られる | bị (làm phiền khi đang) ngủ\n見る | xem, nhìn | 見られる | bị nhìn / được xem\n食べる | ăn | 食べられる | bị ăn mất\nほめる | khen | ほめられる | được khen\nNhóm 3 (bất quy tắc)\nする → される\n来る → 来られる\nThể từ điển | Nghĩa | Thể bị động | Nghĩa bị động\n注意する | nhắc nhở, chú ý | 注意される | bị nhắc nhở\n招待する | mời | 招待される | được mời\n発明する | phát minh | 発明される | được phát minh\n発見する | phát hiện | 発見される | được phát hiện\n設計する | thiết kế | 設計される | được thiết kế\n来る | đến | 来られる | bị (ai đó) đến (làm phiền)","usage":"","compare":"","examples":[{"jp":"来る → 来られる","vn":"Thể từ điển | Nghĩa | Thể bị động | Nghĩa bị động"},{"jp":"私は泥棒に財布を取られました。","vn":"Dịch: Tôi bị kẻ trộm lấy mất ví."},{"jp":"お酒は米から作られます。","vn":"Dịch: Rượu được làm từ gạo."}]},{"title":"N1は N2に V(受身) — Bị động trực tiếp","formula":"Dạng | Công thức | Ví dụ\nKhẳng định | N1は N2に V(受身)ます | 私は先生にほめられます。\nPhủ định | N1は N2に V(受身)ません | 私は先生にほめられません。\nQuá khứ | N1は N2に V(受身)ました | 私は先生にほめられました。\nQuá khứ phủ định | N1は N2に V(受身)ませんでした | 私は先生にほめられませんでした。\nNghi vấn | N1は N2に V(受身)ましたか | あなたは先生にほめられましたか。","explain":"N1 (chủ ngữ) là đối tượng tiếp nhận, bị/được N2 (người gây ra) trực tiếp tác động hành vi.\nN1 = chủ ngữ, luôn là đối tượng tiếp nhận hành vi\nN2 = người gây ra hành vi, đứng trước trợ từ に\nĐộng từ cuối câu chia về thể bị động\nđây là 2 lăng kính đối lập của cùng 1 sự việc — thay vì nói \"N2 làm gì đó với N1\" (chủ động), người nói chọn đặt N1 (người chịu tác động) làm chủ ngữ để nhấn mạnh cảm nhận của N1.","usage":"Dùng khi muốn nhấn mạnh cảm nhận của người/vật bị tác động, đặc biệt trong văn viết, tin tức, đọc hiểu.\nLỗi phổ biến nhất: dịch theo thói quen \"chủ ngữ trước — động từ cuối câu\" mà bỏ qua đuôi られる/れる, dẫn đến dịch ngược nghĩa 180 độ. Ví dụ 私は先生にほめられました là \"tôi được thầy khen\", KHÔNG PHẢI \"tôi khen thầy\".","compare":"","examples":[{"jp":"私は先生にほめられました。","vn":"Dịch: Tôi được thầy giáo khen."},{"jp":"私は犬にお尻を噛まれました。","vn":"Dịch: Tôi bị con chó cắn vào mông."},{"jp":"この椅子は木で作られています。","vn":"Dịch: Cái ghế này được làm từ gỗ."}]},{"title":"N1は N2に N3を V(受身) — Bị động gián tiếp (thể phiền toái)","formula":"Dạng | Công thức | Ví dụ\nKhẳng định | N1は N2に N3を V(受身)ます | 私は弟にパソコンを壊されます。\nPhủ định | N1は N2に N3を V(受身)ません | 私は弟にパソコンを壊されません。\nQuá khứ | N1は N2に N3を V(受身)ました | 私は泥棒に財布を取られました。\nNghi vấn | N1は N2に N3を V(受身)ましたか | 犬にお尻を噛まれましたか。","explain":"N2 tác động hành vi lên N3 (vật sở hữu của N1), khiến N1 (chủ sở hữu) cảm thấy phiền toái/khó chịu/thiệt hại.\nN1 = chủ ngữ, chủ sở hữu của N3, người chịu ảnh hưởng gián tiếp\nN2 = người gây ra hành vi, đứng trước に\nN3 = vật/bộ phận cơ thể là sở hữu của N1, đứng trước を\nquan trọng: mẫu câu này CHỈ mang nghĩa tiêu cực \"bị\", KHÔNG bao giờ dịch là \"được\" — kể cả khi hành vi khách quan là tích cực (ví dụ bố sửa xe đạp cho mình), nếu dùng thể bị động ở đây vẫn hàm ý phiền toái.","usage":"Dùng khi người nói cảm thấy bị làm phiền/thiệt hại (mất đồ, bị hỏng đồ, bị tác động vào cơ thể).\nKHÔNG dùng khi muốn thể hiện lòng biết ơn — trường hợp đó dùng ～てもらいます (đã học ở bài trước). Ví dụ: bố sửa xe đạp cho mình và mình biết ơn → 父に自転車を直してもらいました, KHÔNG dùng 父に自転車を直されました (nghe như đang phàn nàn).\nquên mất N3 (vật bị tác động) khác với N1 (người) — học viên hay nhầm N3 với đối tượng trực tiếp trong mẫu 2.1.","compare":"","examples":[{"jp":"てもらいます","vn":"đã học ở bài trước"},{"jp":"オリンピックは4年に1度開かれます。","vn":"Dịch: Thế vận hội Olympic được tổ chức 4 năm một lần."},{"jp":"私は先生にほめられました。","vn":"Dịch: Tôi được thầy giáo khen."}]},{"title":"Nは/が V(受身) — Bị động ẩn danh chủ thể","formula":"Dạng | Công thức | Ví dụ\nKhẳng định | Nは/が V(受身)ます | オリンピックは4年に1度開かれます。\nPhủ định | Nは/が V(受身)ません | この会議はAホールでは開かれません。\nQuá khứ | Nは/が V(受身)ました | この絵は200年前に描かれました。\nNghi vấn | Nは/が V(受身)ますか | 会議はどこで開かれますか。","explain":"dùng khi không cần thiết/không biết rõ ai là người gây ra hành động — chủ thể gây ra hành động (N2) được lược bỏ hoàn toàn, chỉ còn sự vật/sự việc làm chủ ngữ.\nVật không được nhấn mạnh như chủ đề câu → dùng trợ từ が\nTrước thời gian/địa điểm dùng trợ từ に; sau thời gian/địa điểm dùng trợ từ で\nthường gặp trong tin tức, mô tả sự kiện lịch sử, quy trình — nhấn mạnh sự việc/sự vật, không cần nêu ai thực hiện.","usage":"Dùng khi chủ thể gây ra hành động không quan trọng, hiển nhiên, hoặc không xác định được.\nNếu muốn nhấn mạnh RÕ ai là người gây ra, phải quay lại dùng mẫu 2.1/2.2 (có に) hoặc 2.4 (có によって).","compare":"","examples":[{"jp":"私は先生に叱られました。","vn":"Dịch: Tôi bị thầy giáo mắng."},{"jp":"年にインスタントラーメンが発明されました。","vn":"Dịch: Vào năm 1958, mì ăn liền đã được phát minh ra."},{"jp":"私は先生にほめられました。","vn":"Dịch: Tôi được thầy giáo khen."}]},{"title":"N1は N2によって V(受身) — Bị động thể hiện tác giả/người sáng tạo","formula":"Dạng | Công thức | Ví dụ\nKhẳng định | N1は N2によって V(受身)ます | 電球はエジソンによって発明されます。\nQuá khứ | N1は N2によって V(受身)ました | モナリザはレオナルド・ダ・ビンチによって描かれました。\nPhủ định | N1は N2によって V(受身)ません | この教会は有名な建築家によって設計されていません。\nNghi vấn | N1は N2によって V(受身)ましたか | 電話は誰によって発明されましたか。","explain":"N1 (vật/tác phẩm) được tạo ra/thực hiện bởi N2 (người sáng tạo). N1 là vật, N2 là người làm ra vật đó.\nChỉ dùng với các động từ mang tính sáng tạo, phát minh, phát hiện, thiết kế, sáng tác (không dùng によって cho hành vi thông thường như ăn, mắng, cắn).","usage":"dùng に thay cho によって trong câu nói về tác giả/nhà phát minh — nghe không tự nhiên/sai văn phong trang trọng.","compare":"に vs によって\nTrợ từ | Dùng khi | Ví dụ\nに | Hành vi tác động trực tiếp/gián tiếp lên người (mẫu 2.1, 2.2), mang cảm xúc bị/được | 私は先生にほめられました。\nによって | Nêu tác giả/người phát minh/sáng tạo ra một vật, mang tính khách quan, trang trọng (văn viết) | ドラえもんは藤子・F・不二雄によって書かれました。","examples":[{"jp":"モナリザはレオナルド・ダ・ビンチによって描かれました。","vn":"Dịch: Bức tranh Mona Lisa được vẽ bởi Leonardo da Vinci."},{"jp":"この教会は有名な建築家によって設計されました。","vn":"Dịch: Nhà thờ này được thiết kế bởi một kiến trúc sư nổi tiếng."},{"jp":"に vs によって","vn":"Trợ từ | Dùng khi | Ví dụ"}]},{"title":"Nは N(nguyên liệu)から / N(vật liệu)で 作られます — Bị động chỉ nguyên liệu/vật liệu","formula":"Loại | Công thức | Ví dụ\nNguyên liệu | Nは N(nguyên liệu)から作られます | お酒は米から作られます。（rượu làm từ gạo — không còn thấy hạt gạo）\nVật liệu | Nは N(vật liệu)で作られています | この椅子は木で作られています。（ghế làm từ gỗ — vẫn thấy gỗ）\nQuá khứ | Nは N(vật liệu)で作られました | この家は木で作られました。","explain":"diễn tả một vật được làm ra từ nguyên liệu (có biến đổi bản chất) hoặc vật liệu (giữ nguyên bản chất).\nNguyên liệu (bản chất biến đổi, không còn nhìn thấy nguyên liệu gốc) → dùng から\nVật liệu (bản chất không đổi, vẫn nhìn thấy được) → dùng で","usage":"nhất trong đề thi N4/N3: nhầm lẫn から và で. Bia làm từ lúa mạch (không còn thấy hạt lúa mạch) → から, chứ không phải で.","compare":"","examples":[{"jp":"お酒は米から作られます。","vn":"rượu làm từ gạo — không còn thấy hạt gạo"},{"jp":"この椅子は木で作られています。","vn":"ghế làm từ gỗ — vẫn thấy gỗ"},{"jp":"私は先生にほめられました。","vn":"Dịch: Tôi được thầy giáo khen."}]}],"38":[{"title":"Vこothể thường／い形容詞／な形容詞な + のは + tính từ (cảm tưởng)","formula":"Dạng | Công thức | Ví dụ\nKhẳng định | Vる/Vた + のは + Adj + です | 料理を作るのは楽しいです。\nPhủ định | Vる + のは + Adjない + です | 一人で夜道を歩くのはよくないです。\nQuá khứ | Vた + のは + Adjかった + です | 試験を受けたのは大変でした。\nNghi vấn | Vる/Vた + のは + Adj + ですか | サッカーを見るのは楽しいですか。","explain":"Mẫu câu: [Cụm động từ/tính từ thể thường] + のは + [tính từ chỉ cảm tưởng] + です\nDiễn đạt cảm tưởng, đánh giá của người nói đối với một hành động/sự việc. Có tác dụng nhấn mạnh vấn đề muốn nói.\nCấp độ: N4 (nền tảng dẫn vào N3) | Độ lịch sự: trung tính, dùng được cả văn nói và văn viết\nTính từ đi sau のは thường là tính từ chỉ CẢM XÚC: 楽しい(vui), 嬉しい(vui mừng), 難しい(khó), 危ない(nguy hiểm), 大変(vất vả), 面白い(thú vị).","usage":"Dùng khi muốn nói cụ thể HÀNH ĐỘNG nào gây ra cảm xúc, thay vì nói chung chung về sự vật.\nVD: thay vì nói 「サッカーが好きです」(thích bóng đá chung chung), dùng 「サッカーを見るのは楽しいです」để nói rõ là THÍCH XEM bóng đá.\nngười học Việt Nam hay quên biến động từ về thể thường trước の, hoặc nhầm dùng こと thay vì の trong văn nói (こと trang trọng hơn, thường dùng trong văn viết/diễn đạt trừu tượng).","compare":"","examples":[{"jp":"友達と旅行するのは楽しいです。","vn":"Dịch: Đi du lịch cùng bạn bè thì rất vui."},{"jp":"私が生まれたのは、タイビンの小さな田舎です。","vn":"Dịch: Nơi tôi sinh ra là một miền quê nhỏ ở Thái Bình."},{"jp":"先生がもうすぐ結婚することを知っていますか。","vn":"Dịch: Bạn có biết là thầy giáo sắp kết hôn rồi không?"}]},{"title":"Vこothể thường + のが + tính từ (năng lực/sở thích)","formula":"Dạng | Công thức | Ví dụ\nKhẳng định | Vる + のが + Adj + です | 音楽を聞くのが好きです。\nPhủ định | Vる + のが + Adjない + です | (hiếm dùng, thường phủ định cả câu)\nQuá khứ | Vる + のが + Adjかった + です | 絵を描くのが下手でした。\nNghi vấn | Vる + のが + Adj + ですか | 料理を作るのが上手ですか。","explain":"Mẫu câu: [Cụm động từ thể thường] + のが + [tính từ chỉ năng lực/sở thích] + です\nCấu trúc giống hệt のは về mặt ngữ pháp, chỉ khác ở loại tính từ đi kèm — dùng với tính từ chỉ NĂNG LỰC, SỞ THÍCH, MỨC ĐỘ: 好き(thích), 嫌い(ghét), 上手(giỏi), 下手(kém), 早い(nhanh), 遅い(chậm).\nCấp độ: N4 | Độ lịch sự: trung tính\nGhi nhớ: các tính từ đi với のが (好き・嫌い・上手・下手・早い・遅い) luôn cần trợ từ が phía trước khi ở dạng danh từ hóa thông thường (好きです, 上手です), nên khi danh từ hóa động từ cũng giữ nguyên が chứ không đổi thành は.","usage":"Dùng khi đánh giá NĂNG LỰC thực hiện hành động, không phải cảm xúc chung chung.\nVD: 母は料理を作るのが上手です (Mẹ nấu ăn giỏi) — nhấn mạnh khả năng, không phải cảm xúc thích/ghét.\nnhầm lẫn giữa のは và のが — quy tắc đơn giản để nhớ: nếu tính từ đi sau là 好き/嫌い/上手/下手/早い/遅い → bắt buộc dùng のが; các tính từ cảm xúc khác → dùng のは.","compare":"Tiêu chí | のは + Adj | のが + Adj\nLoại tính từ | Cảm xúc, đánh giá chung: 楽しい, 大変, 危ない, 難しい | Năng lực/sở thích: 好き, 嫌い, 上手, 下手, 早い, 遅い\nVí dụ | 料理を作るのは楽しいです。 | 料理を作るのが上手です。\nDịch | Việc nấu ăn thì vui. | (Anh ấy) nấu ăn giỏi.","examples":[{"jp":"Vる + のが + Adjない + です","vn":"(hiếm dùng, thường phủ định cả câu)"},{"jp":"音楽を聞くのが好きです。","vn":"Dịch: Tôi thích nghe nhạc."},{"jp":"母は料理を作るのが上手です。","vn":"Dịch: Mẹ tôi nấu ăn rất giỏi."}]},{"title":"Vる/Vない + のを忘れました (quên làm gì)","formula":"Dạng | Công thức | Ví dụ\nKhẳng định (quá khứ) | Vる + のを忘れました | 歯を磨くのを忘れました。\nRa lệnh phủ định | Vる + のを忘れないでください | かぎを閉めるのを忘れないでください。\nNhẹ nhàng hơn | Vる + のを忘れないように（してください） | 引き出しにかぎをかけるのを忘れないようにしてください。\nĐã lỡ quên (hối tiếc) | Vる + のを忘れてしまいました | 名前を書くのを忘れてしまいました。","explain":"Mẫu câu: [Cụm động từ thể thường] + のを + 忘れました／忘れないでください／忘れないように\nDiễn đạt việc quên thực hiện một hành động (chưa làm/quên mất phải làm).\nCấp độ: N4 | Độ lịch sự: trung tính, có thể dùng lịch sự với ください\n忘れないでください = mệnh lệnh nhẹ nhàng nhắc nhở; 忘れてしまいました = thể hiện sự tiếc nuối/bối rối vì đã lỡ quên.","usage":"Chỉ dùng khi quên THỰC HIỆN một hành động (quên đánh răng, quên khóa cửa), không dùng khi quên một DANH TỪ/đồ vật đơn thuần (trường hợp đó dùng 忘れました + object を trực tiếp, không cần の).\nhọc viên hay quên biến động từ về thể từ điển (thể る) trước のを, hoặc nhầm thẻ sai khiến 忘れさせる với のを忘れました.","compare":"","examples":[{"jp":"電気を消すのを忘れました。","vn":"Dịch: Tôi đã quên tắt điện."},{"jp":"引き出しにかぎをかけるのを忘れないでください。","vn":"Dịch: Đừng quên khóa ngăn kéo nhé."},{"jp":"音楽を聞くのが好きです。","vn":"Dịch: Tôi thích nghe nhạc."}]},{"title":"Vこothể thường + のを知っていますか (hỏi có biết hay không)","formula":"Dạng | Công thức | Ví dụ\nNghi vấn | Vる/Vた + のを知っていますか | 先生がもうすぐ結婚することを知っていますか。\nTrả lời đã biết (do được hỏi) | 知りました | はい、今知りました。\nTrả lời chưa từng biết, vẫn không biết | 知りません | いいえ、全然知りません。\nTrả lời trước đây không biết | 知りませんでした | いいえ、知りませんでした。","explain":"Mẫu câu: [Cụm câu thể thường] + のを + 知っていますか／知りませんでした／知りませんか\nHỏi người nghe đã biết một thông tin/sự việc gì đó hay chưa, đồng thời truyền tải nội dung thông tin đó.\nCấp độ: N4 (bản lề N3) | Độ lịch sự: trung tính, lịch sự khi dùng thể ます","usage":"cấu trúc gốc chuẩn dùng ことを/のを + 知っていますか (không phải ますか theo động từ 知る thể thường như transcript ASR ghi nhầm).\nhọc viên Việt Nam hay dùng nhầm 知りません khi ý muốn nói là 知りませんでした (vừa mới biết sau khi được hỏi) — cần phân biệt theo NGỮ CẢNH thời điểm biết thông tin.","compare":"Tiêu chí | 知りません | 知りませんでした\nÝ nghĩa | Sau khi được hỏi, người nghe VẪN không biết thông tin đó | Trước khi được hỏi thì không biết, nhưng SAU KHI hỏi xong thì đã biết\nVí dụ hỏi | 鈴木さんの電話番号を知っていますか。 | 先生が日本に行ったことを知っていますか。\nTrả lời | いいえ、知りません。（vẫn chưa biết số điện thoại） | いいえ、知りませんでした。（giờ mới biết tin này）","examples":[{"jp":"いいえ、知りません。","vn":"vẫn chưa biết số điện thoại"},{"jp":"いいえ、知りませんでした。","vn":"giờ mới biết tin này"},{"jp":"駅の前に大きいデパートができたのを知っていますか。","vn":"Dịch: Bạn có biết trước cửa ga có một trung tâm thương mại lớn vừa được xây không?"}]},{"title":"Vこothể thường／Adjい／Adjな + の + は + N + です (danh từ hóa, nhấn mạnh chủ ngữ)","formula":"Dạng | Công thức | Ví dụ\nKhẳng định | [Vる/Adjい/Adjな] + のは + N + です | 私が生まれたのは、タイビンの小さな田舎です。\nPhủ định | のは + N + ではありません | 私が生まれたのは、ハノイではありません。\nQuá khứ | のは + N + でした | その電話を作ったのはサムスンでした。\nNghi vấn | のは + N + ですか | あなたが欲しいのは、どの靴ですか。","explain":"Mẫu câu: [Cụm động từ/tính từ thể thường] + の + は + [danh từ] + です\nDùng の để thay thế danh từ chỉ người/địa điểm/thời gian/lý do/đồ vật, đưa cụm đó ra làm chủ ngữ của câu, rồi đảo xuống cuối câu để nhấn mạnh danh từ. Thường dùng trong văn viết để tạo hiệu ứng tu từ, gợi tò mò cho người đọc.\nCấp độ: N4→N3 | Độ lịch sự: trang trọng, phổ biến trong văn viết\nQuy tắc dịch quan trọng: khi gặp の trong câu, luôn dịch phần TRƯỚC の thành mệnh đề bổ nghĩa, đọc thành 'cái việc/cái nơi/cái người...' rồi mới dịch tiếp phần sau. Ví dụ: 私が生まれたのは、タイビンの田舎です → dịch là 'Nơi tôi sinh ra là miền quê Thái Bình' (không dịch theo thứ tự xuôi).","usage":"Dùng khi muốn nhấn mạnh danh từ đứng cuối câu thay vì liệt kê thông thường bằng し hoặc て — tạo hiệu ứng dẫn dắt người đọc, thường thấy trong văn viết, bài luận, giới thiệu.\nKhông dùng trong hội thoại thường ngày đơn giản — nghe sẽ trang trọng/văn chương hơn mức cần thiết.\nhọc viên dịch theo thứ tự từ trái sang phải như tiếng Việt dẫn đến sai nghĩa; đúng ra phải dịch cụm trước の trước, coi nó là chủ ngữ được danh từ hóa, sau đó nối với phần vị ngữ N です đứng sau の.","compare":"","examples":[{"jp":"音楽を聞くのが好きです。","vn":"Dịch: Tôi thích nghe nhạc."},{"jp":"母は料理を作るのが上手です。","vn":"Dịch: Mẹ tôi nấu ăn rất giỏi."},{"jp":"友達と旅行するのは楽しいです。","vn":"Dịch: Đi du lịch cùng bạn bè thì rất vui."},{"jp":"私が生まれたのは、タイビンの小さな田舎です。","vn":"Dịch: Nơi tôi sinh ra là một miền quê nhỏ ở Thái Bình."},{"jp":"景色がきれいで、食べ物がおいしくて、人がみんな親切な国、それがベトナムです。","vn":"Dịch: Một đất nước có phong cảnh đẹp, đồ ăn ngon, con người thân thiện — đó chính là Việt Nam."}]}],"39":[{"title":"Vて / Vで, Adjで (thể て/で) — vì ... nên ...","formula":"Loại từ | Cách chia | Ví dụ\nĐộng từ | Chia về thể て (bỏ ます, +て/で theo quy tắc thể て) | 食べて、飲んで、行って\nTính từ đuôi い | Bỏ い, + くて | 忙しい → 忙しくて\nTính từ đuôi な / Danh từ | Bỏ な, + で | 静か → 静かで","explain":"Vì nguyên nhân/lý do ở vế trước, dẫn đến kết quả ở vế sau.\nCấp độ: N4 (bản chất gần với N3, cấu trúc thu hẹp hơn から)\nĐộ lịch sự: Trung tính, dùng được cả văn nói và văn viết thông thường","usage":"cấu trúc て/で KHÔNG chia phủ định/quá khứ/nghi vấn riêng — bản thân vế て/で chỉ là một mắt xích nối, thì (quá khứ/hiện tại) và thể khẳng định/phủ định nằm ở vế sau cùng.\n① Vế sau biểu thị cảm giác, tâm trạng: 彼女と別れて、悲しいです。(Vì chia tay người yêu nên tôi buồn.)\n② Vế sau là động từ thể khả năng / trạng thái: 歯が痛くて、何も食べられません。(Vì đau răng nên không thể ăn được gì.)\n③ Vế sau diễn tả tình huống đã xảy ra trong quá khứ: 事故に遭って、遅れました。(Vì gặp tai nạn nên đã bị muộn.) — vế sau bắt buộc chia quá khứ (ました/た).\nKhông dùng khi vế sau là ý muốn, mệnh lệnh, nhờ vả, lời mời, cấm đoán — ví dụ SAI: 危なくて、触らないでください (❌) → phải dùng から: 危ないから、触らないでください。\nPhải tuân thủ trình tự thời gian chặt chẽ: việc xảy ra trước phải đặt trước. Lỗi thường gặp: 明日会議があって、今日準備します (❌ sai thứ tự) → sửa: 明日会議があるので、今日準備します。\nNgười học hay lạm dụng から cho mọi trường hợp — khiến câu nghe 'trình độ N5', trong khi て/で khiến câu tự nhiên, đúng ngữ cảnh N4 hơn.","compare":"","examples":[{"jp":"彼女と別れて、悲しいです。","vn":"Vì chia tay người yêu nên tôi buồn."},{"jp":"歯が痛くて、何も食べられません。","vn":"Vì đau răng nên không thể ăn được gì."},{"jp":"事故に遭って、遅れました。","vn":"Vì gặp tai nạn nên đã bị muộn."}]},{"title":"Danh từ + で — vì (nguyên nhân tự nhiên/khách quan)","formula":"Danh từ (chỉ thiên tai/bệnh tật/sự cố) + で + kết quả","explain":"Nguyên nhân là danh từ chỉ hiện tượng tự nhiên hoặc biến cố khách quan (thiên tai, bệnh tật, tai nạn).\nCấp độ: N4","usage":"Không dùng danh từ+で cho nguyên nhân do hành động chủ ý của con người (không phải hiện tượng tự nhiên/biến cố khách quan).\nVế sau vẫn không được là mệnh lệnh/cấm đoán/ý muốn.\nnhầm động từ tự động từ và tha động từ phía sau — vd 止まる(tự động, bị dừng) khác 止める(tha động, cố ý dừng); đúng ngữ pháp N3 phải dùng tự động từ (台風で電車が止まりました).","compare":"","examples":[{"jp":"火事で、京都の古いお寺が焼けました。","vn":"Do hỏa hoạn, ngôi chùa cổ ở Kyoto đã bị cháy."},{"jp":"地震で、古いビルが倒れました。","vn":"Do động đất, tòa nhà cũ đã bị đổ."},{"jp":"病気で、会社を休みました。","vn":"Vì bị bệnh nên tôi đã nghỉ làm ở công ty."}]},{"title":"ので — vì ... nên ... (lập luận nhẹ nhàng, khách quan)","formula":"Loại từ | Cách chia trước ので\nĐộng từ | Thể thường (辞書形/た形/ない形) hoặc thể ます + ので\nTính từ い | Nguyên dạng + ので\nTính từ な / Danh từ | + な + ので","explain":"Vì nên, nhưng thể hiện nguyên nhân - kết quả một cách khách quan, nhẹ nhàng, giảm cảm giác ép buộc cho người nghe.\nCấp độ: N4, dùng nhiều trong văn viết trang trọng (hồ sơ, đơn xin phép)\nĐộ lịch sự: Lịch sự, tế nhị hơn から và て/で; dùng ました/です + ので để lịch sự tối đa","usage":"Vế sau không được là mệnh lệnh/cấm đoán mạnh mang tính áp đặt (vẫn được dùng cho yêu cầu nhẹ nhàng, xin phép).\nNgười học Việt hay dùng から cho cả câu xin phép trang trọng — nghe cộc, thiếu tế nhị; nên đổi sang ので.","compare":"","examples":[{"jp":"友達の結婚式があるので、早く帰ってもいいですか。","vn":"Vì có tiệc cưới của bạn nên cho em về sớm được không?"},{"jp":"お金がないので、買いませんでした。","vn":"Vì không có tiền nên tôi đã không mua."},{"jp":"小さいときから漫画が好きなので、日本へ留学したいです。","vn":"Vì từ nhỏ đã thích manga nên tôi muốn du học Nhật Bản."}]},{"title":"So sánh から / て・で / ので","formula":"","explain":"Cấu trúc | Phạm vi dùng | Sắc thái | Vế sau cấm đoán/mệnh lệnh?\nから | Rộng, dùng cho mọi nguyên nhân-kết quả | Chủ quan, mạnh, đôi khi nghe 'trẻ con' nếu lạm dụng | Được phép\nて/で | Hẹp: chỉ cảm xúc, khả năng, sự việc quá khứ | Trung tính, tự nhiên, đúng trình tự thời gian | Không được phép\ndanh từ+で | Hẹp: chỉ nguyên nhân tự nhiên/khách quan (thiên tai, bệnh tật) | Khách quan | Không được phép\nので | Trung bình, thiên về lập luận/xin phép/văn viết | Khách quan, nhẹ nhàng, lịch sự | Hạn chế (được dùng cho yêu cầu nhẹ)","usage":"","compare":"","examples":[{"jp":"友達の結婚式があるので、早く帰ってもいいですか。","vn":"Dịch: Vì có tiệc cưới của bạn, cho em về sớm được không ạ?"},{"jp":"小さいときから漫画が好きなので、日本へ留学したいです。","vn":"Dịch: Vì từ nhỏ đã thích manga nên tôi muốn du học Nhật Bản."},{"jp":"今日は誕生日で、たくさんプレゼントをもらって、嬉しいです。","vn":"Dịch: Hôm nay là sinh nhật, tôi nhận được nhiều quà nên rất vui."}]}],"40":[{"title":"疑問詞 + [普通形] + か — Lồng câu hỏi vào câu","formula":"Từ loại | Cách chia | Ví dụ\nĐộng từ | Thể thông thường + か | 行くか／行かないか／行ったか\nTính từ đuôi い | Thể thông thường + か | おいしいか／おいしくないか\nTính từ đuôi な | Bỏ だ + か (không thêm な) | 好きか／好きだったか\nDanh từ | Bỏ だ + か | いつか／だれか／いくらだったか","explain":"Mẫu câu: [Từ nghi vấn] + Thể thông thường + か\nnối một câu hỏi (có từ nghi vấn: 何・いつ・どこ・だれ・いくつ・いくら…) vào giữa hoặc cuối một câu khác, tạo thành câu hỏi gián tiếp (embedded question).\nCấp độ: N4 | Độ lịch sự: trung tính, dùng được cả văn nói và văn viết\nVề bản chất đây là 2 câu (1 câu hỏi + 1 câu trần thuật/mệnh lệnh/rủ rê) được ghép lại thành 1 câu liền mạch, tự nhiên hơn so với việc tách thành 2 câu riêng biệt (cách nói của trình độ N5).","usage":"Dùng khi: muốn hỏi gián tiếp một thông tin có từ nghi vấn, rồi nói tiếp một hành động khác (báo cho biết, hỏi thử, suy nghĩ, thảo luận…).\nKhông dùng khi: câu không chứa từ nghi vấn (何・いつ・どこ・だれ…) — trường hợp đó phải dùng ～かどうか (xem mục 2.2).\nthêm trợ từ か vào cuối câu hỏi rồi vẫn giữ nguyên dấu chấm hỏi/động từ thể lịch sự（ですます）thay vì chuyển về thể thông thường trước khi cộng か.","compare":"か | かどうか\nĐiều kiện | Bắt buộc có từ nghi vấn (何・いつ・どこ…) | KHÔNG có từ nghi vấn\nNghĩa | Hỏi gián tiếp về nội dung cụ thể | Có… hay không (đúng/sai, có/không)\nVí dụ | どこへ行くか、教えてください。 | 行くかどうか、教えてください。","examples":[{"jp":"かどうか","vn":"xem mục 2.2"},{"jp":"この電話はいくらで買ったか、忘れました。","vn":"Dịch: Tôi quên mất đã mua chiếc điện thoại này bao nhiêu tiền rồi."},{"jp":"将来どんな人になりたいか、考えたことがありますか。","vn":"Dịch: Bạn đã từng nghĩ về việc tương lai muốn trở thành người như thế nào chưa?"}]},{"title":"普通形 + かどうか — Có… hay không","formula":"Từ loại | Cách chia | Ví dụ\nĐộng từ | Thể thông thường + かどうか | 行くかどうか／来られるかどうか\nTính từ đuôi い | Thể thông thường + かどうか | おいしいかどうか\nTính từ đuôi な | Bỏ だ + かどうか | 好きかどうか／便利かどうか\nDanh từ | Bỏ だ + かどうか | 学生かどうか","explain":"Mẫu câu: Thể thông thường (không có từ nghi vấn) + かどうか\ndiễn tả sự lựa chọn/không chắc chắn giữa hai khả năng có/không, đúng/sai — tương đương \"có... hay không\" trong tiếng Việt.\nCấp độ: N4 | Độ lịch sự: trung tính\nかどうか khác か ở chỗ: câu gốc không phải là một câu hỏi có từ để hỏi, mà là một câu khẳng định/phủ định — người nói không chắc chắn điều đó đúng hay sai, có hay không.","usage":"Dùng khi: câu hỏi gốc là câu hỏi Yes/No (không có từ nghi vấn).\nKhông dùng khi: câu có sẵn từ nghi vấn (何・いつ・どこ・だれ…) — khi đó chỉ cần か, thêm どうか vào là dư thừa/sai.\nnhầm lẫn dùng か cho câu Yes/No hoặc dùng かどうか cho câu có từ nghi vấn.","compare":"","examples":[{"jp":"田中さんが来るかどうか、まだわかりません。","vn":"Dịch: Vẫn chưa biết là anh Tanaka có đến hay không."},{"jp":"この料理は辛いかどうか、食べてみます。","vn":"Dịch: Tôi sẽ ăn thử món này xem có cay hay không."},{"jp":"サイズが合うかどうかわからないので、はいてみてもいいですか。","vn":"Dịch: Vì không biết cỡ giày có vừa hay không nên cho tôi thử mang được không?"}]},{"title":"動詞て形 + みます — Thử làm gì đó","formula":"Dạng câu | Cấu trúc | Ví dụ\nKhẳng định | Vて + みます | 食べてみます\nPhủ định | Vて + みません | 食べてみません\nQuá khứ | Vて + みました | 食べてみました\nNghi vấn | Vて + みますか | 食べてみますか\nĐề nghị/khuyên nhẹ | Vて + みてください／みませんか | 食べてみてください／食べてみませんか\nXin phép | Vて + みてもいいですか | 食べてみてもいいですか","explain":"Mẫu câu: Động từ thể て + みます\nthử làm một hành động để xem kết quả/cảm nhận thế nào (giống \"thử\" trong tiếng Việt: ăn thử, mặc thử, xem thử…).\nCấp độ: N4 | Độ lịch sự: trung tính, có thể chia theo nhiều thể khác nhau tuỳ ngữ cảnh\nĐộng từ đứng trước てみます thường là động từ mang tính ý chí (hành động chủ động do bản thân quyết định thực hiện), không dùng với động từ chỉ trạng thái hay hành động không chủ ý.","usage":"Dùng khi: muốn diễn tả việc thử làm gì đó để kiểm chứng (ngon/dở, vừa/không vừa, hợp/không hợp…), hoặc đưa lời khuyên nhẹ nhàng bằng てみてください／てみませんか.\nKhông dùng khi: hành động không mang tính thử nghiệm mà là hành động chắc chắn, dứt khoát — khi đó dùng động từ thường, không cần thêm みます.\nquên chia thể て trước khi thêm みます (vd viết nhầm 食べますみます thay vì 食べてみます).","compare":"","examples":[{"jp":"この料理は辛いかどうか、食べてみます。","vn":"Dịch: Tôi sẽ ăn thử món này xem có cay hay không."},{"jp":"来月どこへ旅行に行くか、みんなで話しましょう。","vn":"Dịch: Tháng sau đi du lịch ở đâu thì mọi người cùng bàn bạc nhé."},{"jp":"日本の北から南までどのくらいの距離があるか、調べてみてください。","vn":"Dịch: Hãy thử tìm hiểu xem từ miền Bắc đến miền Nam Nhật Bản cách nhau bao xa."}]}],"41":[{"title":"名詞に + いただきます / もらいます (nhận vật gì đó từ ai đó)","formula":"","explain":"Tôi (hoặc người ở ngôi thấp hơn) nhận được một vật gì đó từ người khác. Cấp độ: N4. Độ lịch sự: いただきます lịch sự/kính trọng, もらいます trung tính.\nDạng | Công thức | Ví dụ\nKhẳng định | N(người cho)に N(vật)をいただきます／もらいます | 先生にペンをいただきました\nPhủ định | N(người cho)に N(vật)をいただきません／もらいません | 友だちに何ももらいませんでした\nQuá khứ | 〜いただきました／もらいました | 母に本をもらいました\nNghi vấn | 〜いただきましたか／もらいましたか | だれにチョコをもらいましたか\nいただきます dùng khi người cho là người trên/cấp trên/khách hàng/người mới quen, thể hiện sự khiêm tốn của người nói. もらいます dùng khi người cho là bạn bè, đồng nghiệp ngang hàng hoặc người dưới (con cái...). Chủ thể của động từ (người nhận) luôn là ngôi thứ nhất (私).","usage":"dùng もらいます khi nhận từ cấp trên/khách hàng → mất lịch sự, cần đổi thành いただきます\nKhông dùng いただきます với người trong gia đình thân thiết trừ khi muốn nhấn mạnh sự trang trọng","compare":"もらう chỉ đổi hình thức lịch sự (いただく) khi người cho ở vị trí cao hơn — không đổi theo người nhận","examples":[{"jp":"私は友だちにペンをもらいました。","vn":"Tôi đã nhận được cây bút từ bạn."},{"jp":"中村課長が京都を案内してくださいました。","vn":"Trưởng phòng Nakamura đã hướng dẫn tôi tham quan Kyoto."},{"jp":"先生に発音を直していただきました。","vn":"Tôi đã được thầy giáo sửa cho phát âm."}]},{"title":"名詞に + くださいます / くれます (ai đó cho tôi vật gì đó)","formula":"","explain":"Người khác (chủ ngữ) cho/tặng tôi một vật gì đó — hướng hành động ngược lại so với もらう/いただく. Cấp độ: N4.\nDạng | Công thức | Ví dụ\nKhẳng định | N(người cho)は(私)に N(vật)をくださいます／くれます | 先生が本をくださいました\nPhủ định | 〜くださいません／くれません | だれも手伝ってくれませんでした\nQuá khứ | 〜くださいました／くれました | 娘が花をくれました\nNghi vấn | 〜くださいましたか／くれましたか | 部長が何をくださいましたか\nくださいます dùng khi người cho là ngôi thứ 2/3 có vị trí cao hơn người nói; không bao giờ chủ ngữ là 私 (Watashi). くれます dùng khi người cho ngang hàng hoặc là người dưới (con cái...).","usage":"nhấn mạnh lòng biết ơn với người đã chủ động cho/giúp mình, người cho luôn làm chủ ngữ\nnhầm chủ ngữ — người học hay đặt 私 làm chủ ngữ của くれる/くださる, đúng ra chủ ngữ phải là người cho","compare":"cùng một sự việc có thể diễn đạt theo 2 chiều — 私は先生にペンをいただきました = 先生が（私に）ペンをくださいました","examples":[{"jp":"私は先生に本をいただきました。","vn":"Tôi đã nhận được cuốn sách từ thầy giáo."},{"jp":"私は子どもに絵本をあげました。","vn":"Tôi đã tặng đứa con quyển truyện tranh."},{"jp":"私は友だちにペンをもらいました。","vn":"Tôi đã nhận được cây bút từ bạn."}]},{"title":"名詞に + あげます / さしあげます / やります (tôi cho ai đó vật gì đó)","formula":"","explain":"Tôi (chủ ngữ luôn là 私) cho/tặng người khác một vật gì đó. Cấp độ: N4.\nDạng | Công thức | Ví dụ\nKhẳng định | (私は)N(người nhận)に N(vật)をあげます／さしあげます／やります | 子どもに本をやりました\nPhủ định | 〜あげません／さしあげません／やりません | 花に水をやりませんでした\nQuá khứ | 〜あげました／さしあげました／やりました | 友だちに本をあげました\nNghi vấn | 〜あげましたか／やりましたか | 犬に何をやりましたか\nあげます dùng cho bạn bè/đồng nghiệp ngang hàng. さしあげます dùng khi người nhận là người trên, nhưng theo bài giảng, cách này ít dùng vì dễ tạo cảm giác kiêu ngạo/khoe khoang — nên hạn chế nói trực tiếp với người trên. やります dùng khi đối tượng nhận ở vị trí thấp hơn (em nhỏ, con cái, động thực vật).\nKhi nào không dùng: tránh dùng さしあげます trực tiếp trước mặt người trên vì dễ gây cảm giác khoe khoang, tinh tướng — nên ưu tiên cách diễn đạt khác","usage":"dùng あげます cho động vật/cây cối/em nhỏ thay vì やります (dù ngày nay あげます cũng được chấp nhận với con cái để thể hiện gần gũi)\nTrợ từ đặc biệt: một số động từ như 迎える/直す tác động trực tiếp lên danh từ khác (không phải người nhận) thì dùng trợ từ を thay vì に — ví dụ 孫を迎えに行ってやります (đi đón cháu) chứ không phải 孫に","compare":"","examples":[{"jp":"娘が誕生日に花をくれました。","vn":"Con gái đã tặng tôi hoa vào ngày sinh nhật."},{"jp":"私は花に水をやりました。","vn":"Tôi đã tưới nước cho hoa."},{"jp":"私は友だちにペンをもらいました。","vn":"Tôi đã nhận được cây bút từ bạn."}]},{"title":"〜てくれませんか／〜ていただけませんか (nhờ vả lịch sự)","formula":"","explain":"Nhờ người nghe thực hiện một hành động cho mình, mức độ lịch sự tăng dần. Cấp độ: N4.\nDạng | Công thức | Độ lịch sự\nThấp nhất | 〜てください | Mang tính sai khiến, không dùng với người trên\nTrung bình | 〜てくれませんか | Lịch sự hơn てください\nCao nhất | 〜ていただけませんか | Lịch sự nhất, dùng với người trên/người lạ\n〜ていただけませんか là dạng khả năng thể của いただく, thể hiện sự khiêm nhường và lịch sự cao nhất","usage":"xếp theo thứ tự lịch sự tăng dần てください → てくれませんか → ていただけませんか; chọn theo đối tượng và mức độ trang trọng của tình huống\ndùng てください với cấp trên/khách hàng, cần thay bằng ていただけませんか","compare":"","examples":[{"jp":"〜てください","vn":"Mang tính sai khiến, không dùng với người trên"},{"jp":"〜ていただけませんか","vn":"Lịch sự nhất, dùng với người trên/người lạ"},{"jp":"中国語の手紙なので、訳していただけませんか。","vn":"Vì là thư tiếng Trung nên anh/chị có thể dịch giúp tôi được không? (nhờ vả mức lịch sự cao nhất)"}]}],"42":[{"title":"Vて形 / Vる形 (ý chí) ＋ ために – \"để...\"","formula":"","explain":"diễn tả mục đích – chủ ngữ thực hiện hành động phía sau nhằm đạt được mục đích phía trước.\nCấp độ: N4 (mở rộng N3, N2)　|　Độ lịch sự: trung tính, dùng cả văn nói lẫn văn viết\nThể | Công thức | Ví dụ\nKhẳng định | Vる (ý chí) ／ 名詞の＋ために | 勉強するために\nPhủ định | Không phủ định trực tiếp mệnh đề trước bằng ないために mang nghĩa mục đích (dùng để chỉ nguyên nhân); muốn phủ định mục đích, đổi động từ phía sau | 留学しないために貯金しない\nQuá khứ | Mệnh đề trước luôn ở thể る (không chia quá khứ); thì quá khứ nằm ở mệnh đề sau | 合格するために勉強した\nNghi vấn | ～ために～か | 何のために勉強しますか。\nmệnh đề trước phải là hành động có ý chí (意志動詞), và chủ ngữ của 2 mệnh đề phải giống nhau. Thể hiện quyết tâm, cam kết thực hiện mạnh mẽ – gần nghĩa \"sẽ làm bằng được\".","usage":"khi người nói có mục tiêu/ước mơ rõ ràng và chủ động hành động để đạt được nó. Ví dụ: 将来自分の会社を作るために、今から一生懸命働いています。\nKhi nào KHÔNG dùng: khi mệnh đề trước là động từ vô ý chí, tự động từ, động từ thể khả năng, hoặc chủ ngữ là ngôi thứ 3 khác với ngôi chủ ngữ mệnh đề sau – lúc này phải dùng ように.\nhọc viên Việt Nam hay dùng ために với tự động từ/động từ thể khả năng (ví dụ 忘れないために thay vì 忘れないように), hoặc dùng khi chủ ngữ 2 vế khác nhau.","compare":"","examples":[{"jp":"大学に入るために、たくさん練習しました。","vn":"Để vào được đại học, tôi đã luyện tập rất nhiều."},{"jp":"世界の平和のために、国際会議が開かれました。","vn":"Vì hòa bình thế giới, hội nghị quốc tế đã được tổ chức."},{"jp":"はさみは紙を切るのに使います。","vn":"Cái kéo được dùng để cắt giấy."}]},{"title":"Vる／Vない (vô ý chí, tự động từ, thể khả năng, chủ ngữ ngôi 3) ＋ ように – \"để...\"","formula":"","explain":"diễn tả mong muốn một trạng thái/kết quả xảy ra, mức độ cam kết nhẹ hơn ために.\nCấp độ: N4 (trọng tâm phân biệt ở N3, N2)　|　Độ lịch sự: trung tính\nThể | Công thức | Ví dụ\nKhẳng định | Vる (khả năng/vô ý chí) ＋ように | 聞こえるように\nPhủ định | Vない＋ように | 忘れないように\nQuá khứ | Mệnh đề trước không chia quá khứ; quá khứ nằm ở mệnh đề sau | 聞こえるように大きな声で話した\nNghi vấn | ～ように～か | 忘れないようにどうすればいいですか。\nchủ ngữ 2 mệnh đề có thể khác nhau (thường mệnh đề trước là ngôi thứ 3 hoặc trạng thái tự nhiên). Thể hiện sự mong muốn, cố gắng theo hướng đó, không cam kết mạnh như ために.","usage":"với tự động từ (聞こえる、見える), động từ thể khả năng (話せる、書ける), động từ vô ý chí, hoặc khi chủ ngữ mệnh đề trước là ngôi thứ 3 (子供が学校に行けるように、貯金しています。)\nKhi nào KHÔNG dùng: khi động từ trước là tha động từ có ý chí và cùng chủ ngữ với vế sau – lúc đó bắt buộc dùng ために.","compare":"","examples":[{"jp":"忘れないように、この漢字を何度も書きました。","vn":"Để không quên, tôi đã viết chữ Hán này nhiều lần."},{"jp":"子供が学校に行けるように、お金を貯金しています。","vn":"Để con có thể đi học, tôi đang tiết kiệm tiền."},{"jp":"はさみは紙を切るのに使います。","vn":"Cái kéo được dùng để cắt giấy."}]},{"title":"So sánh ために và ように","formula":"","explain":"Tiêu chí | ために | ように\nCấu trúc | Vる (ý chí) ／ 名詞の＋ために | Vる／Vない (vô ý chí, khả năng, tự động từ) ＋ように\nLoại động từ vế trước | Tha động từ, có ý chí (意志動詞) | Tự động từ, động từ thể khả năng, động từ vô ý chí\nChủ ngữ 2 vế | Bắt buộc giống nhau | Có thể khác nhau (thường ngôi thứ 3)\nMức độ ý chí | Mạnh – quyết tâm đạt bằng được | Nhẹ hơn – mong muốn, cố gắng hướng tới\nVí dụ | 大学に入るために、たくさん練習した。 | 大学に入れるように、たくさん練習した。\nMẹo phân biệt nhanh: nhìn động từ đứng ngay trước chỗ trống – nếu là tự động từ/thể khả năng/vô ý chí → ように; nếu là tha động từ có ý chí, cùng chủ ngữ → ために. Đây là điểm hay gặp trong đề thi N3, N2 (kể cả đề tháng 7/2018).","usage":"","compare":"","examples":[{"jp":"忘れないように、この漢字を何度も書きました。","vn":"Để không quên, tôi đã viết chữ Hán này nhiều lần."},{"jp":"大学に入るために、たくさん練習しました。","vn":"Để vào được đại học, tôi đã luyện tập rất nhiều."},{"jp":"子供が学校に行けるように、お金を貯金しています。","vn":"Để con có thể đi học, tôi đang tiết kiệm tiền."},{"jp":"世界の平和のために、国際会議が開かれました。","vn":"Vì hòa bình thế giới, hội nghị quốc tế đã được tổ chức."}]},{"title":"名詞＋に – diễn tả công dụng, lợi ích (\"dùng để...\", \"tốt cho...\", \"tiện lợi cho...\", \"cần thiết cho...\")","formula":"","explain":"khác hoàn toàn với ために về bản chất – không nói về mục đích/ý chí mà nói về công dụng, lợi ích của một sự vật.\nCấp độ: N4　|　Độ lịch sự: trung tính\nMẫu | Ý nghĩa | Ví dụ\nN＋に使う | dùng để... | 紙を切るのに使う\nN＋にいい | tốt cho... | 刺身は健康にいい\nN＋に便利（な） | tiện lợi cho... | 電話は連絡に便利だ\nN＋に必要（な） | cần thiết cho... | 辞書は日本語の勉強に必要だ\nN＋に役に立つ | giúp ích cho... | 漢字は新聞を読むのに役に立つ","usage":"ngữ pháp: động từ nhóm 3 (する) dùng trực tiếp N＋に, không cần の đứng trước (khác với động từ thường phải thêm の để danh từ hoá: 紙を切るのに使う, nhưng 連絡にする không cần の).\nkhi muốn nói một đồ vật/việc nào đó có công dụng, lợi ích, sự cần thiết cho một việc khác.\nKhi nào KHÔNG dùng: không dùng để diễn tả mục đích chủ động của người nói (trường hợp đó dùng ために/ように).","compare":"","examples":[{"jp":"はさみは紙を切るのに使います。","vn":"Cái kéo được dùng để cắt giấy."},{"jp":"結婚するには少なくとも二万円は必要です。","vn":"Để kết hôn cần tối thiểu ít nhất 20.000 yên."},{"jp":"刺身は健康にいいです。","vn":"Sashimi tốt cho sức khỏe."}]},{"title":"Mở rộng: 数量詞＋は (mức tối thiểu) và 数量詞＋も (mức nhiều, \"đến tận\")","formula":"","explain":"数量詞＋は diễn tả mức tối thiểu người nói ước lượng; 数量詞＋も diễn tả người nói cảm thấy con số đó là nhiều, \"đến tận...\".\nCấp độ: N3 (kiến thức mở rộng, không có trong giáo trình chính nhưng hữu ích)\nMẫu | Ý nghĩa | Ví dụ\n数量詞＋は | tối thiểu, ít nhất | 結婚するには二万円は必要だ。\n数量詞＋も | đến tận, nhiều | 家を建てるには3000万円もかかる。","usage":"nhầm lẫn 2 trợ từ này vì chỉ khác nhau は/も nhưng nghĩa đối lập hoàn toàn (tối thiểu vs. nhiều).","compare":"","examples":[{"jp":"刺身は健康にいいです。","vn":"Sashimi tốt cho sức khỏe."},{"jp":"家を建てるのに3000万円もかかりました。","vn":"Để xây một ngôi nhà đã tốn đến tận 30 triệu yên."},{"jp":"はさみは紙を切るのに使います。","vn":"Cái kéo được dùng để cắt giấy."}]}],"43":[{"title":"Vます(bỏ ます) + そうです — \"có vẻ sắp...\"","formula":"Dạng | Công thức | Ví dụ\nKhẳng định | V-masu stem + そうです | 雨が降りそうです。\nPhủ định | V-masu stem + そうにありません / そうもありません | 雨が降りそうにありません。\nQuá khứ | V-masu stem + そうでした | 雨が降りそうでした。\nNghi vấn | V-masu stem + そうですか | 雨が降りそうですか。","explain":"diễn tả suy đoán của người nói rằng một sự việc/hành động SẮP xảy ra, dựa trên trạng thái quan sát được ngay lúc nói (chưa xảy ra).\nCấp độ: N4 (nền tảng quan trọng cho N3). Độ lịch sự: trung tính, dùng được trong cả văn nói và văn viết.\nThường đi kèm phó từ 今にも (imo — \"sắp sửa đến nơi\") để làm câu văn mềm mại, tự nhiên hơn.\nĐây là điểm ngữ pháp rất hay xuất hiện trong đề thi N3 (phần điền phó từ 今にも đi kèm そう).","usage":"Dùng khi quan sát trực tiếp một trạng thái và suy đoán điều gì đó SẮP xảy ra (dây sắp đứt, trời sắp mưa, hết ga...).\nnhầm với ý nghĩa thứ 2 của そうです (đi với tính từ) — hai cấu trúc khác nhau hoàn toàn về ý nghĩa dù cùng đuôi そうです.","compare":"","examples":[{"jp":"雨が降りそうです。","vn":"Trời có vẻ sắp mưa."},{"jp":"このピザはおいしそうです。","vn":"Bánh pizza này trông có vẻ ngon."},{"jp":"駅で新聞を買ってきます。","vn":"Tôi đi ra ga mua báo rồi về."},{"jp":"かばんの紐が今にも切れそうです。","vn":"Dây cặp có vẻ sắp đứt đến nơi rồi."}]},{"title":"い/な-tính từ (bỏ い/な) + そうです — \"trông có vẻ...\"","formula":"Dạng | Công thức | Ví dụ\nKhẳng định | い-adj (bỏ い) / な-adj (bỏ な) + そうです | この料理はおいしそうです。\nPhủ định | adj-stem + そうにありません / そうもありません | おいしそうにありません。\nQuá khứ | adj-stem + そうでした | おいしそうでした。\nNghi vấn | adj-stem + そうですか | おいしそうですか。\nTính từ gốc | Dạng そう\nいい (tốt) | よさそうです\nない (không có) | なさそうです\nかわいい (đáng yêu) | かわいそうです — LƯU Ý: đây là từ vựng cố định nghĩa \"tội nghiệp/đáng thương\", KHÔNG phải \"trông có vẻ đáng yêu\"","explain":"diễn tả phán đoán trực tiếp bằng thị giác/quan sát về tính chất của sự vật, sự việc (chưa trải nghiệm trực tiếp — chỉ nhìn mà đoán).\nCấp độ: N4. Độ lịch sự: trung tính.","usage":"CHỈ dùng khi chưa trải nghiệm trực tiếp (chưa ăn, chưa thử) — chỉ nhìn bằng mắt rồi phán đoán. Ví dụ nhìn pizza chưa ăn → おいしそうです.\nKHÔNG dùng そうです khi đã trải nghiệm trực tiếp rồi (đã ăn xong) — lúc đó dùng thẳng tính từ: おいしいです / うまいです. Đây là lỗi rất phổ biến của người học Việt Nam: ăn xong vẫn nói おいしそうです là SAI.\nKhông dùng với かわいい theo nghĩa gốc — vì かわいそう đã bị lexical hoá thành nghĩa khác (\"tội nghiệp\").","compare":"そうです ý nghĩa 1 | そうです ý nghĩa 2\nNối với | Động từ (V-masu stem) | Tính từ (い/な-adj stem)\nNghĩa | Có vẻ SẮP diễn ra hành động/sự việc | Trông CÓ VẺ có tính chất nào đó\nCăn cứ | Trạng thái quan sát trước một sự việc chưa xảy ra | Quan sát trực tiếp bằng mắt, chưa trải nghiệm","examples":[{"jp":"かわいそうです","vn":"LƯU Ý: đây là từ vựng cố định nghĩa \"tội nghiệp/đáng thương\", KHÔNG phải \"trông có vẻ đáng yêu\""},{"jp":"このピザはおいしそうです。","vn":"Bánh pizza này trông có vẻ ngon. (nhìn, chưa ăn)"},{"jp":"雨が降りそうです。","vn":"Trời có vẻ sắp mưa."},{"jp":"かばんの紐が今にも切れそうです。","vn":"Dây cặp có vẻ sắp đứt đến nơi rồi."}]},{"title":"Vて + きます — \"đi làm gì đó rồi quay lại\"","formula":"Dạng | Công thức | Ví dụ\nKhẳng định | Vて + きます | 駅で新聞を買ってきます。\nPhủ định | Vて + きません | 駅で新聞を買ってきません。\nQuá khứ | Vて + きました | 駅で新聞を買ってきました。\nNghi vấn | Vて + きますか | 駅で新聞を買ってきますか。\nMệnh lệnh nhẹ (nhờ ai làm) | Vて + きてください | お土産を買ってきてください。","explain":"biểu thị một chuỗi 3 hành động: đi đến một nơi → thực hiện hành động ở đó → quay trở lại vị trí ban đầu.\nCấp độ: N4. Độ lịch sự: trung tính, rất thông dụng trong hội thoại đời sống.\nTrợ từ chỉ nơi thực hiện hành động: で (địa điểm cố định thực hiện hành động). Khi địa điểm là nơi di chuyển một vật thể qua thì dùng を.\nCâu cửa miệng 行ってきます (tôi đi rồi sẽ về) và ちょっと出かけてきます (tôi ra ngoài một chút rồi về) rất hay dùng khi ra khỏi nhà, không cần nói rõ mục đích.","usage":"Dùng khi hành động có tính chu kỳ khép kín: đi → làm → về. Không dùng khi không có ý định quay lại (khi đó chỉ dùng V-masu/て thường).\nquên gắn きます phía sau khi diễn tả hành động \"đi làm gì rồi về\", khiến câu chỉ còn nghĩa \"đi làm gì đó\" mà mất đi ý \"sẽ quay lại\".","compare":"","examples":[{"jp":"タバコを買ってきます。","vn":"Tôi đi mua bao thuốc lá rồi về."},{"jp":"旅行に行ったら、お土産を買ってきてください。","vn":"Khi đi du lịch thì hãy mua quà mang về nhé."},{"jp":"駅で新聞を買ってきます。","vn":"Tôi đi ra ga mua báo rồi về."}]},{"title":"Vて + くれませんか — \"làm ơn ... giúp tôi được không?\"","formula":"Dạng | Công thức | Ví dụ\nNghi vấn phủ định (dạng chuẩn để nhờ) | Vて + くれませんか | 砂糖を取ってくれませんか。\nKhẳng định (ít lịch sự hơn) | Vて + くれますか | 砂糖を取ってくれますか。\nThân mật/suồng sã | Vて + くれない? | 砂糖を取ってくれない?\nMức | Mẫu câu | Đối tượng dùng\n1 (thấp nhất) | Vてください | Mệnh lệnh nhẹ, chỉ dùng cho người dưới\n2 (bài 43) | Vてくれませんか | Người ngang hàng hoặc người dưới mình\n3 | Vてくださいませんか | Lịch sự hơn, có thể dùng với người trên\n4 (cao nhất) | Vていただけませんか | Rất lịch sự, dùng với người trên/khách hàng","explain":"nhờ vả người nghe thực hiện một hành động giúp mình, với thái độ lịch sự.\nCấp độ: N4. Độ lịch sự: trung bình — lịch sự hơn てください nhưng kém lịch sự hơn ていただけませんか.","usage":"CHỈ dùng với người ngang hàng hoặc người dưới mình. TUYỆT ĐỐI không dùng với người trên/cấp trên/khách hàng — đây là lỗi rất nghiêm trọng về phép lịch sự.\nNgười học Việt Nam hay nhầm てくれませんか với ていただけませんか vì cả hai đều dịch là \"làm ơn giúp tôi...\" nhưng mức độ lịch sự khác hẳn nhau.","compare":"","examples":[{"jp":"Vてください","vn":"Mệnh lệnh nhẹ, chỉ dùng cho người dưới"},{"jp":"Vてくれませんか","vn":"Người ngang hàng hoặc người dưới mình"},{"jp":"Vてくださいませんか","vn":"Lịch sự hơn, có thể dùng với người trên"},{"jp":"Vていただけませんか","vn":"Rất lịch sự, dùng với người trên/khách hàng"},{"jp":"砂糖を取ってくれませんか。","vn":"Lấy giúp tôi một ít đường được không?"}]}],"44":[{"title":"Vます-すぎます / いAすぎます / なAすぎます — \"quá...\"","formula":"Dạng | Cấu trúc | Ví dụ\nKhẳng định | V(ます bỏ ます)+すぎます | 食べすぎます (ăn quá nhiều)\nPhủ định | V(ます bỏ ます)+すぎません | 食べすぎません\nQuá khứ | V(ます bỏ ます)+すぎました | 食べすぎました\nQuá khứ phủ định | V(ます bỏ ます)+すぎませんでした | 食べすぎませんでした\nい-tính từ | い bỏ い +すぎます | 痛い→痛すぎます (quá đau)\nな-tính từ | な bỏ な +すぎます | ハンサムな→ハンサムすぎます (quá đẹp trai)\nNghi vấn | …すぎますか | 食べすぎますか","explain":"Diễn tả một động tác, trạng thái, tính chất vượt quá mức độ bình thường / mong đợi.\nCấp độ: N4 | Độ lịch sự: trung tính, dùng được cả văn nói và văn viết.\nすぎます mang hàm ý tiêu cực (vượt quá mức bình thường, không tốt) — KHÔNG dùng để bày tỏ lời khen/cảm ơn kiểu \"ăn nhiều/ngon quá\" như thói quen tiếng Việt.\nすぎます là động từ nhóm 2 (kết thúc bằng đuôi ます như nhóm 2 thông thường): thể て → すぎて, thể た → すぎた.","usage":"Dùng: diễn tả việc vượt mức khiến kết quả không tốt. VD: 働きすぎて病気になりました (làm việc quá nhiều nên bị ốm).\nKHÔNG dùng khi được mời ăn thêm và muốn nói lịch sự \"đủ rồi, cảm ơn\" — người Nhật dùng もう十分です / けっこうです, KHÔNG dùng もう食べすぎました (nghe như đang chê/phàn nàn).\nhọc viên Việt Nam quen dịch word-by-word \"quá\" = すぎます trong mọi ngữ cảnh khen ngợi, dẫn đến câu mang nghĩa tiêu cực ngoài ý muốn.","compare":"","examples":[{"jp":"食べすぎます","vn":"ăn quá nhiều"},{"jp":"痛い→痛すぎます","vn":"quá đau"},{"jp":"ハンサムな→ハンサムすぎます","vn":"quá đẹp trai"},{"jp":"A：何にしますか。 B：私はこれにします。","vn":"A: Anh/chị chọn gì? B: Tôi chọn cái này."}]},{"title":"Vます-やすいです — \"dễ làm gì đó\"","formula":"","explain":"động tác đó có thể thực hiện một cách dễ dàng, hoặc dễ xảy ra. Cấp độ N4, trung tính.\nDạng | Cấu trúc | Ví dụ\nKhẳng định | V(ます bỏ ます)+やすいです | 読みやすいです (dễ đọc)\nPhủ định | V(ます bỏ ます)+やすくないです | 読みやすくないです\nQuá khứ | V(ます bỏ ます)+やすかったです | 読みやすかったです\nQuá khứ phủ định | V(ます bỏ ます)+やすくなかったです | 読みやすくなかったです\nNghi vấn | …やすいですか | 読みやすいですか\nやすい được chia giống tính từ đuôi い (vì kết thúc bằng い) — chia phủ định/quá khứ theo quy tắc tính từ い.\nDùng khi: mô tả đặc tính khách quan của sự vật/hành động dễ thực hiện. VD: この漢字は読みやすいです。","usage":"nhầm やすい (dễ) với 安い (rẻ) — hai từ đồng âm, học viên cần phân biệt qua ngữ cảnh và kanji.","compare":"","examples":[{"jp":"読みやすいです","vn":"dễ đọc"},{"jp":"A：何にしますか。 B：私はこれにします。","vn":"A: Anh/chị chọn gì? B: Tôi chọn cái này."},{"jp":"お酒を飲みすぎないでください。","vn":"Xin đừng uống rượu quá nhiều."}]},{"title":"Vます-にくいです — \"khó làm gì đó\" (đối lập với やすいです)","formula":"","explain":"động tác đó khó thực hiện, hoặc khó xảy ra. Cấp độ N4, trung tính.\nDạng | Cấu trúc | Ví dụ\nKhẳng định | V(ます bỏ ます)+にくいです | 飲みにくいです (khó uống)\nPhủ định | V(ます bỏ ます)+にくくないです | 飲みにくくないです\nQuá khứ | V(ます bỏ ます)+にくかったです | 飲みにくかったです\nQuá khứ phủ định | V(ます bỏ ます)+にくくなかったです | 飲みにくくなかったです\nNghi vấn | …にくいですか | 飲みにくいですか","usage":"chia sai vì quên にくい cũng là tính từ đuôい い (không phải danh từ), nên phủ định phải là にくくないです chứ không phải にくいじゃないです.","compare":"hai mẫu đối lập nhau hoàn toàn về nghĩa nhưng cùng cấu trúc V(ます bỏ ます) + やすい/にくい, chia như tính từ đuôい い.","examples":[{"jp":"飲みにくいです","vn":"khó uống"},{"jp":"この本は字が小さくて、読みにくいです。","vn":"Cuốn sách này chữ nhỏ nên khó đọc."},{"jp":"A：何にしますか。 B：私はこれにします。","vn":"A: Anh/chị chọn gì? B: Tôi chọn cái này."}]},{"title":"Nに/Aさに/Naに + します — hai nghĩa","formula":"","explain":"Nghĩa 1 — Làm cho trở thành: thay đổi một sự vật/trạng thái sang trạng thái khác, có ý chí của người nói.\nNghĩa 2 — Chọn/quyết định: N + にします — lựa chọn hoặc quyết định một điều gì đó (dùng khi gọi món, chọn đồ, chọn lịch...).\nDạng | Cấu trúc | Ví dụ\nKhẳng định | N/Aさ/Na + にします | 部屋を きれいに します (làm cho phòng sạch lên)\nPhủ định | …にしません | 部屋を きれいに しません\nQuá khứ | …にしました | 私はこれにしました (tôi đã chọn cái này)\nQuá khứ phủ định | …にしませんでした | これにしませんでした\nNghi vấn | …にしますか | 何にしますか (bạn chọn gì?)\ntính từ đuôい い bỏ い + くします (VD: 短くします – làm cho ngắn đi); tính từ đuôい な bỏ な + にします (VD: きれいにします).","usage":"có chủ thể tác động chủ ý làm thay đổi trạng thái của đối tượng (khác với thể tự động từ chỉ trạng thái tự nhiên xảy ra).\nnhầm にします (có ý chí, chủ động thay đổi) với になります (tự nhiên trở thành, không có chủ ý) — đây là hai mẫu ngữ pháp dễ nhầm cần phân biệt kỹ.","compare":"","examples":[{"jp":"部屋を きれいに します","vn":"làm cho phòng sạch lên"},{"jp":"私はこれにしました","vn":"tôi đã chọn cái này"},{"jp":"何にしますか","vn":"bạn chọn gì?"},{"jp":"A：何にしますか。 B：私はこれにします。","vn":"A: Anh/chị chọn gì? B: Tôi chọn cái này."}]}],"45":[{"title":"～ば (ba) — Nếu... thì... / Trong trường hợp...","formula":"Từ loại | Cách chia trước ば\nĐộng từ (V) | Đổi đuôi う→え, く→け, ぐ→げ, す→せ, つ→て, ぬ→ね, ぶ→べ, む→め, る→れ + ば\n(VD: 起きる→起きれば, 行く→行けば)\nTính từ đuôi い (Adj-i) | Bỏ い, thêm ければ\n(VD: 高い→高ければ)\nTính từ đuôi な (Adj-na) | Thân từ + であれば / ならば\n(VD: 静か→静かであれば)\nDanh từ (N) | N + であれば / ならば\n(VD: 学生→学生であれば)\nKhẳng định: 地震が来れば、机の下に隠れてください。(Nếu động đất xảy ra thì hãy chui xuống gầm bàn.)\nPhủ định: Vば phủ định dùng dạng ～なければ (VD: 行かなければ = nếu không đi thì...)\nQuá khứ: ～ば không chia trực tiếp ở thì quá khứ; giả định thường hướng tới tương lai/hiện tại. Nếu cần diễn tả điều kiện đã xảy ra, dùng ～たら thay thế.\nNghi vấn: どうすればいいですか。(Phải làm thế nào thì tốt?) — mẫu hỏi rất thông dụng kết hợp với ば.","explain":"Diễn tả một trường hợp giả định có thể xảy ra (vế trước), theo sau là cách xử lý/biện pháp đối phó hoặc kết quả (vế sau).\nCấp độ: N4\nĐộ lịch sự: Trung tính, dùng được trong cả văn nói và văn viết; thường mang tính đưa ra lời khuyên/hướng dẫn khách quan.\nVế trước ば luôn mang tính chất giả định (chưa chắc chắn xảy ra), không phải sự thật đã diễn ra.\nVế sau thường là: lời khuyên, biện pháp xử lý, hoặc kết quả tự nhiên xảy ra khi điều kiện ở vế trước được thỏa mãn.\nCấu trúc rất phổ biến trong mẫu hỏi đường/hỏi cách xử lý: ～ばいいですか, ～ばいいですか。","usage":"Dùng khi: đưa ra lời khuyên, hướng dẫn cách xử lý cho một tình huống giả định (VD: nếu bị ốm thì phải liên lạc nhà trường; nếu tiền thừa không ra thì gạt cần gạt).\nKhông dùng khi: muốn diễn tả một sự việc đã chắc chắn xảy ra trong quá khứ — khi đó nên dùng ～たら hoặc câu trần thuật thông thường.\nngười học Việt Nam hay chia nhầm ば giống hệt たら hoặc quên đổi đuôi động từ nhóm 1 đúng hàng e (VD: 飲む→飲めば chứ không phải 飲むば).\nnhầm nghĩa 'nếu...thì' kiểu điều kiện tình cảm (nếu thích em thì hãy nói) — ば ở đây KHÔNG mang sắc thái đó mà là giả định khách quan, mang tính hướng dẫn/biện pháp.","compare":"Mẫu | Đặc điểm chính\nば | Giả định khách quan, thường đi với lời khuyên/biện pháp xử lý; nhấn mạnh điều kiện.\nたら | Linh hoạt nhất, dùng được cho cả giả định và sự việc đã xảy ra, sắc thái tự nhiên trong hội thoại.\nと | Kết quả xảy ra tất yếu, quy luật (VD: 春になると桜が咲く).\nなら | Giả định dựa trên điều đối phương vừa nói, thường đặt lời khuyên ngay sau.","examples":[{"jp":"地震が来れば、机の下に隠れてください。","vn":"Nếu động đất xảy ra thì hãy chui xuống gầm bàn."},{"jp":"どうすればいいですか。","vn":"Phải làm thế nào thì tốt?"},{"jp":"お釣りが出なければ、レバーを引いてください。","vn":"Nếu tiền thừa không ra thì hãy gạt cái cần gạt này."}]},{"title":"～のに (noni) — Thế mà.../ Vậy mà...","formula":"Từ loại | Cách chia trước のに\nĐộng từ (V) | Thể thông thường + のに\n(VD: 行く→行くのに, 行かない→行かないのに)\nTính từ đuôi い | Thể thông thường + のに\n(VD: 高い→高いのに)\nTính từ đuôi な | Thân từ + な + のに\n(VD: 静か→静かなのに)\nDanh từ (N) | N + な + のに\n(VD: 学生→学生なのに)\nKhẳng định: N1に合格したのに、日本語が話せない。(Đã đỗ N1 vậy mà không nói được tiếng Nhật.)\nPhủ định: Vế trước hoặc vế sau đều có thể ở dạng phủ định tùy ngữ cảnh: 勉強しなかったのに、合格した。(Không học vậy mà vẫn đỗ.)\nQuá khứ: Vた + のに (VD: 頑張ったのに、結果が出なかった。— Đã cố gắng vậy mà kết quả không như mong muốn.)\nNghi vấn/mệnh lệnh: Vế sau KHÔNG dùng thể ý chí, yêu cầu hay nhờ vả — chỉ dùng để trần thuật/than phiền.","explain":"Diễn tả kết quả/sự việc ở vế sau trái ngược với điều đương nhiên/mong đợi được suy ra từ vế trước, thể hiện tâm trạng bất ngờ, tiếc nuối hoặc bất mãn của người nói.\nCấp độ: N4 (nền tảng quan trọng cho N3, N2)\nĐộ lịch sự: Thường dùng trong văn nói, mang cảm xúc chủ quan mạnh (than phiền, tiếc nuối).\nVế sau luôn thể hiện điều trái ngược với những gì người nói cho là đương nhiên phải xảy ra ở vế trước.\nSắc thái cảm xúc: bất ngờ, tiếc nuối, hoặc bất mãn/kêu ca — không chỉ đơn thuần là 'nhưng mà' trung tính.","usage":"Dùng khi: muốn than phiền, tiếc nuối, hoặc bày tỏ sự bất ngờ về một kết quả trái với kỳ vọng (VD: đã 10 giờ sáng vậy mà em trai vẫn chưa dậy).\nKhông dùng khi: vế sau là câu mệnh lệnh, yêu cầu, hoặc thể hiện ý chí của người nói — のに không tương thích với các thể này.\nngười học nhầm のに với で (Bài 44: mục đích sử dụng, dùng để...) — hai từ đọc gần giống nhưng nghĩa hoàn toàn khác nhau.\ndùng のに thay cho が/けど khi câu không mang sắc thái tiếc nuối/bất mãn mà chỉ là tương phản trung tính — khi đó nên dùng が hoặc けど.","compare":"Mẫu | Đặc điểm chính\nのに | Tương phản + cảm xúc mạnh (tiếc nuối/bất ngờ/bất mãn); vế sau không dùng thể ý chí, mệnh lệnh.\nけど / が | Tương phản trung tính, không nhất thiết mang cảm xúc; vế sau dùng được mọi thể loại câu kể cả mệnh lệnh, ý chí.","examples":[{"jp":"N1に合格したのに、日本語が話せない。","vn":"Đã đỗ N1 vậy mà không nói được tiếng Nhật."},{"jp":"お金持ちなのに、けちだ。","vn":"Giàu có vậy mà lại keo kiệt."},{"jp":"10時なのに、弟はまだ起きない。","vn":"Đã 10 giờ rồi vậy mà em trai tôi vẫn chưa dậy."},{"jp":"キャンプの準備をしたのに、雨が降ったので中止になった。","vn":"Đã chuẩn bị cắm trại vậy mà trời mưa nên phải hủy."}]}],"46":[{"title":"Vるところです — sắp sửa, chuẩn bị làm gì đó","formula":"Dạng | Cấu trúc | Ví dụ\nKhẳng định | V(る)＋ところです | 食べるところです\nPhủ định | Không dùng dạng phủ định trực tiếp (diễn tả bằng cách khác) | —\nQuá khứ | Không có — đổi sang Vたところです (nhóm khác) | —\nNghi vấn | V(る)＋ところですか | 食べるところですか","explain":"Hành động sắp sửa / chuẩn bị diễn ra, nhấn mạnh vào thời điểm ngay trước khi hành động xảy ra — hành động CHƯA diễn ra.\nCấp độ: N4  |  Độ lịch sự: trung tính, dùng được cả văn nói lẫn văn viết\nThường đi kèm các trạng từ chỉ thời điểm: 今から (từ bây giờ), ちょうど (vừa lúc), これから (từ đây trở đi)\nKhoảng thời gian tới khi hành động xảy ra rất ngắn — \"chỉ còn một chút nữa là xảy ra\"","usage":"Dùng khi muốn nhấn mạnh hành động chưa xảy ra nhưng sắp xảy ra ngay lập tức\nngười học Việt Nam hay nhầm Vるところです với thì tương lai thông thường (ます) — Vるところです nhấn mạnh SÁT thời điểm xảy ra hơn nhiều\ntrong đề thi nghe: nghe thấy ところです liền mặc định hành động ĐÃ xảy ra — thực chất hành động vẫn CHƯA xảy ra","compare":"","examples":[{"jp":"たところです","vn":"nhóm khác"},{"jp":"これから ご飯を 食べるところです。","vn":"Dịch: Tôi sắp sửa ăn cơm."},{"jp":"今、パンを 焼いているところです。","vn":"Dịch: Tôi đang nướng bánh mì đây."}]},{"title":"Vているところです — đang làm gì đó (nhấn mạnh)","formula":"Dạng | Cấu trúc | Ví dụ\nKhẳng định | V(ている)＋ところです | パンを焼いているところです\nPhủ định | Không dùng trực tiếp | —\nQuá khứ | V(ていた)＋ところです | 調べていたところです\nNghi vấn | V(ている)＋ところですか | パンを焼いているところですか","explain":"Hành động đang diễn ra tại một thời điểm nói, nhấn mạnh hành động đang xảy ra mạnh hơn Vています thông thường.\nCấp độ: N4  |  Độ lịch sự: trung tính\nThường đi kèm 今 (bây giờ)\nSo với Vています đơn thuần, Vているところです nhấn mạnh \"tôi đang ở trong hoàn cảnh/quá trình thực hiện hành động này\"","usage":"Dùng khi cần nhấn mạnh rõ hành động đang xảy ra (ví dụ: đang bận, đừng làm phiền)\nnhầm với Vるところです — Vるところです là CHƯA xảy ra, còn Vているところです là ĐANG xảy ra","compare":"","examples":[{"jp":"今、パンを 焼いているところです。","vn":"Dịch: Tôi đang nướng bánh mì đây."},{"jp":"この魚は 新鮮ですから、おいしいはずです。","vn":"Dịch: Vì con cá này tươi nên chắc chắn sẽ ngon."},{"jp":"これから ご飯を 食べるところです。","vn":"Dịch: Tôi sắp sửa ăn cơm."}]},{"title":"Vたところです — vừa mới làm xong (khách quan, rất gần)","formula":"Dạng | Cấu trúc | Ví dụ\nKhẳng định | V(た)＋ところです | 駅に着いたところです\nPhủ định | Không dùng trực tiếp | —\nQuá khứ | Chính bản thân đã ở dạng quá khứ (Vた) | —\nNghi vấn | V(た)＋ところですか | 駅に着いたところですか","explain":"Hành động vừa mới kết thúc, nhấn mạnh thời điểm ngay sau khi hoàn thành — khoảng thời gian rất ngắn (theo cảm nhận chung, khoảng 1 phút).\nCấp độ: N4  |  Độ lịch sự: trung tính\nChỉ đi kèm được với trạng từ chỉ thời gian たった今 (vừa mới xong) — trong đề thi JLPT nếu thấy Vたところです thì đáp án phó từ chắc chắn là たった今\nKhoảng thời gian tính từ lúc hành động kết thúc đến lúc nói là rất ngắn, mang tính khách quan (không phụ thuộc cảm giác người nói)","usage":"Chỉ dùng khi hành động vừa kết thúc trong khoảng thời gian rất ngắn (vài chục giây đến khoảng 1 phút)\ndùng Vたところです cho hành động đã xảy ra cách đây 30 phút, 1 tiếng — sai, trường hợp này phải dùng Vたばかりです","compare":"Tiêu chí | Vたところです | Vたばかりです\nTính chất khoảng thời gian | Khách quan, cố định, rất ngắn (~1 phút) | Chủ quan, theo cảm giác người nói, có thể dài (vài phút đến vài năm)\nTrạng từ đi kèm | たった今 (bắt buộc) | Không bắt buộc trạng từ cố định\nVí dụ | たった今、着いたところです（今すぐ） | 日本に来たばかりです（半年前でもOK）","examples":[{"jp":"たった今、駅に 着いたところです。","vn":"Dịch: Tôi vừa mới đến ga xong."},{"jp":"今朝、田中さんに 連絡しましたから、会議の時間は もう知っているはずです。","vn":"Dịch: Vì sáng nay tôi đã liên lạc với anh Tanaka rồi nên chắc chắn anh ấy đã biết giờ họp."},{"jp":"これから ご飯を 食べるところです。","vn":"Dịch: Tôi sắp sửa ăn cơm."}]},{"title":"Vたばかりです — vừa mới làm gì đó (chủ quan)","formula":"Dạng | Cấu trúc | Ví dụ\nKhẳng định | V(た)＋ばかりです | ご飯を食べたばかりです\nPhủ định | Không dùng trực tiếp (diễn đạt bằng cách khác) | —\nQuá khứ | Chính bản thân đã ở dạng quá khứ (Vた) | —\nNghi vấn | V(た)＋ばかりですか | 結婚したばかりですか","explain":"Diễn đạt hành động kết thúc chưa được bao lâu — theo cảm giác chủ quan của người nói, không quy định khoảng thời gian cụ thể.\nCấp độ: N4  |  Độ lịch sự: trung tính\nKhoảng thời gian \"vừa mới\" hoàn toàn phụ thuộc cảm giác của người nói: có thể là vài phút, cũng có thể là 1 năm, 2 năm","usage":"Dùng khi muốn nhấn mạnh cảm giác chủ quan \"còn mới\", không quan tâm khoảng thời gian chính xác\nnhầm lẫn với Vたところです trong đề thi — nếu câu có mốc thời gian cụ thể như 先週 (tuần trước) thì phải chọn ばかり chứ không phải ところ (vì ところ chỉ hợp với thời điểm cực ngắn, ngay-lập-tức)","compare":"","examples":[{"jp":"先月、日本に 来たばかりです。","vn":"Dịch: Tôi mới đến Nhật tháng trước thôi."},{"jp":"二人は 結婚したばかりなのに、もう離婚したそうです。","vn":"Dịch: Hai người vừa mới cưới xong mà nghe nói đã ly hôn rồi."},{"jp":"これから ご飯を 食べるところです。","vn":"Dịch: Tôi sắp sửa ăn cơm."}]}],"47":[{"title":"～そうです (伝聞 — nghe nói, nghe đồn)","formula":"gắn そうです vào ĐUÔI THỂ THƯỜNG (ふつう形) của động từ / tính từ / danh từ.\nLoại từ | Khẳng định | Phủ định | Quá khứ\nĐộng từ | 降ります → 降るそうです | 降らないそうです | 降ったそうです\nTính từ đuôi い | 忙しい → 忙しいそうです | 忙しくないそうです | 忙しかったそうです\nTính từ đuôi な | 静かだ → 静かだそうです | 静かじゃないそうです | 静かだったそうです\nDanh từ | 雨だ → 雨だそうです | 雨じゃないそうです | 雨だったそうです\nThường đi kèm nguồn tin: 天気予報によると〜そうです (theo dự báo thời tiết thì...), 〜の話では (theo lời...)\nNghi vấn: KHÔNG dùng ～そうですか để hỏi trực tiếp — thường hỏi bằng câu khác rồi trả lời bằng そうです\nKhông chia theo chủ ngữ, không đổi thể lịch sự của そうです (luôn そうです/そうだ)\nKHÔNG dùng cho suy đoán dựa trên hình dáng/vẻ ngoài quan sát trực tiếp — đó là việc của ようです","explain":"truyền đạt lại thông tin người nói NGHE/ĐỌC được từ người khác, báo chí, dự báo thời tiết, v.v. Không phải nhận định của bản thân.","usage":"","compare":"","examples":[{"jp":"天気予報によると、明日は雨だそうです。","vn":"Theo dự báo thời tiết, ngày mai trời sẽ mưa."},{"jp":"このラーメンはおいしそうです。","vn":"Món ramen này trông có vẻ ngon."},{"jp":"ニュースによると、来月新しい製品が発売されるそうです。","vn":"Theo tin tức, tháng sau sản phẩm mới sẽ được phát hành."},{"jp":"山田さんの話では、来週から忙しくなるそうです。","vn":"Theo lời anh Yamada, từ tuần sau sẽ bận rộn hơn."}]},{"title":"～ようです (様態・推量 — có vẻ như, suy đoán)","formula":"Loại từ | Khẳng định | Phủ định | Quá khứ\nĐộng từ | 降る → 降るようです | 降らないようです | 降ったようです\nTính từ đuôi い | 忙しい → 忙しいようです | 忙しくないようです | 忙しかったようです\nTính từ đuôi な | 静かだ → 静かなようです | 静かじゃないようです | 静かだったようです\nDanh từ | 雨だ → 雨のようです | 雨じゃないようです | 雨だったようです","explain":"người nói suy đoán/nhận định dựa trên những gì mình QUAN SÁT, CẢM NHẬN được (nhìn, nghe, sờ...), mang tính chủ quan, không chắc chắn 100%.","usage":"đặc biệt: tính từ な bỏ だ thêm な (静かなようです), danh từ bỏ だ thêm の (雨のようです) — khác hẳn そうです\nCó thể dùng làm phó từ bổ nghĩa cho danh từ: ようなN, hoặc bổ nghĩa cho động từ: ように\nMang tính lịch sự, gián tiếp, người Nhật hay dùng để tránh khẳng định thẳng thừng\nNghi vấn: 〜ようですか ít dùng trực tiếp, thường dùng trong câu trần thuật","compare":"","examples":[{"jp":"田中さんは今日、具合が悪いようです。顔色が悪いですから。","vn":"Hôm nay anh Tanaka có vẻ không khỏe. Vì sắc mặt anh ấy không tốt."},{"jp":"あの二人は最近あまり一緒にいませんね。別れたようですよ。","vn":"Hai người đó gần đây không đi cùng nhau nữa nhỉ. Có vẻ như họ chia tay rồi."},{"jp":"空が急に暗くなってきました。雨が降るようですね、傘を持っていきましょう。","vn":"Trời bỗng tối sầm lại. Có vẻ sắp mưa, mang ô theo nhé."}]},{"title":"So sánh そうです vs ようです","formula":"","explain":"Tiêu chí | そうです (伝聞) | ようです (様態推量)\nNguồn thông tin | Nghe/đọc từ người khác, báo chí | Tự quan sát, cảm nhận trực tiếp\nCách nối với tính từ な/danh từ | giữ nguyên だ + そうです | bỏ だ, thêm な/の + ようです\nMức độ chắc chắn | Chỉ truyền đạt lại, không đánh giá | Suy đoán chủ quan của người nói\nVí dụ điển hình | 天気予報によると明日は雨だそうです | 空が暗いから雨が降るようです","usage":"giáo trình Minna no Nihongo KHÔNG dạy らしいです ở bài này (らしいです thuộc trình độ N3, xuất hiện ở giáo trình khác). Bài 46 trước đó đã học ところ/ばかり/はず nên không lặp lại ở bài này.","compare":"","examples":[{"jp":"天気予報によると、明日は雨だそうです。","vn":"Theo dự báo thời tiết, ngày mai trời sẽ mưa."},{"jp":"このラーメンはおいしそうです。","vn":"Món ramen này trông có vẻ ngon."},{"jp":"田中さんは今日、具合が悪いようです。顔色が悪いですから。","vn":"Hôm nay anh Tanaka có vẻ không khỏe. Vì sắc mặt anh ấy không tốt."},{"jp":"ニュースによると、来月新しい製品が発売されるそうです。","vn":"Theo tin tức, tháng sau sản phẩm mới sẽ được phát hành."},{"jp":"あの二人は最近あまり一緒にいませんね。別れたようですよ。","vn":"Hai người đó gần đây không đi cùng nhau nữa nhỉ. Có vẻ như họ chia tay rồi."}]}],"48":[{"title":"Cách chia động từ thể sai khiến (使役形)","formula":"","explain":"biến đổi động từ để diễn tả hành động \"sai khiến / cho phép / gây ra\" — cấp độ N4, có thể trung tính đến lịch sự tùy ngữ cảnh.\nNhóm 1 (五段動詞): đuôi い → あ + せる\nTừ điển | Thể sai khiến | Nghĩa\n書く (かく) | 書かせる (かかせる)\n読む (よむ) | 読ませる (よませる)\n買う (かう) | 買わせる (かわせる)\n行く (いく) | 行かせる (いかせる)\nQuy tắc: đổi đuôi い (hàng い) → あ (hàng あ) rồi cộng せる. Lưu ý: động từ đuôi う → わ (không phải あ).\nNhóm 2 (一段動詞): bỏ る + させる\nTừ điển | Thể sai khiến | Nghĩa\n食べる (たべる) | 食べさせる (たべさせる)\n見る (みる) | 見させる (みさせる)\n寝る (ねる) | 寝させる (ねさせる)\nNhóm 3 (bất quy tắc)\nTừ điển | Thể sai khiến | Nghĩa\nする | させる\n来る (くる) | 来させる (こさせる)\nGhi chú nhận diện: động từ đuôi せる = thể sai khiến; đuôi れる/られる = thể bị động hoặc thể khả năng (phân biệt theo ngữ cảnh).","usage":"","compare":"","examples":[{"jp":"母は娘を自由に遊ばせました。","vn":"Dịch: Mẹ cho phép con gái chơi tự do."},{"jp":"私は子供のとき、体が弱くて母を心配させました。","vn":"Dịch: Khi tôi còn nhỏ, vì cơ thể yếu nên tôi đã làm mẹ lo lắng."},{"jp":"部長は田中さんを大阪へ出張させました。","vn":"Dịch: Trưởng phòng cho/bắt anh Tanaka đi công tác Osaka."}]},{"title":"Ba nghĩa của thể sai khiến","formula":"","explain":"Nghĩa | Diễn giải | Ví dụ ngắn\n部長は田中さんを出張させました。\n母は娘を自由に遊ばせました。\n私は母を心配させました。","usage":"quan trọng: nghĩa ① và ② luôn đi theo chiều trên→dưới; riêng nghĩa ③ (gây ra cảm xúc) có thể đi theo chiều dưới→trên (con cái làm bố mẹ lo lắng, buồn, yên tâm...) — đây là điểm học viên hay bỏ sót.","compare":"","examples":[{"jp":"私は母を心配させました。","vn":"quan trọng: nghĩa ① và ② luôn đi theo chiều trên→dưới; riêng nghĩa ③ (gây ra cảm xúc) có thể đi theo chiều dưới→trên (con cái làm bố mẹ lo lắng, buồn, yên tâm...)"},{"jp":"私は彼女を悲しませてしまいました。","vn":"Dịch: Tôi đã lỡ làm cho người yêu buồn."},{"jp":"母は娘を自由に遊ばせました。","vn":"Dịch: Mẹ cho phép con gái chơi tự do."}]},{"title":"Quy tắc trợ từ bất biến (rất quan trọng)","formula":"","explain":"Quy tắc: một câu có động từ thể sai khiến BẮT BUỘC phải có đúng MỘT trợ từ を hoặc に đứng trước đối tượng bị tác động — không được có cả hai.\nTrường hợp | Quy tắc trợ từ | Ví dụ\n部長は田中さんを大阪へ出張させました。\n先生は学生に宿題をさせました。","usage":"","compare":"","examples":[{"jp":"部長は田中さんを大阪へ出張させました。","vn":"Dịch: Trưởng phòng cho/bắt anh Tanaka đi công tác Osaka."},{"jp":"母は娘を自由に遊ばせました。","vn":"Dịch: Mẹ cho phép con gái chơi tự do."},{"jp":"先生は学生に宿題をさせました。","vn":"Dịch: Giáo viên bắt học sinh làm bài tập về nhà."}]},{"title":"So sánh: Vて＋いただけませんか vs V使役て＋いただけませんか","formula":"Động từ thể sai khiến → chia thể て → cộng いただけませんか。\nDạng | Công thức | Ví dụ (休む → 休ませる)\nV使役て形＋いただけませんか | 休ませていただけませんか。\nV使役て形＋もいい？ | 休ませてもいい？","explain":"Đây là 2 cấu trúc rất dễ nhầm vì hình thức gần giống nhau nhưng nghĩa ngược nhau hoàn toàn — video nhấn mạnh phải phân biệt thật kỹ.\nCấu trúc | Người thực hiện hành động | Nghĩa | Ví dụ\n手伝っていただけませんか。\n休ませていただけませんか。","usage":"","compare":"","examples":[{"jp":"すみません、用事がありますので、今日は早退させていただけませんか。","vn":"Dịch: Xin lỗi, vì tôi có việc bận nên hôm nay cho phép tôi về sớm được không ạ?"},{"jp":"先生、頭が痛いので、休ませていただけませんか。","vn":"Dịch: Thưa thầy, vì em bị đau đầu nên cho phép em được nghỉ ạ."},{"jp":"母は娘を自由に遊ばせました。","vn":"Dịch: Mẹ cho phép con gái chơi tự do."}]},{"title":"Khi nào dùng / không dùng — lỗi thường gặp","formula":"","explain":"Dùng khi: cấp trên ra lệnh/cho phép cấp dưới; khi diễn tả một hành động gây ra cảm xúc cho người khác; khi xin phép được làm gì đó một cách lịch sự.\nKhông dùng khi: người dưới sai khiến hoặc cho phép người trên (trừ trường hợp nghĩa ③ gây ra cảm xúc).","usage":"nhầm を và に khi câu đã có sẵn một trợ từ を trong cụm động từ (ví dụ 宿題をさせる mà lại thêm を cho người, phải dùng に).\nnhầm chiều nghĩa của V使役て＋いただけませんか — hiểu lầm là nhờ người nghe làm, trong khi thực chất là xin phép cho BẢN THÂN làm.","compare":"","examples":[{"jp":"先生は学生に宿題をさせました。","vn":"Dịch: Giáo viên bắt học sinh làm bài tập về nhà."},{"jp":"母は娘を自由に遊ばせました。","vn":"Dịch: Mẹ cho phép con gái chơi tự do."},{"jp":"部長は田中さんを大阪へ出張させました。","vn":"Dịch: Trưởng phòng cho/bắt anh Tanaka đi công tác Osaka."}]}],"49":[{"title":"Khái niệm Tôn kính ngữ (尊敬語)","formula":"","explain":"cách nói đề cao, thể hiện sự kính trọng đối với hành động/trạng thái của người có địa vị hoặc tuổi tác cao hơn người nói.\nCấp độ / độ lịch sự: N4, mức độ lịch sự cao nhất trong giao tiếp trang trọng (kính ngữ).","usage":"(1) với người có địa vị/tuổi tác cao hơn mình; (2) với người chưa thân/mới gặp lần đầu; (3) trong quan hệ đối tác, khách hàng.\nKhi nào KHÔNG dùng: không dùng Tôn kính ngữ cho chính hành động của bản thân mình hoặc người trong nhóm mình khi nói với người ngoài nhóm (nhóm ngoài).\ndùng nhầm Tôn kính ngữ cho hành động của chính mình (VD: nói 「私がいらっしゃいます」 thay vì phải dùng Khiêm nhường ngữ 「私が参ります」).","compare":"","examples":[{"jp":"どうぞ、おかけください。","vn":"Xin mời anh/chị ngồi."},{"jp":"少々お待ちください。","vn":"Xin quý khách vui lòng đợi một chút."},{"jp":"お待たせいたしました。どうぞ召し上がってください。","vn":"Xin lỗi đã để quý khách đợi lâu. Xin mời dùng bữa."}]},{"title":"Khái niệm Khiêm nhường ngữ (謙譲語)","formula":"","explain":"cách nói hạ thấp bản thân (hoặc hành động của người trong nhóm mình) để gián tiếp thể hiện sự kính trọng đối với người nghe/người trên.\nCấp độ / độ lịch sự: N4, mức độ lịch sự cao, dùng song song với Tôn kính ngữ trong cùng một cuộc hội thoại.","usage":"khi bản thân người nói (hoặc người cùng nhóm/công ty/gia đình mình) là người thực hiện hành động, và người nghe ở vị trí cao hơn hoặc là người ngoài nhóm (khách hàng, đối tác).\nKhi nào KHÔNG dùng: không dùng Khiêm nhường ngữ để mô tả hành động của người khác (người trên, khách hàng) — sẽ bị hiểu là hạ thấp người nghe, mất lịch sự.\nnhầm lẫn giữa Tôn kính ngữ và Khiêm nhường ngữ khi nói về người trong công ty mình với đối tác bên ngoài — phải dùng Khiêm nhường ngữ cho người trong công ty mình (kể cả giám đốc) khi nói với khách hàng/đối tác.","compare":"","examples":[{"jp":"少々お待ちください。","vn":"Xin quý khách vui lòng đợi một chút."},{"jp":"どうぞ、おかけください。","vn":"Xin mời anh/chị ngồi."},{"jp":"お待たせいたしました。どうぞ召し上がってください。","vn":"Xin lỗi đã để quý khách đợi lâu. Xin mời dùng bữa."}]},{"title":"Thể lịch sự (丁寧語) — so sánh nhanh","formula":"","explain":"Thể lịch sự (です/ます) dùng khi không cần thiết phải dùng Tôn kính ngữ hay Khiêm nhường ngữ — tức là giao tiếp lịch sự thông thường, không phân biệt rõ trên dưới hoặc nhóm trong/ngoài. Đây là mức lịch sự cơ bản, còn Tôn kính ngữ/Khiêm nhường ngữ là mức kính ngữ nâng cao hơn, áp dụng có điều kiện.","usage":"","compare":"","examples":[{"jp":"お待たせいたしました。どうぞ召し上がってください。","vn":"Xin lỗi đã để quý khách đợi lâu. Xin mời dùng bữa."},{"jp":"どうぞ、おかけください。","vn":"Xin mời anh/chị ngồi."},{"jp":"少々お待ちください。","vn":"Xin quý khách vui lòng đợi một chút."}]},{"title":"Quy tắc 2 bước chọn Tôn kính ngữ hay Khiêm nhường ngữ","formula":"","explain":"Bước 1: Xác định AI là người thực hiện hành động (chủ ngữ thực hiện động từ).\nBước 2: Xác định người đó ở vị trí CAO hơn hay THẤP hơn mình (hoặc thuộc nhóm ngoài/nhóm trong).\nNếu người thực hiện hành động ở vị trí CAO hơn (khách hàng, cấp trên, người ngoài nhóm) → dùng Tôn kính ngữ.\nNếu người thực hiện hành động là bản thân mình (hoặc người nhóm trong khi nói với nhóm ngoài) → dùng Khiêm nhường ngữ.","usage":"trong câu hỏi và câu mệnh lệnh, người TIẾP NHẬN hành động luôn là người thực hiện hành động.","compare":"","examples":[{"jp":"先生、この写真を拝見してもよろしいですか。","vn":"Thưa cô, em có thể xem bức ảnh này được không ạ?"},{"jp":"どうぞ、おかけください。","vn":"Xin mời anh/chị ngồi."},{"jp":"少々お待ちください。","vn":"Xin quý khách vui lòng đợi một chút."}]},{"title":"Khái niệm nhóm trong (内・うち) và nhóm ngoài (外・そと)","formula":"","explain":"Nhóm trong: bao gồm tất cả thành viên trong nội bộ công ty mình (hoặc gia đình mình) — kể cả giám đốc. Trong nội bộ nhóm trong, cấp dưới dùng Tôn kính ngữ với cấp trên, cấp trên không cần dùng Tôn kính ngữ với cấp dưới.\nNhóm ngoài: là công ty đối tác, khách hàng, hoặc bất kỳ ai không thuộc nội bộ công ty/gia đình mình.\nQuy tắc khi nhóm trong giao tiếp với nhóm ngoài: mọi thành viên trong nhóm trong (kể cả giám đốc) đều phải dùng Khiêm nhường ngữ khi nói về hành động của người trong nhóm mình, và dùng Tôn kính ngữ khi nói về hành động của người thuộc nhóm ngoài — không còn phân biệt cấp bậc nội bộ nữa.","usage":"","compare":"","examples":[{"jp":"田中はただいま外出しております。戻りましたら、お電話するよう申し伝えます。","vn":"Anh Tanaka hiện đang ra ngoài ạ. Khi anh ấy về, tôi sẽ nhắn anh ấy gọi lại cho anh/chị."},{"jp":"どうぞ、おかけください。","vn":"Xin mời anh/chị ngồi."},{"jp":"少々お待ちください。","vn":"Xin quý khách vui lòng đợi một chút."}]},{"title":"So sánh dễ nhầm: Tôn kính ngữ vs Khiêm nhường ngữ vs Thể lịch sự","formula":"","explain":"Tiêu chí | Tôn kính ngữ | Khiêm nhường ngữ | Thể lịch sự\nChủ thể hành động | Người trên / nhóm ngoài | Bản thân / nhóm trong | Không phân biệt\nMục đích | Đề cao người khác | Hạ thấp bản thân | Lịch sự thông thường\nVí dụ (ăn) | 召し上がります | いただきます | 食べます","usage":"","compare":"","examples":[{"jp":"部長は明日の会議にいらっしゃいますか。","vn":"Ngày mai trưởng phòng có tham dự cuộc họp không ạ?"},{"jp":"どうぞ、おかけください。","vn":"Xin mời anh/chị ngồi."},{"jp":"少々お待ちください。","vn":"Xin quý khách vui lòng đợi một chút."}]},{"title":"Bảng động từ đặc biệt — Tôn kính ngữ (尊敬語)","formula":"","explain":"Động từ gốc (thể lịch sự) | Tôn kính ngữ\n行きます (đi) | 参ります／いらっしゃいます\n来ます (đến) | いらっしゃいます\nいます (ở, có mặt) | いらっしゃいます\nします (làm) | なさいます\n言います (nói) | おっしゃいます\n見ます (xem, nhìn) | ご覧になります\n食べます／飲みます (ăn/uống) | 召し上がります\nくれます (cho, tặng) | くださいます\n知っています (biết) | ご存知です","usage":"行きます và 来ます cùng chuyển thành いらっしゃいます khi tôn kính; riêng khi diễn tả \"đi/đến/có mặt\" một cách trang trọng đơn thuần cũng có thể dùng 参られます nhưng ít dùng bằng いらっしゃいます.","compare":"","examples":[{"jp":"くれます","vn":"cho, tặng"},{"jp":"知っています","vn":"biết"},{"jp":"どうぞ、おかけください。","vn":"Xin mời anh/chị ngồi."}]},{"title":"Bảng động từ đặc biệt — Khiêm nhường ngữ (謙譲語)","formula":"","explain":"Động từ gốc (thể lịch sự) | Khiêm nhường ngữ\n行きます／来ます (đi/đến) | 参ります\nいます (ở, có mặt) | おります\nします (làm) | いたします\n言います (nói) | 申します\n見ます (xem, nhìn) | 拝見します\n食べます／飲みます／もらいます (ăn/uống/nhận) | いただきます\n知っています (biết) | 存じております\n聞きます／尋ねます／訪問します (nghe/hỏi/thăm) | 伺います\n会います (gặp) | お目にかかります","usage":"","compare":"","examples":[{"jp":"知っています","vn":"biết"},{"jp":"どうぞ、おかけください。","vn":"Xin mời anh/chị ngồi."},{"jp":"少々お待ちください。","vn":"Xin quý khách vui lòng đợi một chút."}]},{"title":"Công thức tổng quát","formula":"","explain":"Khẳng định: chia động từ đặc biệt + ます (VD: いらっしゃいます / 参ります)\nPhủ định: chia động từ đặc biệt + ません (VD: いらっしゃいません / 参りません)\nQuá khứ: chia động từ đặc biệt + ました / ませんでした (VD: いらっしゃいました / 参りました)\nNghi vấn: thêm か cuối câu (VD: いらっしゃいますか。)","usage":"","compare":"","examples":[{"jp":"どうぞ、おかけください。","vn":"Xin mời anh/chị ngồi."},{"jp":"少々お待ちください。","vn":"Xin quý khách vui lòng đợi một chút."},{"jp":"お待たせいたしました。どうぞ召し上がってください。","vn":"Xin lỗi đã để quý khách đợi lâu. Xin mời dùng bữa."}]}],"50":[{"title":"Nguyên tắc xác định thể (áp dụng cho toàn bộ bài)","formula":"","explain":"Bước 1: Xác định AI là người thực hiện hành động trong câu.\nBước 2: So sánh địa vị/tuổi tác của người đó với người nói (cao hơn hay thấp hơn).\nNếu người thực hiện hành động ở địa vị CAO hơn người nói → dùng Tôn kính ngữ (尊敬語).\nNếu người thực hiện hành động là bản thân người nói (hoặc người cùng nhóm/phía với người nói — nhóm trong) → dùng Khiêm nhường ngữ (謙譲語) để hạ mình, nâng cao vị thế người nghe.\nTrong câu hỏi/câu mệnh lệnh, người TIẾP NHẬN luôn là người thực hiện hành động — cần xác định địa vị của người tiếp nhận để chọn thể phù hợp.\nVới khách hàng/đối tác: khách hàng luôn ở vị thế cao hơn (dùng Tôn kính ngữ với khách); người trong công ty mình — kể cả giám đốc — khi nói chuyện với đối tác bên ngoài đều thuộc \"nhóm trong\", phải dùng Khiêm nhường ngữ khi nhắc đến hành động của họ, KHÔNG được dùng Tôn kính ngữ.\nSự việc/sự vật không liên quan đến hành vi của người nói lẫn người nghe (VD: giới thiệu đồ vật, vị trí) → chỉ cần dùng thể lịch sự (です/ます, でございます), không cần tôn kính/khiêm nhường.","usage":"","compare":"","examples":[{"jp":"少々お待ちください。","vn":"Xin quý khách đợi cho một chút."},{"jp":"先生の結婚式の写真を拝見しました。","vn":"Tôi đã xem ảnh cưới của thầy/cô rồi."},{"jp":"時間が変わりましたら、お客様にご連絡します。","vn":"Nếu có thay đổi về thời gian, chúng tôi sẽ thông báo cho quý khách."}]},{"title":"Tôn kính ngữ (尊敬語) — Cách 1: Thể bị động","formula":"Dạng | Công thức | Ví dụ\nKhẳng định | Vれる/られる (chỉ dùng động từ nhóm II) | 来ます → 来られます (来る thuộc nhóm III nhưng ví dụ minh hoạ mức độ nghĩa; áp dụng chuẩn: 帰る→帰られる)\nPhủ định | Vれません/られません | 帰られません\nQuá khứ | Vれました/られました | 田中さんが来られました\nNghi vấn | Vれますか/られますか | 部長は何時に来られますか\nGhi chú: Cách này CHỈ áp dụng cho động từ nhóm II. Không dùng với động từ nhóm I và nhóm III (nhóm III đã có động từ đặc biệt riêng).","explain":"Mẫu câu: Động từ nhóm II (thể bị động) → thể hiện sự tôn kính\nDùng thể bị động của động từ để diễn tả hành động của người có địa vị cao hơn, mức độ tôn kính ở mức cơ bản.\nCấp độ: N4  |  Độ lịch sự: Trung bình — thấp hơn Cách 2","usage":"Chỉ dùng khi người thực hiện hành động là người có địa vị cao hơn người nói.\nhọc viên áp dụng nhầm cách chia bị động cho động từ nhóm I hoặc nhóm III — cách này chỉ áp dụng cho nhóm II.\ndùng cách này khi nói về hành động của chính mình — đây là lỗi nghiêm trọng vì Tôn kính ngữ chỉ dùng cho người khác (cấp trên), không bao giờ dùng cho bản thân.","compare":"","examples":[{"jp":"中村さんは何時に来られますか。","vn":"Anh Nakamura đến lúc mấy giờ ạ?"},{"jp":"部長はお酒をやめられましたか。","vn":"Trưởng phòng đã bỏ rượu rồi ạ?"},{"jp":"先生は毎日何時に寝られますか。","vn":"Hàng ngày thầy ngủ vào lúc mấy giờ ạ?"},{"jp":"田中さんがさっき伝えられました。","vn":"Vừa nãy anh Tanaka đã truyền đạt [thông tin] rồi."}]},{"title":"Tôn kính ngữ (尊敬語) — Cách 2: お + Vます (bỏ ます) + になる","formula":"Dạng | Công thức | Ví dụ\nKhẳng định | お + Vます(bỏます) + になります | 部長はもうお帰りになりました\nPhủ định | お + Vます(bỏます) + になりません | 部長はまだお帰りになりません\nQuá khứ | お + Vます(bỏます) + になりました | 部長がお決めになりました\nNghi vấn | お + Vます(bỏます) + になりますか | 課長はもうお読みになりましたか\nGhi chú: KHÔNG dùng với động từ nhóm III (する) và động từ có một âm tiết ở thân ます (VD: 見ます、来ます、います).","explain":"Mẫu câu: お + [thân động từ ます] + になる\nCấu trúc tôn kính ngữ có mức độ lịch sự CAO hơn Cách 1 (thể bị động).\nCấp độ: N4  |  Độ lịch sự: Cao","usage":"Không dùng với động từ nhóm III (する) — dùng động từ đặc biệt hoặc cấu trúc される thay thế.\nKhông dùng với động từ một âm tiết ở thân ます như 見ます, 来ます, います — các động từ này đã có dạng tôn kính đặc biệt riêng.\nnhầm お...になる với お...する (khiêm nhường ngữ) — cần nhớ になる là TÔN KÍNH (dành cho người khác), する là KHIÊM NHƯỜNG (dành cho bản thân).","compare":"","examples":[{"jp":"部長のお子さんはもうお帰りになりましたか。","vn":"Giám đốc đã về rồi ạ?"},{"jp":"部長がお決めになりました。","vn":"Giám đốc đã quyết định rồi."},{"jp":"あしたから夏休みだと先生がお話しになりました。","vn":"Cô giáo đã thông báo là từ mai được nghỉ hè."},{"jp":"部長は何時に来られますか。","vn":"Giám đốc đến lúc mấy giờ ạ?"},{"jp":"部長がまだ日程表をお書きになっていないので、私がお知らせします。","vn":"Vì giám đốc chưa viết lịch trình nên để tôi thông báo."}]},{"title":"Tôn kính ngữ đặc biệt (尊敬語の特別な形)","formula":"","explain":"Nhóm động từ có dạng tôn kính riêng biệt (không theo quy tắc chia thông thường), mức độ tôn kính tương đương Cách 2.\nCấp độ: N4/N5 (đã học ở Bài 49)  |  Độ lịch sự: Cao\nĐộng từ thường | Tôn kính ngữ đặc biệt | Nghĩa\n行きます／来ます／います | いらっしゃいます | đi / đến / có (ở)\nします | なさいます | làm\n言います | おっしゃいます | nói\n食べます／飲みます | 召し上がります | ăn / uống\n見ます | ご覧になります | xem, nhìn\n知っています | ご存じです | biết\nくれます | くださいます | cho, tặng","usage":"chia thể: いらっしゃいます, なさいます, おっしゃいます, くださいます đều thuộc nhóm I nhưng khi chia thể て/ない lại biến đổi theo hàng ら (VD: いらっしゃる → いらっしゃって, KHÔNG chia いらっしゃります/いらっしゃった theo quy tắc thường mà là いらっしゃい, ngoại lệ ở thể ます).","compare":"","examples":[{"jp":"研究室に田中先生がいらっしゃいます。","vn":"Thầy Tanaka có ở phòng nghiên cứu."},{"jp":"どうぞ、召し上がってください。","vn":"Xin mời thầy/cô dùng bữa."},{"jp":"部長はこのニュースをご存じですか。","vn":"Giám đốc có biết tin này không ạ?"},{"jp":"先生はテニスをなさいますか。","vn":"Thầy có chơi tennis không ạ?"},{"jp":"いらっしゃいます","vn":"đi / đến / có (ở)"}]},{"title":"Tôn kính ngữ — Cách dùng khi nhờ vả/mời (mệnh lệnh lịch sự)","formula":"Dạng | Công thức | Ví dụ\nKhẳng định (đề nghị) | お + Vます(bỏます) + ください | 少々お待ちください\nPhủ định (đề nghị) | お + Vません(bỏます) + にならないでください | そちらにお入りにならないでください\nGhi chú: KHÔNG dùng với động từ nhóm III. Các động từ tôn kính đặc biệt (nhóm III đặc biệt) như 召し上がる、ご覧になる vẫn có thể chuyển thành ください: 召し上がってください、ご覧ください.","explain":"Mẫu câu: お + [thân động từ ます] + ください\nDùng khi nhờ vả hoặc mời người có địa vị cao hơn thực hiện một hành động, thể hiện sự kính trọng trong lời đề nghị/mệnh lệnh lịch sự.\nCấp độ: N4  |  Độ lịch sự: Cao","usage":"","compare":"","examples":[{"jp":"少々お待ちください。","vn":"Xin quý khách đợi cho một chút."},{"jp":"あちらからお入りください。","vn":"Xin quý khách vào từ lối kia."},{"jp":"カメラをお持ちください。","vn":"Xin hãy mang theo máy ảnh."},{"jp":"どうぞ、ゆっくり召し上がってください。","vn":"Xin mời quý khách từ từ thưởng thức."}]},{"title":"Khiêm nhường ngữ (謙譲語) — Cách 1: お + Vます (bỏます) + する","formula":"Dạng | Công thức | Ví dụ\nKhẳng định | お + Vます(bỏます) + します | 私がお持ちします\nPhủ định | お + Vます(bỏます) + しません | まだお知らせしません\nQuá khứ | お + Vます(bỏます) + しました | 先ほどお知らせしました\nNghi vấn (đề nghị) | お + Vます(bỏます) + しましょうか | お持ちしましょうか\nGhi chú: Chỉ dùng với động từ nhóm I và nhóm II. KHÔNG dùng với nhóm III và động từ một âm tiết ở thân ます (見ます、います、来ます). Bắt buộc phải có đối tượng tiếp nhận hành vi rõ ràng — nếu hành động không hướng đến ai (VD: 来月国に帰ります — tự mình về nước, không liên quan ai) thì KHÔNG dùng cấu trúc này.","explain":"Mẫu câu: お + [thân động từ ます] + します\nHạ thấp hành động của bản thân (hoặc người cùng nhóm với người nói) để thể hiện sự kính trọng đối với người nghe/người được nhắc đến.\nCấp độ: N4  |  Độ lịch sự: Cao","usage":"","compare":"","examples":[{"jp":"重そうですね。私がお持ちしましょうか。","vn":"Nặng quá nhỉ. Để tôi mang hộ nhé."},{"jp":"部長がまだ日程表をお書きになっていないので、私がお知らせします。","vn":"Giám đốc chưa viết lịch trình nên để tôi thông báo."},{"jp":"事故の原因をお調べしました。","vn":"Tôi đã điều tra nguyên nhân sự cố rồi ạ."},{"jp":"部長は何時に来られますか。","vn":"Giám đốc đến lúc mấy giờ ạ?"},{"jp":"課長のお子さんは、あす、テニスをなさいますか。","vn":"Con trai trưởng phòng ngày mai có chơi tennis không ạ?"}]},{"title":"Khiêm nhường ngữ (謙譲語) — Cách 2: ご + Vする (động từ nhóm III)","formula":"Dạng | Công thức | Ví dụ\nKhẳng định | ご + N + します | ご案内します\nNgoại lệ (dùng お thay ご) | お + N + します | 電話します → お電話します、約束します → お約束します\nGhi chú: Cả Cách 1 và Cách 2 đều bắt buộc phải có đối tượng tiếp nhận hành vi (nói với ai / cho ai). Ngoại lệ đặc biệt: 電話します、約束します dùng お thay vì ご dù là động từ nhóm III.","explain":"Mẫu câu: ご + [danh động từ nhóm III] + します\nÁp dụng cho động từ nhóm III (danh từ + する), tương đương chức năng với お...する.\nCấp độ: N4  |  Độ lịch sự: Cao","usage":"","compare":"","examples":[{"jp":"あした、たいへいざんをご案内します。","vn":"Ngày mai em sẽ đưa giám đốc đi tham quan núi Thái Bình."},{"jp":"きょうの予定をご説明します。","vn":"Em xin phép trình bày về kế hoạch của ngày hôm nay."},{"jp":"時間が変わりましたら、お客様にご連絡します。","vn":"Nếu có thay đổi về thời gian, chúng tôi sẽ thông báo cho quý khách."},{"jp":"先生にご相談したいことがあります。","vn":"Tôi có điều muốn thảo luận với thầy/cô."}]},{"title":"Khiêm nhường ngữ đặc biệt (謙譲語の特別な形)","formula":"","explain":"Nhóm động từ có dạng khiêm nhường riêng biệt, dùng khi (1) hành vi của người nói liên quan đến người nghe/người được nhắc tới, hoặc (2) khi nói về bản thân mình (giới thiệu bản thân).\nCấp độ: N4/N5 (đã học ở Bài 49)  |  Độ lịch sự: Cao\nĐộng từ thường | Khiêm nhường ngữ đặc biệt | Nghĩa\n行きます／来ます | 参ります | đi / đến\n言います | 申し上げます | nói (kính trọng đối tượng nghe)\nします | いたします | làm\n見ます | 拝見します | xem, nhìn (khiêm nhường)\n知っています | 存じています | biết\n会います | お目にかかります | gặp (khiêm nhường)\nもらいます | いただきます | nhận","usage":"","compare":"","examples":[{"jp":"部長の奥様に一度お目にかかりました。","vn":"Tôi đã từng gặp phu nhân giám đốc một lần."},{"jp":"先生の結婚式の写真を拝見しました。","vn":"Tôi đã xem ảnh cưới của thầy/cô rồi."},{"jp":"そのことはもう存じております。","vn":"Vấn đề đó tôi đã hiểu rõ rồi."},{"jp":"予定通りに仕事を進めております。","vn":"Tôi vẫn đang tiến hành công việc theo đúng kế hoạch."},{"jp":"ベトナムから参りました。","vn":"Tôi đến từ Việt Nam."}]},{"title":"Thể lịch sự (でございます／です・ます)","formula":"N + でございます (thay cho N + です khi cần trang trọng hơn)\nお待たせして申し訳ございません (dùng khiêm nhường ngữ vì có hành vi của người nói — 待たせる là hành động do người nói gây ra)","explain":"Dùng khi giới thiệu sự vật/sự việc KHÔNG liên quan đến hành vi (động từ hành động) của cả người nói lẫn người nghe — chỉ cần lịch sự, không cần tôn kính/khiêm nhường.\nCấp độ: N4  |  Độ lịch sự: Trang trọng vừa phải","usage":"","compare":"Tiêu chí | Tôn kính ngữ (尊敬語) | Khiêm nhường ngữ (謙譲語)\nÁp dụng cho ai | Người khác có địa vị/tuổi tác cao hơn người nói | Bản thân người nói hoặc người cùng nhóm (nhóm trong)\nMục đích | Nâng cao vị thế người được nhắc đến | Hạ thấp bản thân để gián tiếp nâng người nghe\nCấu trúc phổ biến | ～れる/られる、お～になる、お～ください | お～する、ご～する、～ておる\nNhóm động từ đặc biệt | いらっしゃる、おっしゃる、召し上がる, ご覧になる... | 参る、申し上げる、いたす、拝見する...\nVới khách hàng/đối tác bên ngoài | Dùng cho khách hàng, đối tác | Dùng cho người trong công ty mình (kể cả giám đốc) khi nói với đối tác bên ngoài","examples":[{"jp":"スーパーは2階にございます。","vn":"Siêu thị có ở trên tầng hai."},{"jp":"これはサムスンの電話でございます。","vn":"Đây là điện thoại Samsung ạ."},{"jp":"お待たせして申し訳ございません。","vn":"Xin lỗi vì đã để quý khách phải đợi lâu."},{"jp":"部長は何時に来られますか。","vn":"Giám đốc đến lúc mấy giờ ạ?"},{"jp":"重そうですね。私がお持ちしましょうか。","vn":"Nặng quá nhỉ. Để tôi mang hộ nhé."}]}]};
